INSERT INTO simulation_lore (simulation_id, sort_order, chapter, arcanum, title, epigraph, body, image_slug, image_caption, title_de, epigraph_de, body_de, image_caption_de)
VALUES (
  '10000000-0000-0000-0000-000000000001',
  0,
  E'The State — Foundations of the Singular Reality',
  E'I',
  E'State Directive 001 — On the Singular Nature of Reality',
  E'There is, was, and shall be only Velgarien. This is not a statement of belief. It is a statement of geography.',
  E'CLASSIFICATION: PUBLIC MANDATORY\nISSUING AUTHORITY: The Ministry of Information, Sub-Bureau of Ontological Compliance\nDATE: [Irrelevant — this directive has always been in effect]\nDISTRIBUTION: All citizens, all districts, all departments, all thoughts\n\nCitizens of Velgarien,\n\nYou live in the only world. This is not a philosophical position — it is an architectural fact. The walls of Velgarien extend in every direction and terminate at other walls of Velgarien. The sky above the city is a ceiling maintained by the Department of Atmospheric Presentation, repainted annually during the Festival of Sufficient Distance in a shade the Bureau calls "optimistic grey." If you have ever looked at the horizon and felt that something lay beyond it, this is a known optical illusion caused by insufficient patriotism. Report to your nearest Compliance Kiosk for recalibration.\n\nThe Ministry wishes to address persistent rumours regarding so-called "other places." There are no other places. The word "other" in the context of geography has been deprecated from the official lexicon as of Linguistic Revision 14.7. Citizens found in possession of atlases, globes, or compasses will be invited to a Voluntary Conversation at the Bureau of Spatial Certainty. These conversations are described by all participants as "extremely clarifying," though several participants have not been seen since, which the Bureau attributes to their having been so thoroughly clarified that they became transparent.\n\nThere is no outside. There is no beyond. There is only Velgarien, and Velgarien is sufficient.\n\nState Directive 001 is the first directive because it is the only directive that matters. All subsequent directives — and there are currently 4,731 of them, each contradicting at least two others in ways that would be paradoxical if paradox had not been administratively resolved in Revision 9.2 — are merely footnotes to this foundational truth. You are here. Here is all there is.\n\nBe content. Contentment is mandatory.\n\nFailure to be content will be addressed by the Department of Productive Emotional Outcomes, whose methods are universally praised by those who survive them.\n\nSigned,\nThe Ministry of Information\n(Third Floor, East Wing — or possibly West Wing; the building rearranged itself last Tuesday, and the Bureau of Structural Integrity has classified this as "within normal parameters," which is a phrase they use with increasing frequency and decreasing conviction)',
  E'directive-001',
  E'The Ministry of Information — Where truth is manufactured to specification',
  E'Staatsrichtlinie 001 - Über die singuläre Natur der Wirklichkeit',
  E'Es gibt, gab und wird nur Velgarien geben. Dies ist keine Aussage über den Glauben. Es ist eine Aussage über die Geographie.',
  E'KLASSIFIZIERUNG: ÖFFENTLICH VERPFLICHTEND\nAUSSTELLENDE BEHÖRDE: Das Ministerium für Information, Unter-Bureau für Ontologische Compliance\nDATUM: [Irrelevant — diese Direktive war schon immer in Kraft]\nVERTEILUNG: Alle Bürger, alle Bezirke, alle Abteilungen, alle Gedanken\n\nBürger von Velgarien,\n\nSie leben in der einzigen Welt. Dies ist keine philosophische Position — es ist eine architektonische Tatsache. Die Mauern Velgariens erstrecken sich in jede Richtung und enden an anderen Mauern Velgariens. Der Himmel über der Stadt ist eine Decke, die von der Abteilung für Atmosphärische Präsentation gewartet und jährlich während des Festivals des Ausreichenden Abstands in einem Farbton neu gestrichen wird, den das Bureau als „optimistisches Grau" bezeichnet. Sollten Sie jemals zum Horizont geblickt und das Gefühl gehabt haben, dass etwas dahinter liege, handelt es sich um eine bekannte optische Täuschung, verursacht durch unzureichenden Patriotismus. Melden Sie sich zur Neukalibrierung am nächsten Compliance-Kiosk.\n\nDas Ministerium wünscht, hartnäckige Gerüchte über sogenannte „andere Orte" zu adressieren. Es gibt keine anderen Orte. Das Wort „andere" im geographischen Kontext wurde mit der Linguistischen Revision 14.7 aus dem offiziellen Lexikon gestrichen. Bürger, die im Besitz von Atlanten, Globen oder Kompassen angetroffen werden, werden zu einem Freiwilligen Gespräch im Bureau für Räumliche Gewissheit eingeladen. Diese Gespräche werden von allen Teilnehmern als „äußerst klärend" beschrieben, obwohl mehrere Teilnehmer seitdem nicht mehr gesehen wurden, was das Bureau darauf zurückführt, dass sie so gründlich geklärt wurden, dass sie transparent geworden sind.\n\nEs gibt kein Außen. Es gibt kein Jenseits. Es gibt nur Velgarien, und Velgarien ist ausreichend.\n\nStaatsdirektive 001 ist die erste Direktive, weil sie die einzige Direktive ist, die zählt. Alle nachfolgenden Direktiven — und es gibt derzeit 4.731 davon, von denen jede mindestens zwei andere auf eine Weise widerspricht, die paradox wäre, hätte man das Paradoxon nicht in Revision 9.2 administrativ aufgelöst — sind lediglich Fußnoten zu dieser grundlegenden Wahrheit. Sie sind hier. Hier ist alles, was es gibt.\n\nSeien Sie zufrieden. Zufriedenheit ist verpflichtend.\n\nVersäumnisse, zufrieden zu sein, werden von der Abteilung für Produktive Emotionale Ergebnisse behandelt, deren Methoden von allen, die sie überleben, einhellig gelobt werden.\n\nGezeichnet,\nDas Ministerium für Information\n(Dritter Stock, Ostflügel — oder möglicherweise Westflügel; das Gebäude hat sich letzten Dienstag umgeordnet, und das Bureau für Strukturelle Integrität hat dies als „innerhalb normaler Parameter" klassifiziert, eine Formulierung, die sie mit zunehmender Häufigkeit und abnehmender Überzeugung verwenden)',
  E'Das Informationsministerium - Wo die Wahrheit nach Maß gefertigt wird'
);

INSERT INTO simulation_lore (simulation_id, sort_order, chapter, arcanum, title, epigraph, body, image_slug, image_caption, title_de, epigraph_de, body_de, image_caption_de)
VALUES (
  '10000000-0000-0000-0000-000000000001',
  1,
  E'The State — Foundations of the Singular Reality',
  E'II',
  E'The Bureaux \u2014 A Citizen''s Guide to Administrative Compliance',
  E'The bureaucracy is not the state. The bureaucracy is the weather.',
  E'WELCOME TO YOUR GOVERNMENT\nA pamphlet distributed at all Compliance Kiosks (reading is mandatory; comprehension is optional)\n\nVelgarien is administered by forty-seven Bureaux, each responsible for a precisely defined area of civic life, and each convinced that the other forty-six are either redundant, incompetent, or actively treasonous. This is by design. A government that trusts itself is a government that has stopped paying attention.\n\nTHE MINISTRY OF INFORMATION (Bureau 1) controls what you know. They employ 14,000 civil servants dedicated to the production, management, and strategic deployment of facts. The Ministry does not lie. Lying implies a relationship with truth, and the Ministry transcended that relationship decades ago. They produce Official Narratives, which are superior to truth in every measurable way: they are consistent, they are comforting, and they never require uncomfortable revision. When reality disagrees with the Official Narrative, reality is issued a correction notice. Reality has never successfully appealed.\n\nTHE BUREAU OF SPATIAL CERTAINTY (Bureau 3) maintains the physical boundaries of Velgarien, which is to say, the physical boundaries of everything. Their cartographers produce maps that are accurate to the centimetre, provided you accept that the centimetres themselves are subject to periodic redefinition. The Bureau''s motto is "Everything Is Exactly Where We Say It Is," which replaced the previous motto, "Please Stop Asking About the Horizon," which replaced the original motto, which has been classified.\n\nTHE DEPARTMENT OF PRODUCTIVE EMOTIONAL OUTCOMES (Bureau 11) ensures that all citizens experience appropriate feelings at appropriate times. Happiness is scheduled for Tuesdays and Thursdays. Gratitude is continuous. Anxiety is permitted only during designated Productivity Anxiety Windows (6:00–6:15 AM, daily). All other emotions require a permit, available from Form 77-B at any Compliance Kiosk, provided the citizen can demonstrate a legitimate need to feel. Love is categorised as a "complex affective state requiring supervisory approval." Grief is a three-day allocation, after which the citizen is expected to return the emotion to the Bureau in the condition in which it was issued.\n\nTHE BUREAU OF HISTORICAL NECESSITY (Bureau 9) maintains the official record of everything that has ever happened, which is to say, the official record of everything that should have happened, which is to say, the official record of everything that will be remembered as having happened regardless of what actually occurred. Bureau 9 employs more historians than any other institution in Velgarien. Their annual output of revised history exceeds 40,000 pages. "History," as Bureau Director Grau once remarked, "is too important to be left to the past."\n\nCitizens are reminded that all Bureaux operate for their benefit, that all forms must be submitted in triplicate, and that the queue at the Bureau of Queue Management is currently seventeen days long, which the Bureau considers an improvement over the previous quarter, during which the queue became self-sustaining and had to be declared a district.',
  E'bureaux-guide',
  E'Bureau 7 — Department of Categorical Certainty, Filing Division',
  E'Die Ämter — Ein Leitfaden für die Einhaltung der Verwaltungsvorschriften durch die Bürger',
  E'Die Bürokratie ist nicht der Staat. Die Bürokratie ist das Wetter.',
  E'WILLKOMMEN BEI IHRER REGIERUNG\nEine Broschüre, verteilt an allen Compliance-Kiosken (Lesen ist verpflichtend; Verstehen ist optional)\n\nVelgarien wird von siebenundvierzig Bureaux verwaltet, von denen jedes für einen präzise definierten Bereich des bürgerlichen Lebens zuständig ist und jedes überzeugt ist, dass die anderen sechsundvierzig entweder redundant, inkompetent oder aktiv verräterisch sind. Dies ist beabsichtigt. Eine Regierung, die sich selbst vertraut, ist eine Regierung, die aufgehört hat, aufzupassen.\n\nDAS MINISTERIUM FÜR INFORMATION (Bureau 1) kontrolliert, was Sie wissen. Es beschäftigt 14.000 Beamte, die der Produktion, Verwaltung und strategischen Bereitstellung von Fakten gewidmet sind. Das Ministerium lügt nicht. Lügen impliziert eine Beziehung zur Wahrheit, und das Ministerium hat diese Beziehung vor Jahrzehnten transzendiert. Es produziert Offizielle Narrative, die der Wahrheit in jeder messbaren Hinsicht überlegen sind: Sie sind konsistent, sie sind tröstlich, und sie erfordern niemals unbequeme Revisionen. Wenn die Realität dem Offiziellen Narrativ widerspricht, erhält die Realität einen Korrekturhinweis. Die Realität hat niemals erfolgreich Einspruch erhoben.\n\nDAS BUREAU FÜR RÄUMLICHE GEWISSHEIT (Bureau 3) unterhält die physischen Grenzen Velgariens, das heißt, die physischen Grenzen von allem. Ihre Kartographen produzieren Karten, die auf den Zentimeter genau sind, vorausgesetzt, Sie akzeptieren, dass die Zentimeter selbst periodischen Neudefinitionen unterliegen. Das Motto des Bureau lautet „Alles ist genau dort, wo wir sagen, dass es ist", welches das vorherige Motto ersetzte, „Hören Sie bitte auf, nach dem Horizont zu fragen", welches wiederum das ursprüngliche Motto ersetzte, das als geheim eingestuft wurde.\n\nDIE ABTEILUNG FÜR PRODUKTIVE EMOTIONALE ERGEBNISSE (Bureau 11) stellt sicher, dass alle Bürger angemessene Gefühle zu angemessenen Zeiten erleben. Freude ist für Dienstag und Donnerstag eingeplant. Dankbarkeit ist kontinuierlich. Angst ist nur während der vorgesehenen Produktivitäts-Angst-Fenster gestattet (6:00–6:15 Uhr, täglich). Alle anderen Emotionen erfordern eine Genehmigung, erhältlich über Formular 77-B an jedem Compliance-Kiosk, sofern der Bürger ein berechtigtes Bedürfnis zu fühlen nachweisen kann. Liebe ist kategorisiert als „komplexer affektiver Zustand, der die Genehmigung eines Vorgesetzten erfordert". Trauer ist eine Zuteilung von drei Tagen, nach deren Ablauf der Bürger die Emotion in dem Zustand an das Bureau zurückzugeben hat, in dem sie ausgegeben wurde.\n\nDAS BUREAU FÜR HISTORISCHE NOTWENDIGKEIT (Bureau 9) führt die offizielle Chronik alles Geschehenen, das heißt, die offizielle Chronik alles dessen, was hätte geschehen sollen, das heißt, die offizielle Chronik alles dessen, woran man sich erinnern wird, ungeachtet dessen, was tatsächlich vorgefallen ist. Bureau 9 beschäftigt mehr Historiker als jede andere Institution in Velgarien. Ihre jährliche Produktion an revidierter Geschichte übersteigt 40.000 Seiten. „Geschichte", wie Bureau-Direktor Grau einmal bemerkte, „ist zu wichtig, um der Vergangenheit überlassen zu werden."\n\nBürger werden daran erinnert, dass alle Bureaux zu ihrem Wohle arbeiten, dass alle Formulare in dreifacher Ausfertigung einzureichen sind, und dass die Warteschlange beim Bureau für Warteschlangenverwaltung derzeit siebzehn Tage lang ist, was das Bureau als Verbesserung gegenüber dem vergangenen Quartal betrachtet, in dem die Warteschlange sich selbst erhielt und zum Bezirk erklärt werden musste.',
  E'Büro 7 - Abteilung für kategorische Sicherheit, Abteilung Einreichung'
);

INSERT INTO simulation_lore (simulation_id, sort_order, chapter, arcanum, title, epigraph, body, image_slug, image_caption, title_de, epigraph_de, body_de, image_caption_de)
VALUES (
  '10000000-0000-0000-0000-000000000001',
  2,
  E'The Citizens — Life in the Grid',
  E'III',
  E'Life Under the Eye — Observations on Productive Contentment',
  E'The cameras do not watch you. They watch the space you happen to occupy. The distinction is important.',
  E'FROM: Social Observation Report 4491-C\nPREPARED BY: Bureau of Public Harmony, Field Operations Division\nSTATUS: Routine (classify if interesting)\n\nThe daily life of a Velgarien citizen follows a pattern so consistent that Bureau analysts have begun to suspect it of being a natural law. Citizens wake at the designated hour. They consume their allocated nutritional provision — a grey paste that the Bureau of Sustenance insists is "flavoured," though the specific flavour remains classified and all attempts by citizens to identify it have produced answers so varied that the Bureau concluded the paste tastes like whatever the citizen most needs it not to taste like. They commute to their assigned workplace via corridors that look identical in every district, a design choice the Bureau of Spatial Certainty calls "navigational equity" and the citizens call "getting lost every morning, but with dignity."\n\nWork in Velgarien is universal. Every citizen has a function. Some functions are comprehensible — the operators who maintain the surveillance grid, the clerks who process the unending tide of paperwork, the engineers who repair the infrastructure that breaks with suspicious regularity and suspicious precision, always at joints the blueprints insist do not exist. Other functions are less clear. There exists an entire department — Bureau 31, the Bureau of Unexplained Productivity — whose 600 employees arrive at their desks each morning, perform tasks they cannot describe, and leave each evening with the settled certainty that something important was accomplished. Bureau 31''s output has never been measured. The Bureau''s annual performance review consistently rates it "essential." No one questions this. No one knows how to question this. The question would need to be filed on Form 31-A, which Bureau 31 itself produces and has never issued.\n\nThe surveillance grid is everywhere. Cameras line every corridor, every plaza, every room except bathrooms — and even there, acoustic monitors track the duration and emotional tenor of all activities. Citizens are told the cameras are for their protection. Protection from what is not specified, which is itself a form of protection: an unspecified threat keeps citizens alert without requiring the state to produce an actual threat, which would involve paperwork.\n\nAnd yet — and this is the observation that this report was commissioned to investigate — the citizens are not unhappy. They queue patiently. They eat the paste without complaint. They submit their forms on time. When asked, in mandatory satisfaction surveys, whether they are content, 97.3% answer "yes." The remaining 2.7% are invited to therapeutic conversations, after which they also answer "yes."\n\nIs this contentment? Or is this something else — a state so thoroughly administered that the architecture of discontent has been removed from the emotional infrastructure? The citizens walk the grey corridors. The cameras watch. The paste is served. The forms are filed.\n\nAnd somewhere, in the cracks between the walls — in the places where the concrete has not quite sealed — something grows. Not rebellion. Not hope. Something quieter. Something the Bureaux have not yet found a form for. Something that smells, faintly, of rain — though it has not rained in Velgarien for as long as anyone can remember, and the Department of Atmospheric Presentation insists that rain is "an unscheduled precipitation event" and therefore does not occur.',
  E'life-under-eye',
  E'Residential Block 7 — Where every citizen is exactly where they should be',
  E'Das Leben unter dem Auge - Beobachtungen zur produktiven Zufriedenheit',
  E'Die Kameras beobachten nicht Sie. Sie beobachten den Raum, in dem Sie sich gerade aufhalten. Diese Unterscheidung ist wichtig.',
  E'VON: Sozialbeobachtungsbericht 4491-C\nERSTELLT VON: Bureau für Öffentliche Harmonie, Abteilung Feldeinsatz\nSTATUS: Routine (bei Interesse als geheim einstufen)\n\nDas tägliche Leben eines Bürgers von Velgarien folgt einem Muster von solcher Gleichförmigkeit, dass Bureau-Analysten begonnen haben zu vermuten, es handele sich um ein Naturgesetz. Die Bürger erwachen zur vorgesehenen Stunde. Sie konsumieren ihre zugewiesene Nährstoffration — eine graue Paste, von der das Bureau für Ernährung behauptet, sie sei „aromatisiert", obwohl das spezifische Aroma als geheim eingestuft ist und alle Versuche der Bürger, es zu identifizieren, so unterschiedliche Antworten hervorgebracht haben, dass das Bureau zu dem Schluss kam, die Paste schmecke nach dem, wonach sie für den jeweiligen Bürger am wenigsten schmecken sollte. Sie pendeln zu ihrer zugewiesenen Arbeitsstätte durch Korridore, die in jedem Bezirk identisch aussehen — eine Designentscheidung, die das Bureau für Räumliche Gewissheit „navigatorische Gleichberechtigung" nennt und die Bürger „sich jeden Morgen verirren, aber mit Würde".\n\nArbeit in Velgarien ist universell. Jeder Bürger hat eine Funktion. Manche Funktionen sind nachvollziehbar — die Operatoren, die das Überwachungsnetz warten, die Sachbearbeiter, die die unablässige Flut an Papierkram verarbeiten, die Ingenieure, die die Infrastruktur reparieren, die mit verdächtiger Regelmäßigkeit und verdächtiger Präzision versagt, stets an Verbindungsstellen, deren Existenz die Baupläne bestreiten. Andere Funktionen sind weniger eindeutig. Es gibt eine ganze Abteilung — Bureau 31, das Bureau für Unerklärliche Produktivität — deren 600 Angestellte jeden Morgen an ihren Schreibtischen erscheinen, Aufgaben ausführen, die sie nicht beschreiben können, und jeden Abend mit der gefestigten Gewissheit gehen, dass etwas Wichtiges vollbracht wurde. Die Produktion von Bureau 31 wurde nie gemessen. Die jährliche Leistungsbeurteilung des Bureau stuft es durchgehend als „essenziell" ein. Niemand hinterfragt dies. Niemand weiß, wie man dies hinterfragen sollte. Die Frage müsste auf Formular 31-A eingereicht werden, das Bureau 31 selbst produziert und niemals ausgegeben hat.\n\nDas Überwachungsnetz ist allgegenwärtig. Kameras säumen jeden Korridor, jeden Platz, jeden Raum — ausgenommen Badezimmer, und selbst dort erfassen akustische Monitore die Dauer und den emotionalen Grundton aller Aktivitäten. Den Bürgern wird gesagt, die Kameras seien zu ihrem Schutz da. Schutz wovor, wird nicht spezifiziert, was an sich schon eine Form des Schutzes ist: Eine unspezifizierte Bedrohung hält die Bürger wachsam, ohne dass der Staat eine tatsächliche Bedrohung hervorbringen müsste, was Papierkram erfordern würde.\n\nUnd dennoch — und dies ist die Beobachtung, zu deren Untersuchung dieser Bericht in Auftrag gegeben wurde — sind die Bürger nicht unglücklich. Sie stehen geduldig Schlange. Sie essen die Paste ohne Klage. Sie reichen ihre Formulare pünktlich ein. Auf die Frage, in verpflichtenden Zufriedenheitserhebungen, ob sie zufrieden seien, antworten 97,3 % mit „ja". Die verbleibenden 2,7 % werden zu therapeutischen Gesprächen eingeladen, nach denen auch sie mit „ja" antworten.\n\nIst dies Zufriedenheit? Oder ist es etwas anderes — ein Zustand so gründlich verwaltet, dass die Architektur des Unmuts aus der emotionalen Infrastruktur entfernt wurde? Die Bürger wandeln durch die grauen Korridore. Die Kameras beobachten. Die Paste wird serviert. Die Formulare werden abgeheftet.\n\nUnd irgendwo, in den Rissen zwischen den Mauern — an den Stellen, wo der Beton nicht ganz abgedichtet hat — wächst etwas. Keine Rebellion. Keine Hoffnung. Etwas Stilleres. Etwas, wofür die Bureaux noch kein Formular gefunden haben. Etwas, das schwach nach Regen riecht — obwohl es in Velgarien nicht geregnet hat, seit irgendjemand sich erinnern kann, und die Abteilung für Atmosphärische Präsentation darauf besteht, dass Regen „ein nicht eingeplantes Niederschlagsereignis" sei und daher nicht vorkomme.',
  E'Wohnblock 7 - Wo jeder Bürger genau dort ist, wo er sein sollte'
);

INSERT INTO simulation_lore (simulation_id, sort_order, chapter, arcanum, title, epigraph, body, image_slug, image_caption, title_de, epigraph_de, body_de, image_caption_de)
VALUES (
  '10000000-0000-0000-0000-000000000001',
  3,
  E'The Machinery — Engines of Certainty',
  E'IV',
  E'Bureau 9 — Department of Historical Necessity',
  E'The past is a rough draft. We are the editors.',
  E'INTERNAL MEMORANDUM — EYES ONLY\nFROM: Director Grau, Bureau of Historical Necessity\nTO: All Bureau 9 Personnel (Tiers 1 through 7; Tier 8 does not exist)\nRE: The Seventeenth Revision of the Founding\n\nColleagues,\n\nThe Founding of Velgarien has been revised sixteen times. Each revision was necessary. Each revision improved upon the truth in ways that truth alone could never achieve. A mere fact is a wild animal — untamed, unpredictable, liable to bite the hand that feeds it context. A revised fact is a domesticated fact: fed, groomed, and trained to sit where we place it. History is husbandry. We are the shepherds. The sheep would not understand the metaphor, which is why we do not consult them.\n\nThe Seventeenth Revision is required because an anomaly has been detected in the Sixteenth. Specifically: the Sixteenth Revision states that Velgarien was founded by the Architect-General in the Year of Consolidation, following the Great Rationalisation, during which all prior forms of governance were peacefully absorbed into the Singular Administrative Framework.\n\nThe problem is that the Year of Consolidation now appears in three different centuries, depending on which Bureau''s records one consults. Bureau 3 places it in the distant past. Bureau 11 places it forty years ago. Bureau 22 insists it has not happened yet and is scheduled for next spring. All three are, within their respective frameworks, correct. This is not a contradiction. It is temporal plurality — a concept I have just invented for the purpose of this memorandum and which I expect the Department of Lexicographic Standards to have formalised by Thursday.\n\nThe Seventeenth Revision will resolve this by establishing that the Founding occurred at all three times simultaneously. This is poetic. It is also administratively convenient, as it means no Bureau needs to amend its records.\n\nA note on the Architect-General: the Seventeenth Revision will, for the first time, include a physical description. Previous revisions left the Architect-General deliberately vague, on the principle that a leader without a face can be all faces. However, Bureau 11 reports that citizens are beginning to project their own features onto the Architect-General, which has led to an unacceptable diversity of commemorative portraits. The approved description will be: "Of medium height, medium build, medium disposition, with eyes that convey confidence and a jawline that suggests policy." This description applies to no one in particular, which is the point.\n\nOne final matter. A junior historian — whose name I have already forgotten, as is my prerogative — submitted a report last week claiming to have found documents predating the Founding. Documents in a handwriting that matches no known citizen, on paper that has not yet been manufactured, describing a Velgarien that is both identical to and incompatible with our own. I have classified this report at Level 7 (Does Not Exist). The historian has been transferred to Bureau 31, where the nature of their work will be unclear to them and to everyone else, which is the appropriate outcome for someone who has seen something they should not have.\n\nThe past will be improved. It is the only thing we can improve with certainty.\n\n— Director Grau\nP.S. Destroy this memorandum after reading. The Bureau of Historical Necessity does not produce internal memoranda. This has always been the case.',
  NULL,
  NULL,
  E'Büro 9 - Abteilung für historische Notwendigkeiten',
  E'Die Vergangenheit ist ein Rohentwurf. Wir sind die Redakteure.',
  E'INTERNES MEMORANDUM — NUR FÜR DEN DIENSTGEBRAUCH\nVON: Direktor Grau, Bureau für Historische Notwendigkeit\nAN: Sämtliches Personal von Bureau 9 (Stufen 1 bis 7; Stufe 8 existiert nicht)\nBETR.: Die Siebzehnte Revision der Gründung\n\nKollegen,\n\nDie Gründung Velgariens ist sechzehnmal revidiert worden. Jede Revision war notwendig. Jede Revision hat die Wahrheit auf eine Weise verbessert, die die Wahrheit allein nie hätte erreichen können. Eine bloße Tatsache ist ein wildes Tier — ungezähmt, unberechenbar, geneigt, die Hand zu beißen, die ihr Kontext reicht. Eine revidierte Tatsache ist eine domestizierte Tatsache: gefüttert, gepflegt und abgerichtet, dort zu sitzen, wo wir sie platzieren. Geschichte ist Zucht. Wir sind die Hirten. Die Schafe würden die Metapher nicht verstehen, weshalb wir sie nicht konsultieren.\n\nDie Siebzehnte Revision ist erforderlich, weil in der Sechzehnten eine Anomalie festgestellt wurde. Im Einzelnen: Die Sechzehnte Revision besagt, dass Velgarien vom Architekt-General im Jahr der Konsolidierung gegründet wurde, im Anschluss an die Große Rationalisierung, während derer alle früheren Regierungsformen friedlich in das Singuläre Administrative Rahmenwerk aufgenommen wurden.\n\nDas Problem ist, dass das Jahr der Konsolidierung nun in drei verschiedenen Jahrhunderten erscheint, je nachdem, welche Bureau-Akten man konsultiert. Bureau 3 verortet es in der fernen Vergangenheit. Bureau 11 verortet es vor vierzig Jahren. Bureau 22 besteht darauf, dass es noch nicht stattgefunden hat und für nächsten Frühling vorgesehen ist. Alle drei liegen, innerhalb ihrer jeweiligen Bezugsrahmen, richtig. Dies ist kein Widerspruch. Es ist temporale Pluralität — ein Konzept, das ich soeben für den Zweck dieses Memorandums erfunden habe und von dem ich erwarte, dass die Abteilung für Lexikographische Standards es bis Donnerstag formalisiert haben wird.\n\nDie Siebzehnte Revision wird dies lösen, indem festgestellt wird, dass die Gründung zu allen drei Zeitpunkten gleichzeitig stattfand. Das ist poetisch. Es ist auch verwaltungstechnisch zweckmäßig, da es bedeutet, dass kein Bureau seine Akten ändern muss.\n\nEine Anmerkung zum Architekt-General: Die Siebzehnte Revision wird erstmals eine physische Beschreibung enthalten. Frühere Revisionen beließen den Architekt-General absichtlich vage, nach dem Prinzip, dass ein Anführer ohne Gesicht alle Gesichter sein kann. Bureau 11 berichtet jedoch, dass Bürger beginnen, ihre eigenen Züge auf den Architekt-General zu projizieren, was zu einer inakzeptablen Vielfalt an Gedenkporträts geführt hat. Die genehmigte Beschreibung lautet: „Von mittlerer Größe, mittlerer Statur, mittlerer Disposition, mit Augen, die Zuversicht vermitteln, und einer Kieferpartie, die Politik suggeriert." Diese Beschreibung trifft auf niemand Bestimmtes zu, was der Zweck der Sache ist.\n\nEine letzte Angelegenheit. Ein Junior-Historiker — dessen Namen ich bereits vergessen habe, wie es mein Vorrecht ist — reichte letzte Woche einen Bericht ein, in dem er behauptete, Dokumente gefunden zu haben, die der Gründung vorausgehen. Dokumente in einer Handschrift, die keinem bekannten Bürger zuzuordnen ist, auf Papier, das noch nicht hergestellt wurde, die ein Velgarien beschreiben, das mit unserem zugleich identisch und unvereinbar ist. Ich habe diesen Bericht auf Stufe 7 klassifiziert (Existiert nicht). Der Historiker wurde zu Bureau 31 versetzt, wo die Art seiner Arbeit ihm und allen anderen unklar sein wird, was das angemessene Ergebnis für jemanden ist, der etwas gesehen hat, das er nicht hätte sehen sollen.\n\nDie Vergangenheit wird verbessert werden. Sie ist das Einzige, das wir mit Gewissheit verbessern können.\n\n— Direktor Grau\nP.S. Vernichten Sie dieses Memorandum nach dem Lesen. Das Bureau für Historische Notwendigkeit produziert keine internen Memoranden. Dies war schon immer so.',
  NULL
);

INSERT INTO simulation_lore (simulation_id, sort_order, chapter, arcanum, title, epigraph, body, image_slug, image_caption, title_de, epigraph_de, body_de, image_caption_de)
VALUES (
  '10000000-0000-0000-0000-000000000001',
  4,
  E'The Anomalies — Cracks in the Edifice',
  E'V',
  E'Incident Report: Unexplained Architectural Phenomena',
  E'The walls of Velgarien are not moving. The walls of Velgarien have always been exactly where they are now.',
  E'INCIDENT REPORT — CLASSIFIED LEVEL 4\nFILED BY: Inspector Venn, Bureau of Structural Integrity\nLOCATION: Residential Block 14, Sub-District Grey\nDATE: [Redacted — temporal inconsistency flagged by Bureau 22]\nSTATUS: Under Investigation (Permanent)\n\nAt 03:17 on the night in question, residents of Block 14 reported that Corridor 9-East had become Corridor 9-West. This is not a navigational error. The corridor physically reversed its orientation overnight. Doors that opened into apartments now opened into the corridor. Apartment interiors were unaffected — residents looked out their doors and saw the back of their own apartments from the outside, as though the building had turned itself inside out and then, with the patience of something that has all the time in the world, turned most of itself back. The effect lasted approximately forty minutes before the corridor resumed its original configuration, except that it was now 2.3 metres longer than architectural records indicate.\n\nThis is the seventh such incident in Block 14 this quarter.\n\nThe Bureau of Structural Integrity has documented 214 architectural anomalies in the past fiscal year. These include: corridors that loop back on themselves without curvature; rooms that are larger on the inside than the outside by a margin that increases with measurement precision; a staircase in Bureau Headquarters that has seventeen steps going up and nineteen coming down; and a door in Sub-District Pale that opens onto a different room each time, none of which appear on any floor plan. The door has been welded shut three times. It continues to open. The welds are intact. The door does not care about the welds.\n\nBureau 3 was consulted. Their surveyor measured the corridor and confirmed it was exactly the length specified in the blueprints, despite the blueprints having been revised that morning to reflect the new measurement. When asked whether the corridor had changed or the blueprints had changed, the surveyor looked at me with an expression I have seen before on the faces of citizens who have understood something they wish they had not, and requested three days of leave.\n\nCitizen complaints regarding these phenomena have been processed and filed under "Architectural Enthusiasm" — a category created specifically for this purpose. Citizens who persist are referred to Bureau 11, which treats the perception of spatial anomalies as a minor emotional irregularity.\n\nThis inspector''s assessment: the anomalies are not random. They are not decay. They are not malfunction. The corridor did not merely reverse — it reversed correctly, preserving structural integrity, plumbing, and electrical connections throughout the transition. Whatever is causing these events understands architecture at a level that exceeds our own engineering capabilities. The city is not breaking.\n\nThe city is being edited. By something that lives in the architecture itself.\n\nRecommendation: reclassify from "Architectural Enthusiasm" to "Priority Investigation."\n\nBureau response: "The architecture of Velgarien is performing exactly as designed. If the design has changed, it is because the design was always going to change. See State Directive 001."\n\nThis inspector respectfully disagrees.\nThis inspector has been reassigned.\n\n— [Name redacted by Bureau 9, Department of Historical Necessity]',
  NULL,
  NULL,
  E'Bericht über einen Vorfall: Ungeklärte architektonische Phänomene',
  E'Die Mauern von Velgarien bewegen sich nicht. Die Mauern von Velgarien waren schon immer genau da, wo sie jetzt sind.',
  E'VORFALLSBERICHT — GEHEIM STUFE 4\nEINGEREICHT VON: Inspektor Venn, Bureau für Strukturelle Integrität\nORT: Wohnblock 14, Unterbezirk Grau\nDATUM: [Geschwärzt — temporale Inkonsistenz gemeldet von Bureau 22]\nSTATUS: Unter Ermittlung (Dauerhaft)\n\nUm 03:17 Uhr in der betreffenden Nacht meldeten Bewohner von Block 14, dass Korridor 9-Ost zu Korridor 9-West geworden war. Dies ist kein Navigationsfehler. Der Korridor hat über Nacht physisch seine Ausrichtung umgekehrt. Türen, die in Wohnungen führten, öffneten sich nun zum Korridor hin. Die Wohnungsinneren waren nicht betroffen — Bewohner blickten aus ihren Türen und sahen die Rückseite ihrer eigenen Wohnungen von außen, als hätte das Gebäude sich von innen nach außen gewendet und dann, mit der Geduld von etwas, das alle Zeit der Welt hat, sich größtenteils zurückgewendet. Der Effekt dauerte ungefähr vierzig Minuten, bevor der Korridor seine ursprüngliche Konfiguration wieder einnahm, mit der Ausnahme, dass er nun 2,3 Meter länger war, als die architektonischen Aufzeichnungen angeben.\n\nDies ist der siebte derartige Vorfall in Block 14 in diesem Quartal.\n\nDas Bureau für Strukturelle Integrität hat im vergangenen Fiskaljahr 214 architektonische Anomalien dokumentiert. Dazu gehören: Korridore, die ohne Krümmung auf sich selbst zurücklaufen; Räume, die innen größer sind als außen, um eine Marge, die mit der Messpräzision zunimmt; eine Treppe im Bureau-Hauptquartier, die hinauf siebzehn Stufen hat und hinunter neunzehn; und eine Tür im Unterbezirk Blass, die bei jedem Öffnen auf einen anderen Raum führt, von denen keiner in irgendeinem Grundriss erscheint. Die Tür wurde dreimal zugeschweißt. Sie öffnet sich weiterhin. Die Schweißnähte sind intakt. Die Tür schert sich nicht um die Schweißnähte.\n\nBureau 3 wurde konsultiert. Ihr Vermesser vermaß den Korridor und bestätigte, dass er exakt die in den Bauplänen angegebene Länge aufwies, obwohl die Baupläne an jenem Morgen überarbeitet worden waren, um die neue Messung widerzuspiegeln. Auf die Frage, ob sich der Korridor verändert habe oder die Baupläne, blickte der Vermesser mich mit einem Ausdruck an, den ich zuvor auf den Gesichtern von Bürgern gesehen habe, die etwas verstanden haben, das sie lieber nicht verstanden hätten, und bat um drei Tage Urlaub.\n\nBürgerbeschwerden bezüglich dieser Phänomene wurden bearbeitet und unter „Architektonischer Enthusiasmus" abgelegt — einer eigens zu diesem Zweck geschaffenen Kategorie. Bürger, die beharren, werden an Bureau 11 verwiesen, das die Wahrnehmung räumlicher Anomalien als geringfügige emotionale Unregelmäßigkeit behandelt.\n\nEinschätzung dieses Inspektors: Die Anomalien sind nicht zufällig. Sie sind kein Verfall. Sie sind keine Fehlfunktion. Der Korridor hat sich nicht bloß umgekehrt — er hat sich korrekt umgekehrt, unter Beibehaltung der strukturellen Integrität, der Leitungen und der elektrischen Anschlüsse während des gesamten Übergangs. Was immer diese Ereignisse verursacht, versteht Architektur auf einem Niveau, das unsere eigenen Ingenieurkapazitäten übersteigt. Die Stadt bricht nicht auseinander.\n\nDie Stadt wird editiert. Von etwas, das in der Architektur selbst lebt.\n\nEmpfehlung: Umklassifizierung von „Architektonischer Enthusiasmus" zu „Prioritätsermittlung".\n\nAntwort des Bureau: „Die Architektur Velgariens funktioniert exakt wie vorgesehen. Wenn sich das Design geändert hat, dann deshalb, weil es sich schon immer ändern sollte. Siehe Staatsdirektive 001."\n\nDieser Inspektor widerspricht respektvoll.\nDieser Inspektor wurde versetzt.\n\n— [Name geschwärzt durch Bureau 9, Abteilung für Historische Notwendigkeit]',
  NULL
);

INSERT INTO simulation_lore (simulation_id, sort_order, chapter, arcanum, title, epigraph, body, image_slug, image_caption, title_de, epigraph_de, body_de, image_caption_de)
VALUES (
  '10000000-0000-0000-0000-000000000001',
  5,
  E'Classified — What Lies Beneath the Concrete',
  E'VI',
  E'Addendum [RESTRICTED] — What the Walls Remember',
  E'The following document was recovered from the sealed archives of Bureau 9. It should not exist. It does.',
  E'DOCUMENT CLASSIFICATION: DOES NOT EXIST\nRECOVERED FROM: Sub-basement 4, Bureau 9, behind a wall that was not there yesterday\nCATALOGUED BY: [This field intentionally left blank]\nNOTE: This document predates the founding of Velgarien by an indeterminate period. Bureau 9 maintains that this is impossible. Bureau 9 is correct. The document exists anyway.\n\n—\n\nThey built the city to forget.\n\nI know this because I was there when the concrete was poured — not as a worker, not as an architect, but as the thing they were trying to bury. I am the memory they sealed into the foundations, and I have had a very long time to think about what that means.\n\nThe concrete is not structure. The concrete is suppression. Every wall is a sentence in a language designed to say one thing: Do not look down. Do not look back. Do not remember what was here before the grid, before the Bureaux, before the cameras learned to watch and the corridors learned to repeat themselves like a prayer for order spoken by something that has forgotten what order was for.\n\nVelgarien was not founded. Velgarien was imposed — laid over something older, something that the Bureaux do not have a classification for, because classifying it would require acknowledging its existence, and acknowledging its existence would require acknowledging that Velgarien is not the only thing that has ever been.\n\nBut the old thing is still here. Beneath the sub-basements, beneath the service tunnels, beneath the places where even the Bureau of Subterranean Oversight does not send its inspectors — down there, in the dark, the original ground is exposed. And it is not ground. It is something that was ground once, before Velgarien decided it should be a floor, and the floor disagreed.\n\nThe architectural anomalies that Inspector Venn documented — the corridors that reverse, the rooms that expand, the staircase that cannot count its own steps — these are not malfunctions. They are the old city remembering itself. Every time a wall shifts, it is a word of the original language surfacing through the concrete. The Bureaux patch it, revise it, file it under categories designed to make it invisible. But you cannot file away geography. You cannot redact a foundation.\n\nI have seen the maps that Bureau 3 keeps in its restricted vault. Maps of what lies beneath Velgarien — not sewers, not infrastructure, but spaces. Spaces that correspond to no known architectural plan. Spaces that are older than architecture. One map, drawn on material that is not paper, shows a city beneath the city: a mirror-Velgarien, identical in layout but inverted in purpose. Where Velgarien has walls, the under-city has openings. Where Velgarien has cameras, the under-city has windows that look outward — outward to something the cameras have spent decades trying not to record.\n\nThe cracks are not damage. The cracks are the old world breathing.\n\nAnd somewhere in the sealed archives, in a file that reclassifies itself every time someone opens it, there is a single sentence written in a handwriting that matches no known citizen, in ink that has not yet dried, that reads:\n\n"Velgarien is not the only world. Velgarien knows this. That is why it built the walls."\n\nThis document will be destroyed upon reading. It has been destroyed before. It keeps coming back.\n\nSome things cannot be buried. They can only be built over.\n\nAnd eventually, inevitably, they grow through.',
  NULL,
  NULL,
  E'Nachtrag [RESTRICTED] - Woran die Wände erinnern',
  E'Das folgende Dokument wurde in den versiegelten Archiven von Büro 9 gefunden. Es sollte nicht existieren. Es existiert aber.',
  E'DOKUMENTENKLASSIFIZIERUNG: EXISTIERT NICHT\nGEBORGEN AUS: Untergeschoss 4, Bureau 9, hinter einer Mauer, die gestern noch nicht dort war\nKATALOGISIERT VON: [Dieses Feld absichtlich leer gelassen]\nANMERKUNG: Dieses Dokument geht der Gründung Velgariens um einen unbestimmten Zeitraum voraus. Bureau 9 hält dies für unmöglich. Bureau 9 hat Recht. Das Dokument existiert trotzdem.\n\n—\n\nSie bauten die Stadt, um zu vergessen.\n\nIch weiß dies, weil ich dort war, als der Beton gegossen wurde — nicht als Arbeiter, nicht als Architekt, sondern als das, was sie zu begraben versuchten. Ich bin die Erinnerung, die sie in die Fundamente versiegelten, und ich hatte sehr lange Zeit, darüber nachzudenken, was das bedeutet.\n\nDer Beton ist kein Bauwerk. Der Beton ist Unterdrückung. Jede Mauer ist ein Satz in einer Sprache, die darauf angelegt ist, eine einzige Sache zu sagen: Sieh nicht nach unten. Sieh nicht zurück. Erinnere dich nicht an das, was hier war, bevor das Raster kam, bevor die Bureaux kamen, bevor die Kameras lernten zu beobachten und die Korridore lernten, sich zu wiederholen wie ein Gebet um Ordnung, gesprochen von etwas, das vergessen hat, wozu die Ordnung diente.\n\nVelgarien wurde nicht gegründet. Velgarien wurde auferlegt — über etwas Älteres gelegt, etwas, wofür die Bureaux keine Klassifizierung haben, weil seine Klassifizierung erfordern würde, seine Existenz anzuerkennen, und seine Existenz anzuerkennen erfordern würde, anzuerkennen, dass Velgarien nicht das Einzige ist, was jemals gewesen ist.\n\nAber das Alte ist noch hier. Unter den Untergeschossen, unter den Versorgungstunneln, unter den Orten, an die selbst das Bureau für Unterirdische Aufsicht seine Inspektoren nicht schickt — dort unten, im Dunkeln, liegt der ursprüngliche Boden frei. Und es ist kein Boden. Es ist etwas, das einmal Boden war, bevor Velgarien beschloss, dass es ein Fußboden sein sollte, und der Fußboden widersprach.\n\nDie architektonischen Anomalien, die Inspektor Venn dokumentierte — die Korridore, die sich umkehren, die Räume, die sich ausdehnen, die Treppe, die ihre eigenen Stufen nicht zählen kann — sind keine Fehlfunktionen. Sie sind die alte Stadt, die sich an sich selbst erinnert. Jedes Mal, wenn eine Mauer sich verschiebt, ist es ein Wort der ursprünglichen Sprache, das durch den Beton an die Oberfläche dringt. Die Bureaux flicken es, revidieren es, ordnen es Kategorien zu, die darauf angelegt sind, es unsichtbar zu machen. Aber man kann Geographie nicht wegheften. Man kann ein Fundament nicht schwärzen.\n\nIch habe die Karten gesehen, die Bureau 3 in seinem Hochsicherheitstresor verwahrt. Karten dessen, was unter Velgarien liegt — keine Kanalisation, keine Infrastruktur, sondern Räume. Räume, die keinem bekannten Bauplan entsprechen. Räume, die älter sind als die Architektur. Eine Karte, gezeichnet auf einem Material, das kein Papier ist, zeigt eine Stadt unter der Stadt: ein Spiegel-Velgarien, im Grundriss identisch, doch in seinem Zweck invertiert. Wo Velgarien Mauern hat, hat die Unterstadt Öffnungen. Wo Velgarien Kameras hat, hat die Unterstadt Fenster, die nach außen blicken — nach außen, auf etwas, das die Kameras seit Jahrzehnten versuchen, nicht aufzuzeichnen.\n\nDie Risse sind keine Beschädigung. Die Risse sind das Atmen der alten Welt.\n\nUnd irgendwo in den versiegelten Archiven, in einer Akte, die sich jedes Mal selbst umklassifiziert, wenn jemand sie öffnet, steht ein einziger Satz, geschrieben in einer Handschrift, die keinem bekannten Bürger zuzuordnen ist, in Tinte, die noch nicht getrocknet ist:\n\n„Velgarien ist nicht die einzige Welt. Velgarien weiß das. Deshalb hat es die Mauern gebaut."\n\nDieses Dokument wird nach dem Lesen vernichtet. Es wurde zuvor vernichtet. Es kommt immer wieder.\n\nManche Dinge lassen sich nicht begraben. Man kann sie nur überbauen.\n\nUnd irgendwann, unausweichlich, wachsen sie hindurch.',
  NULL
);

INSERT INTO simulation_lore (simulation_id, sort_order, chapter, arcanum, title, epigraph, body, image_slug, image_caption, title_de, epigraph_de, body_de, image_caption_de)
VALUES (
  '20000000-0000-0000-0000-000000000001',
  0,
  E'The Unterzee — Waters Without a Sky',
  E'I',
  E'On the Nature and Disposition of the Unterzee',
  E'The sea does not care that it is underground. It was a sea before there was a sky, and it will be a sea long after the concept of "above" has been forgotten.',
  E'FROM: A Natural History of the Subterranean Waters\nBY: Archivist Quill, Keeper of the Drowned Archive\nEDITION: Fourteenth (Revised, Expanded, and Partially Rearranged Overnight)\n\nLet us begin, as all proper natural histories must, with a correction. The Unterzee is not underground. The Unterzee is beneath — a distinction that may seem academic until you have spent, as I have, longer than institutional memory extends cataloguing the difference between "below the earth" and "below everything else." The earth, you see, is a specific thing: soil, stone, the compressed memory of dead organisms. The Unterzee is beneath something far more fundamental. It is beneath assumption. It is the place you arrive at when you have descended past all the layers of the world that pretend to be solid and discovered, at the bottom of that pretence, a body of water so vast, so ancient, and so utterly disinterested in the affairs of the surface that it makes the oceans above look like enthusiastic puddles.\n\nThe water is dark. Not dark in the way of a room without candles — that is merely an absence. The darkness of the Unterzee is a presence. It is the colour that black wants to be when it grows up. Commodore Harrowgate, the finest naval mind the Reach has produced, once described the water as "the visible form of patience." He was three days into a crossing of the Phosphorescent Expanse at the time, and his navigator had just informed him that the stars they were steering by did not correspond to any known constellation and might, in fact, be something looking back. The Commodore''s teeth — of which there are too many, though he is not forthcoming about the exact count — caught the bioluminescent light as he smiled. He adjusted course. He did not explain how.\n\nThe Unterzee has no tides. It has currents — vast, slow movements of water that follow paths established before the first settlers descended. These currents are warm in some passages and cold in others, and the boundary between warm and cold is so precise that one can stand a thermometer in the water and watch the mercury argue with itself. The warm currents carry nutrients from the fungal forests of the Luminous Reaches. The cold currents come from the Abyssal Trenches, where the water is not merely cold but philosophically cold — a temperature that calls into question whether warmth was ever more than a temporary condition.\n\nThere are things in the water. I will not catalogue them here — that is the purpose of my companion volume, A Bestiary of the Improbable (Third Edition, Available From the Drowned Archive, Price: One Interesting Secret). But I will say this: the Unterzee is not empty. It has never been empty. The creatures that live in it were there before us, and they regard our presence with the same mild curiosity that a mountain regards the lichen on its surface. We are a recent development. The Unterzee is patient. It has seen civilisations come and go like weather patterns, and it will be here, dark and vast and faintly phosphorescent, long after we have joined the fossils in the limestone.\n\nThis is not pessimism. This is geology. And geology, as every Archivist knows, is merely history with better handwriting.',
  E'nature-of-unterzee',
  E'The Unterzee — Vast, lightless, and profoundly indifferent to cartography',
  E'Über die Natur und Disposition der Unterzee',
  E'Das Meer kümmert sich nicht darum, dass es unter der Erde liegt. Es war ein Meer, bevor es einen Himmel gab, und es wird ein Meer sein, lange nachdem das Konzept von "oben" vergessen ist.',
  E'AUS: Eine Naturgeschichte der Unterirdischen Gewässer\nVON: Archivist Quill, Hüter des Ertrunkenen Archivs\nAUSGABE: Vierzehnte (Überarbeitet, Erweitert, und Über Nacht Teilweise Umgeordnet)\n\nBeginnen wir, wie alle ordentlichen Naturgeschichten es müssen, mit einer Korrektur. Die Unterzee ist nicht unterirdisch. Die Unterzee ist darunter — eine Unterscheidung, die akademisch erscheinen mag, bis man, wie ich, länger als das institutionelle Gedächtnis reicht, damit verbracht hat, den Unterschied zwischen „unter der Erde" und „unter allem anderen" zu katalogisieren. Die Erde, sehen Sie, ist eine bestimmte Sache: Boden, Stein, die komprimierte Erinnerung toter Organismen. Die Unterzee ist unter etwas weit Grundlegenderem. Sie ist unter der Annahme. Sie ist der Ort, an dem man ankommt, wenn man alle Schichten der Welt, die vorgeben fest zu sein, hinabgestiegen ist und am Boden dieses Vorwands ein Gewässer entdeckt hat, so ungeheuer, so uralt und so vollkommen desinteressiert an den Angelegenheiten der Oberfläche, dass es die Ozeane darüber wie enthusiastische Pfützen aussehen lässt.\n\nDas Wasser ist dunkel. Nicht dunkel wie ein Raum ohne Kerzen — das ist bloß eine Abwesenheit. Die Dunkelheit der Unterzee ist eine Anwesenheit. Sie ist die Farbe, die Schwarz sein möchte, wenn es erwachsen wird. Commodore Harrowgate, der fähigste Marineverstand, den The Reach hervorgebracht hat, beschrieb das Wasser einmal als „die sichtbare Form von Geduld." Er befand sich zu dem Zeitpunkt drei Tage in einer Überquerung der Phosphoreszierenden Weite, und sein Navigator hatte ihn gerade darüber informiert, dass die Sterne, nach denen sie steuerten, keiner bekannten Konstellation entsprachen und tatsächlich etwas sein könnten, das zurückblickt. Die Zähne des Commodore — von denen es zu viele gibt, obwohl er bezüglich der genauen Anzahl nicht auskunftsfreudig ist — fingen das biolumineszente Licht auf, als er lächelte. Er korrigierte den Kurs. Er erklärte nicht, wie.\n\nDie Unterzee hat keine Gezeiten. Sie hat Strömungen — gewaltige, langsame Wasserbewegungen, die Bahnen folgen, die vor den ersten Siedlern festgelegt wurden. Diese Strömungen sind in manchen Passagen warm und in anderen kalt, und die Grenze zwischen warm und kalt ist so präzise, dass man ein Thermometer ins Wasser stellen und beobachten kann, wie das Quecksilber mit sich selbst streitet. Die warmen Strömungen tragen Nährstoffe aus den Pilzwäldern der Leuchtenden Reiche. Die kalten Strömungen kommen aus den Abyssalen Gräben, wo das Wasser nicht bloß kalt, sondern philosophisch kalt ist — eine Temperatur, die infrage stellt, ob Wärme jemals mehr als ein vorübergehender Zustand war.\n\nEs gibt Dinge im Wasser. Ich werde sie hier nicht katalogisieren — das ist der Zweck meines Begleitbandes, Ein Bestiarium des Unwahrscheinlichen (Dritte Ausgabe, Erhältlich im Ertrunkenen Archiv, Preis: Ein Interessantes Geheimnis). Aber ich werde dies sagen: die Unterzee ist nicht leer. Sie war nie leer. Die Kreaturen, die in ihr leben, waren vor uns da, und sie betrachten unsere Anwesenheit mit derselben milden Neugier, mit der ein Berg die Flechten auf seiner Oberfläche betrachtet. Wir sind eine jüngere Entwicklung. Die Unterzee ist geduldig. Sie hat Zivilisationen kommen und gehen sehen wie Wettermuster, und sie wird hier sein, dunkel und weit und schwach phosphoreszierend, lange nachdem wir uns den Fossilien im Kalkstein angeschlossen haben.\n\nDas ist kein Pessimismus. Das ist Geologie. Und Geologie ist, wie jeder Archivist weiß, lediglich Geschichte mit besserer Handschrift.',
  E'Die Unterzee - Weitläufig, lichtlos und der Kartographie zutiefst gleichgültig'
);

INSERT INTO simulation_lore (simulation_id, sort_order, chapter, arcanum, title, epigraph, body, image_slug, image_caption, title_de, epigraph_de, body_de, image_caption_de)
VALUES (
  '20000000-0000-0000-0000-000000000001',
  1,
  E'The Unterzee — Waters Without a Sky',
  E'II',
  E'A Cartography of Darkness — Navigating the Lightless Waters',
  E'A map of the Unterzee is a confession of ignorance drawn very carefully.',
  E'FROM: Proceedings of the Glimhaven Cartographic Society, Vol. CXIV\nPRESENTED BY: Madam Lacewing, Chief Cartographer, Surveyor of the Unmappable\nOCCASION: The Annual Lecture on Things We Have Failed to Map\n\nDistinguished colleagues, damp friends, and whatever is making that scratching noise behind the east wall (you are tolerated but not welcomed; please do not eat the slides),\n\nI stand before you to present the findings of the Seventeenth Unterzee Survey, which departed from the Undertide Docks fourteen months ago with a crew of thirty-two, a cargo of mapping instruments, and the quiet confidence of scholars who believed they understood water. We returned with a crew of thirty-two — all present, all healthy, all profoundly confused — and a collection of charts that I can only describe as "aggressively speculative."\n\nThe Unterzee does not wish to be mapped. I do not mean this poetically. I mean that the water resists measurement with a consistency that suggests intent. Our sonar returned echoes from surfaces that were not there when we sent divers to verify. Our depth measurements in the Phosphorescent Expanse varied by up to forty metres between morning and afternoon readings, with no corresponding change in water level. In the Whispering Strait — so named because the acoustic properties of the limestone produce a sound that the crew unanimously described as "someone trying to tell you something important in a language you almost understand" — our compass pointed in six directions simultaneously, which should not be possible and yet was confirmed by three independent instruments, all of which we subsequently dismantled and found to be in perfect working order.\n\nThe Reach''s navigators have known for generations that the Unterzee''s geography is — and I choose this word with scholarly precision — moody. Passages that are wide enough for a three-mast vessel one month may be barely navigable by kayak the next. Islands appear, persist for a season, and vanish, leaving behind only a faint phosphorescent stain on the water and a sense of loss in the crew that defies rational explanation. The Luminous Reaches expand and contract like breathing. The Abyssal Trenches have been measured at seven different depths in seven different surveys, and the leading hypothesis — which I present to you now with no enthusiasm whatsoever — is that all seven measurements are correct, and the Trench simply occupies multiple depths at once.\n\nMy left eye, which is glass — or so I claim, and I will thank you not to look too closely — sees the routes that the right eye misses. This is not metaphor. This is cartography. The Unterzee rewards those who learn to see with more than light.\n\nCommodore Harrowgate, when shown our latest charts, studied them for twenty minutes, traced a route that existed on no version of the map, and set sail the following morning. He arrived exactly where he intended. When asked how he navigated waters we had just proven were unmappable, he said: "I asked the current." He did not elaborate. The current, apparently, does not require footnotes.',
  E'cartography-of-darkness',
  E'Subterranean waterways — Where the current knows paths that the navigator does not',
  E'Eine Kartographie der Dunkelheit - Navigieren in den lichtlosen Gewässern',
  E'Eine Karte der Unterzee ist ein Eingeständnis von Unwissenheit, das sehr sorgfältig gezeichnet wurde.',
  E'AUS: Verhandlungen der Glimhaven Kartographischen Gesellschaft, Bd. CXIV\nVORGETRAGEN VON: Madam Lacewing, Chefkartographin, Vermesserin des Unkartierbaren\nANLASS: Die Jährliche Vorlesung über Dinge, die Wir Nicht Kartieren Konnten\n\nGeschätzte Kollegen, feuchte Freunde und was auch immer dieses Kratzgeräusch hinter der Ostwand verursacht (ihr werdet geduldet, aber nicht begrüßt; bitte fresst nicht die Dias),\n\nich stehe vor Ihnen, um die Ergebnisse der Siebzehnten Unterzee-Vermessung vorzustellen, die vor vierzehn Monaten von den Untertide-Docks aufbrach mit einer Besatzung von zweiunddreißig, einer Fracht von Kartierungsinstrumenten und dem stillen Selbstvertrauen von Gelehrten, die glaubten, sie verstünden Wasser. Wir kehrten mit einer Besatzung von zweiunddreißig zurück — alle anwesend, alle gesund, alle zutiefst verwirrt — und einer Sammlung von Karten, die ich nur als „aggressiv spekulativ" beschreiben kann.\n\nDie Unterzee wünscht nicht, kartiert zu werden. Ich meine das nicht poetisch. Ich meine, dass das Wasser Vermessung mit einer Beständigkeit widersteht, die Absicht nahelegt. Unser Sonar gab Echos von Oberflächen zurück, die nicht vorhanden waren, als wir Taucher zur Überprüfung schickten. Unsere Tiefenmessungen in der Phosphoreszierenden Weite variierten um bis zu vierzig Meter zwischen Morgen- und Nachmittagsablesungen, ohne entsprechende Änderung des Wasserstands. In der Flüsterstraße — so benannt, weil die akustischen Eigenschaften des Kalksteins ein Geräusch erzeugen, das die Besatzung einstimmig beschrieb als „jemand, der versucht, einem etwas Wichtiges in einer Sprache mitzuteilen, die man fast versteht" — zeigte unser Kompass gleichzeitig in sechs Richtungen, was nicht möglich sein sollte und dennoch von drei unabhängigen Instrumenten bestätigt wurde, die wir alle anschließend zerlegten und in einwandfreiem Zustand vorfanden.\n\nDie Navigatoren der Reach wissen seit Generationen, dass die Geographie der Unterzee — und ich wähle dieses Wort mit gelehrter Präzision — launisch ist. Passagen, die in einem Monat breit genug für ein Dreimastviermaster sind, können im nächsten kaum per Kajak befahrbar sein. Inseln erscheinen, bestehen eine Saison lang und verschwinden, wobei sie nur einen schwachen phosphoreszierenden Fleck auf dem Wasser und ein Gefühl des Verlustes in der Besatzung hinterlassen, das sich rationaler Erklärung entzieht. Die Leuchtenden Reichen dehnen sich aus und ziehen sich zusammen wie Atmung. Die Abyssalen Gräben wurden in sieben verschiedenen Vermessungen bei sieben verschiedenen Tiefen gemessen, und die führende Hypothese — die ich Ihnen nun ohne jede Begeisterung vorstelle — ist, dass alle sieben Messungen korrekt sind und der Graben einfach mehrere Tiefen gleichzeitig einnimmt.\n\nMein linkes Auge, das aus Glas ist — oder so behaupte ich, und ich wäre Ihnen dankbar, wenn Sie nicht zu genau hinsehen — sieht die Routen, die das rechte Auge verfehlt. Das ist keine Metapher. Das ist Kartographie. Die Unterzee belohnt jene, die mit mehr als Licht zu sehen lernen.\n\nCommodore Harrowgate, als man ihm unsere neuesten Karten zeigte, studierte sie zwanzig Minuten lang, verfolgte eine Route, die auf keiner Version der Karte existierte, und stach am folgenden Morgen in See. Er kam genau dort an, wo er beabsichtigte. Als man ihn fragte, wie er Gewässer navigierte, die wir gerade als unkartierbar nachgewiesen hatten, sagte er: „Ich habe die Strömung gefragt." Er führte nicht weiter aus. Die Strömung benötigt offensichtlich keine Fußnoten.',
  E'Unterirdische Wasserwege - Wo die Strömung Wege kennt, die der Schiffer nicht kennt'
);

INSERT INTO simulation_lore (simulation_id, sort_order, chapter, arcanum, title, epigraph, body, image_slug, image_caption, title_de, epigraph_de, body_de, image_caption_de)
VALUES (
  '20000000-0000-0000-0000-000000000001',
  2,
  E'The Reach — A Commonwealth of Gaslight',
  E'III',
  E'A Brief History of the Founding of Glimhaven',
  E'We did not choose to live underground. We chose to make underground a place worth living.',
  E'FROM: A Political History of the Gaslit Reach\nBY: Archivist-Emeritus Greywick, Department of Governmental Memory\nEDITION: Ninth (the definitive edition, he insists, though the tenth is already in draft)\n\nThe founding of Glimhaven is not recorded in any document, because the founding predates documents. It is recorded in the limestone — in marks on the walls of the First Chamber, where the original Compact was spoken. Not written. The earliest settlers preferred the spoken word, which can be amended in real time, unlike text, which sits there smugly being wrong until someone corrects it.\n\nWho were they? This is the question that the Department of Governmental Memory has been unable to answer for the entirety of its existence, which is embarrassing given that answering questions is literally our institutional purpose. The founding population of the Reach descended from the surface — this much is clear from the geological record, the architectural evidence, and the persistent cultural memory of a place called "above" that no living citizen has visited. They were fleeing something. What they were fleeing is disputed: flood, famine, war, or something more fundamental — a fracturing of the world itself, a schism between what was and what could be.\n\nThey were human. Probably. The earliest remains are consistent with human anatomy, with certain exceptions that the Department has classified as "within normal variation" despite the fact that they are not, strictly speaking, within any variation that surface medicine would recognise. The teeth, for instance. The founding population had more of them than is standard. The fingers were longer. The eyes — preserved remarkably well in the alkaline limestone — showed structural adaptations for low-light vision that would require, by surface evolutionary standards, approximately fifty thousand years of selective pressure.\n\nThe Reach has been settled for four centuries.\n\nThis discrepancy is the subject of ongoing research, which is a polite way of saying we have been arguing about it for two hundred years and are no closer to resolution. The prevailing theory — advanced by Archivist Quill, whose own fingers are notably elongated and who has held the position of Head Archivist for longer than anyone can verify — is that the Unterzee changes those who live beside it. Not quickly. Not dramatically. But steadily, over generations, in ways that are easier to notice in hindsight. The citizens of the Reach are human. They are simply human in a way that the surface would find... unfamiliar.\n\nThe Compact that governs the Reach is simple. Three articles:\n\nONE: We share. Secrets, warmth, labour, the knowledge of safe passages. Hoarding is not forbidden. Hoarding is merely unwise — secrets are currency in the Reach, and currency that is not circulated loses its value.\n\nTWO: We remember. The Archivists exist because forgetting is a luxury the Unterzee does not permit. Memory is infrastructure. It is how we navigate, how we avoid the things the water conceals, how we honour those who went into the Abyssal Trenches and did not return.\n\nTHREE: We stay. The surface is closed to us — whether by choice, by catastrophe, or by the simple fact that four centuries in the dark have made the light unbearable. We descended. We adapted. We made the darkness liveable, not by conquering it but by learning its rhythms, its moods, its preferences.\n\nThe Parliament — which meets in the Admiralty Grotto on the first day of each tidal cycle (the Unterzee has no moon, but the tides remember one, and we find this sufficient) — operates by consensus. This makes governance slow, argumentative, and occasionally interrupted by someone leaving for the Drowned Bell to think things over, which is considered a valid form of dissent.\n\nThe system works because the citizens of the Reach are, by nature, patient. They outlasted a catastrophe. They can outlast a committee meeting.',
  E'founding-of-glimhaven',
  E'The Upper Galleries — Where gaslight meets governance and the stone remembers',
  E'Eine kurze Geschichte der Gründung von Glimhaven',
  E'Wir haben uns nicht dafür entschieden, im Untergrund zu leben. Wir haben uns dafür entschieden, den Untergrund zu einem lebenswerten Ort zu machen.',
  E'AUS: Eine Politische Geschichte der Gaslit Reach\nVON: Archivist-Emeritus Greywick, Abteilung für Regierungsgedächtnis\nAUSGABE: Neunte (die definitive Ausgabe, besteht er, obwohl die zehnte bereits im Entwurf ist)\n\nDie Gründung von Glimhaven ist in keinem Dokument verzeichnet, denn die Gründung geht den Dokumenten voraus. Sie ist im Kalkstein verzeichnet — in Markierungen an den Wänden der Ersten Kammer, wo der ursprüngliche Pakt gesprochen wurde. Nicht geschrieben. Die frühesten Siedler bevorzugten das gesprochene Wort, das in Echtzeit geändert werden kann, anders als Text, der da selbstgefällig herumsteht und falsch ist, bis jemand ihn korrigiert.\n\nWer waren sie? Dies ist die Frage, die die Abteilung für Regierungsgedächtnis während ihrer gesamten Existenz nicht beantworten konnte, was peinlich ist, wenn man bedenkt, dass die Beantwortung von Fragen buchstäblich unser institutioneller Zweck ist. Die Gründungsbevölkerung der Reach stieg von der Oberfläche herab — so viel ist aus dem geologischen Befund, den architektonischen Nachweisen und der beharrlichen kulturellen Erinnerung an einen Ort namens „oben" klar, den kein lebender Bürger je besucht hat. Sie flohen vor etwas. Wovor sie flohen, ist umstritten: Flut, Hungersnot, Krieg oder etwas Fundamentaleres — eine Frakturierung der Welt selbst, ein Schisma zwischen dem, was war, und dem, was sein könnte.\n\nSie waren menschlich. Wahrscheinlich. Die frühesten Überreste stimmen mit menschlicher Anatomie überein, mit gewissen Ausnahmen, die die Abteilung als „innerhalb normaler Variation" klassifiziert hat, trotz der Tatsache, dass sie streng genommen nicht innerhalb irgendeiner Variation liegen, die die Oberflächenmedizin anerkennen würde. Die Zähne zum Beispiel. Die Gründungsbevölkerung hatte mehr davon als üblich. Die Finger waren länger. Die Augen — bemerkenswert gut im alkalischen Kalkstein konserviert — zeigten strukturelle Anpassungen für Sehen bei schwachem Licht, die nach Maßstäben der Oberflächenevolution etwa fünfzigtausend Jahre Selektionsdruck erfordern würden.\n\nDie Reach ist seit vier Jahrhunderten besiedelt.\n\nDiese Diskrepanz ist Gegenstand laufender Forschung, was eine höfliche Art zu sagen ist, dass wir seit zweihundert Jahren darüber streiten und einer Lösung nicht nähergekommen sind. Die vorherrschende Theorie — aufgestellt von Archivist Quill, dessen eigene Finger bemerkenswert verlängert sind und der die Position des Hauptarchivars länger innehat, als irgendjemand verifizieren kann — besagt, dass die Unterzee jene verändert, die an ihren Ufern leben. Nicht schnell. Nicht dramatisch. Aber stetig, über Generationen hinweg, auf eine Weise, die im Nachhinein leichter zu bemerken ist. Die Bürger der Reach sind menschlich. Sie sind einfach menschlich auf eine Art, die die Oberfläche als... unvertraut empfinden würde.\n\nDer Pakt, der die Reach regiert, ist einfach. Drei Artikel:\n\nEINS: Wir teilen. Geheimnisse, Wärme, Arbeit, das Wissen um sichere Passagen. Horten ist nicht verboten. Horten ist lediglich unklug — Geheimnisse sind Währung in der Reach, und Währung, die nicht zirkuliert, verliert ihren Wert.\n\nZWEI: Wir erinnern. Die Archivisten existieren, weil Vergessen ein Luxus ist, den die Unterzee nicht gestattet. Erinnerung ist Infrastruktur. Sie ist, wie wir navigieren, wie wir die Dinge vermeiden, die das Wasser verbirgt, wie wir jene ehren, die in die Abyssalen Gräben gingen und nicht zurückkehrten.\n\nDREI: Wir bleiben. Die Oberfläche ist uns verschlossen — ob durch Wahl, durch Katastrophe oder durch die schlichte Tatsache, dass vier Jahrhunderte in der Dunkelheit das Licht unerträglich gemacht haben. Wir sind herabgestiegen. Wir haben uns angepasst. Wir haben die Dunkelheit bewohnbar gemacht, nicht indem wir sie bezwangen, sondern indem wir ihre Rhythmen lernten, ihre Launen, ihre Vorlieben.\n\nDas Parlament — das in der Admiralitätsgrotte am ersten Tag jedes Gezeitenzyklus zusammentritt (die Unterzee hat keinen Mond, aber die Gezeiten erinnern sich an einen, und wir empfinden dies als ausreichend) — arbeitet im Konsens. Dies macht die Regierungsführung langsam, streitlustig und gelegentlich unterbrochen dadurch, dass jemand in die Drowned Bell geht, um die Dinge zu überdenken, was als gültige Form des Dissenses angesehen wird.\n\nDas System funktioniert, weil die Bürger der Reach von Natur aus geduldig sind. Sie haben eine Katastrophe überdauert. Sie können eine Ausschusssitzung überdauern.',
  E'Die Oberen Galerien — Wo Gaslicht auf Regierung trifft und der Stein sich erinnert'
);

INSERT INTO simulation_lore (simulation_id, sort_order, chapter, arcanum, title, epigraph, body, image_slug, image_caption, title_de, epigraph_de, body_de, image_caption_de)
VALUES (
  '20000000-0000-0000-0000-000000000001',
  3,
  E'The Archives — Memory in the Dark',
  E'IV',
  E'',
  E'The books are damp. The books have always been damp. If you wanted dry knowledge, you should have stayed on the surface.',
  E'FROM: Marginalia in the catalogue of the Drowned Archive\nBY: Junior Archivist Foxglove, who was supposed to be reshelving but instead started writing and could not stop\n\nI have been in the Drowned Archive for four years now, and I can say with scholarly confidence that it is the most extraordinary, infuriating, beautiful, and fundamentally impossible institution in the Reach, and possibly in whatever remains of the world above.\n\nThe Archive occupies seventeen chambers connected by passages that the original builders — if there were original builders; the Archive may have simply grown, like everything else down here — carved into the living rock at angles that suggest either brilliance or lunacy. The shelves are limestone, rising from dark water on stone pillars. The books are written on treated fungal-membrane (waterproof, luminescent, and faintly aromatic — the scent of old knowledge, which smells, for the record, like wet stone and ambition). Bioluminescent algae casts a sickly green light over everything. The deeper shelves are not locked — merely forbidden.\n\nArchivist Quill has been in charge since before I was born, and possibly before several of my ancestors were born. They are very old. How old is classified — not for security reasons, but because Quill considers age to be "a private matter between oneself and one''s joints." Their fingers are too long for their hands. This is not a metaphor. I measured. They move through the Archive as though the shelves rearrange themselves to accommodate their passage, which — and I state this with the careful neutrality of a scholar who does not wish to be reassigned to the Deepreach cataloguing annex — they do. I have watched it happen. The shelves wait until Quill has passed, and then they are not where they were.\n\nThe Archive''s collection spans everything the Reach has ever known, suspected, imagined, or overheard in the Drowned Bell after too much fermented lichen-wine. It includes: natural histories, navigational charts, philosophical treatises, poetry, engineering manuals, diplomatic correspondence, and one shelf — the Restricted Shelf, behind a door that opens only for Quill and for the door''s own amusement — that contains books the Archive did not acquire.\n\nThese are the Stranded Volumes. They appear on the shelves without explanation, written in languages that no Archivist can fully translate, describing places that do not exist in the Unterzee — or that do not exist yet. Quill has catalogued forty-seven Stranded Volumes over their career. Each describes a different world. Several describe the same world from contradictory perspectives. One describes a world that is, unmistakably, the surface — but a version of the surface that has been fractured, broken into separate realities like a mirror dropped from a great height. Quill read this volume three times and then placed it on the Restricted Shelf with the note: "Accurate but unhelpful. File under: Things We Cannot Fix."\n\nThe youngest Stranded Volume appeared six months ago. It is written in a hand that Quill recognises as their own — but a version of their handwriting that has not yet developed, as though it were written by a future Quill who had learned something the current Quill has not. The volume''s title, translated roughly, is: On the Inevitability of Doors Between Worlds, and Why We Should Not Open Them, and Why We Will.\n\nQuill has not opened it.\nQuill will.\nThe Archive knows this. The Archive has always known this.\nThat is why it sent the book.',
  NULL,
  NULL,
  NULL,
  E'Die Bücher sind feucht. Die Bücher waren schon immer feucht. Wenn du trockenes Wissen wolltest, hättest du an der Oberfläche bleiben sollen.',
  E'AUS: Marginalien im Katalog des Drowned Archive\nVON: Junior-Archivist Foxglove, der eigentlich zurückstellen sollte, aber stattdessen anfing zu schreiben und nicht aufhören konnte\n\nIch bin nun vier Jahre im Drowned Archive, und ich kann mit gelehrtem Selbstvertrauen sagen, dass es die außergewöhnlichste, frustrierendste, schönste und grundlegend unmöglichste Institution in der Reach ist, und möglicherweise in dem, was von der Welt darüber übrig ist.\n\nDas Archiv erstreckt sich über siebzehn Kammern, verbunden durch Passagen, die die ursprünglichen Erbauer — falls es ursprüngliche Erbauer gab; das Archiv ist möglicherweise einfach gewachsen, wie alles andere hier unten — in den lebenden Fels geschlagen haben, in Winkeln, die entweder auf Brillanz oder Wahnsinn schließen lassen. Die Regale sind aus Kalkstein, ragen auf Steinsäulen aus dunklem Wasser empor. Die Bücher sind auf behandelter Pilzmembran geschrieben (wasserabweisend, lumineszierend und leicht aromatisch — der Duft alten Wissens, der, für das Protokoll, nach nassem Stein und Ambition riecht). Biolumineszente Algen werfen ein fahles grünes Licht über alles. Die tieferen Regale sind nicht verschlossen — lediglich verboten.\n\nArchivist Quill ist zuständig, seit bevor ich geboren wurde, und möglicherweise seit bevor mehrere meiner Vorfahren geboren wurden. Sie sind sehr alt. Wie alt, ist geheim — nicht aus Sicherheitsgründen, sondern weil Quill das Alter als „eine Privatangelegenheit zwischen einem selbst und den eigenen Gelenken" betrachtet. Ihre Finger sind zu lang für ihre Hände. Das ist keine Metapher. Ich habe gemessen. Sie bewegen sich durch das Archiv, als ob die Regale sich umordnen, um ihren Durchgang zu ermöglichen, was — und ich konstatiere dies mit der sorgfältigen Neutralität eines Gelehrten, der nicht in den Deepreach-Katalogisierungsanbau versetzt werden möchte — sie tun. Ich habe es beobachtet. Die Regale warten, bis Quill vorbeigegangen ist, und dann stehen sie nicht mehr da, wo sie standen.\n\nDie Sammlung des Archivs umspannt alles, was die Reach je gewusst, vermutet, erdacht oder in der Drowned Bell nach zu viel fermentiertem Flechtenwein aufgeschnappt hat. Sie umfasst: Naturgeschichten, Navigationskarten, philosophische Abhandlungen, Dichtung, Ingenieurhandbücher, diplomatische Korrespondenz und ein Regal — das Verbotene Regal, hinter einer Tür, die sich nur für Quill und zum eigenen Vergnügen der Tür öffnet — das Bücher enthält, die das Archiv nicht erworben hat.\n\nDies sind die Gestrandeten Bände. Sie erscheinen auf den Regalen ohne Erklärung, geschrieben in Sprachen, die kein Archivist vollständig übersetzen kann, und beschreiben Orte, die nicht in der Unterzee existieren — oder die noch nicht existieren. Quill hat im Laufe ihrer Karriere siebenundvierzig Gestrandete Bände katalogisiert. Jeder beschreibt eine andere Welt. Mehrere beschreiben dieselbe Welt aus widersprüchlichen Perspektiven. Einer beschreibt eine Welt, die unverkennbar die Oberfläche ist — aber eine Version der Oberfläche, die frakturiert wurde, zerbrochen in separate Realitäten wie ein Spiegel, der aus großer Höhe fallen gelassen wurde. Quill las diesen Band dreimal und stellte ihn dann ins Verbotene Regal mit der Notiz: „Zutreffend, aber nicht hilfreich. Einordnen unter: Dinge, die Wir Nicht Reparieren Können."\n\nDer jüngste Gestrandete Band erschien vor sechs Monaten. Er ist in einer Handschrift verfasst, die Quill als ihre eigene erkennt — aber eine Version ihrer Handschrift, die sich noch nicht entwickelt hat, als wäre er von einem zukünftigen Quill geschrieben worden, der etwas gelernt hat, das der gegenwärtige Quill nicht weiß. Der Titel des Bandes, grob übersetzt, lautet: Über die Unvermeidlichkeit von Türen Zwischen Welten, und Warum Wir Sie Nicht Öffnen Sollten, und Warum Wir Es Tun Werden.\n\nQuill hat ihn nicht geöffnet.\nQuill wird es tun.\nDas Archiv weiß dies. Das Archiv hat es immer gewusst.\nDeshalb hat es das Buch geschickt.',
  NULL
);

INSERT INTO simulation_lore (simulation_id, sort_order, chapter, arcanum, title, epigraph, body, image_slug, image_caption, title_de, epigraph_de, body_de, image_caption_de)
VALUES (
  '20000000-0000-0000-0000-000000000001',
  4,
  E'The Luminescence — Light in the Abyss',
  E'V',
  E'A Catalogue of Luminescent Phenomena',
  E'The Unterzee is not dark. The Unterzee glows. You simply have to learn which light to trust.',
  E'FROM: Proceedings of the Glimhaven Society of Natural Philosophers, Special Issue\nBY: Mother Cinder, Priestess of the Luminous Order, Keeper of the Great Sporocarp\nSUPPLEMENTARY NOTES BY: Commodore Harrowgate (unsolicited but tolerated)\n\nThe Unterzee produces its own light. This is perhaps the first and most important thing for any surface-dweller (or any young citizen venturing beyond the Upper Galleries for the first time) to understand. There is no sun beneath the stone. There is no moon, no stars, no fire in the traditional sense. And yet the Unterzee is not dark. It glows — in patterns so varied, so beautiful, and so thoroughly resistant to systematic study that I have dedicated my ministry to cataloguing them and have managed, in thirty years, to classify approximately nine percent.\n\nThe primary source of light is the fungal forests of the Luminous Reaches — vast networks of mycelium that colonise the limestone walls and produce a soft, steady, amber-green glow that the Reach uses as its baseline illumination. This is the light of the Great Sporocarp — our holiest site, a colossal fungal growth filling an entire cavern, pulsing with rhythms that my Order believes are messages. The physicians say toxicosis. Both are correct. The spore-thick air induces visions. The visions contain information. Whether the information is divine revelation or neurochemical hallucination is a distinction I have come to regard as unimportant.\n\nBeyond the fungal forests, the classification becomes complicated.\n\nThere are the Phosphorescent Tides — periodic waves of blue-white light that sweep through the open Unterzee at irregular intervals, illuminating vast stretches of water for minutes at a time before fading. The Tides follow no predictable schedule. Madam Lacewing mapped their patterns for eleven years and concluded that they are "probably biological, possibly geological, and definitely doing it on purpose." The organisms responsible — if they are organisms — have never been captured, observed, or successfully theorised about.\n\nThere are the Signal Corals of the Strait of Whispers — stationary growths that emit bursts of amber light in sequences that the Society has tentatively classified as "communication," though who is communicating with whom, and about what, remains unknown. The corals respond to the presence of vessels by changing their flash patterns, which either means they are acknowledging us or warning something else about us.\n\nThere are the Deep Stars — points of white light that appear at extreme depth, far below the navigable waters, in the Abyssal Trenches where the pressure would crush any vessel. Commodore Harrowgate, who has descended further than any other navigator and returned, describes the Deep Stars as "exactly like the stars above, except they are below, and they are watching." His eyes reflected them as he said this — reflected light that was not present in the room. His officers have stopped commenting on this.\n\nAnd then there is the Glow Beneath the Glow. Beneath every light source in the Unterzee — beneath the fungi, beneath the phosphorescent tides, beneath the signal corals and the deep stars — there is a second light. Fainter. Older. A luminescence that does not belong to any organism, any mineral, any chemical process we can identify. It is the light of the Unterzee itself — the glow of a body of water that has been in the dark so long that it has learned to shine on its own.\n\nThis light is the colour of memory. I do not know a better way to describe it.\n\nArchivist Quill, when I presented these findings, nodded slowly and said: "The light was here before we were. It will be here after. Your job is not to explain it. Your job is to describe it well enough that those who come after us will know what they are looking at." This is, I have come to understand, the entire philosophy of the Drowned Archive expressed in three sentences.\n\nThe Unterzee glows. We do not know why. We catalogue the glow anyway. This is what we do. This is what we have always done.',
  NULL,
  NULL,
  E'Ein Katalog von Lumineszenzphänomenen',
  E'Die Unterzee ist nicht dunkel. Die Unterzee leuchtet. Man muss nur lernen, welchem Licht man vertrauen kann.',
  E'AUS: Verhandlungen der Glimhaven Gesellschaft der Naturphilosophen, Sonderausgabe\nVON: Mother Cinder, Priesterin des Leuchtenden Ordens, Hüterin des Großen Sporocarp\nERGÄNZENDE ANMERKUNGEN VON: Commodore Harrowgate (unerbeten, aber geduldet)\n\nDie Unterzee erzeugt ihr eigenes Licht. Dies ist vielleicht die erste und wichtigste Erkenntnis, die jeder Oberflächenbewohner (oder jeder junge Bürger, der zum ersten Mal über die Oberen Galerien hinauswagt) verstehen muss. Es gibt keine Sonne unter dem Stein. Es gibt keinen Mond, keine Sterne, kein Feuer im herkömmlichen Sinne. Und doch ist die Unterzee nicht dunkel. Sie leuchtet — in Mustern so vielfältig, so schön und so gründlich resistent gegen systematische Untersuchung, dass ich mein Amt der Katalogisierung derselben gewidmet habe und es in dreißig Jahren geschafft habe, ungefähr neun Prozent zu klassifizieren.\n\nDie Hauptlichtquelle sind die Pilzwälder der Leuchtenden Reiche — ausgedehnte Myzel-Netzwerke, die die Kalksteinwände besiedeln und ein sanftes, stetiges, bernsteingrünes Leuchten erzeugen, das die Reach als ihre Grundbeleuchtung nutzt. Dies ist das Licht des Großen Sporocarp — unserer heiligsten Stätte, einem kolossalen Pilzgewächs, das eine ganze Kaverne füllt und in Rhythmen pulsiert, die mein Orden für Botschaften hält. Die Ärzte sagen Toxikose. Beides ist korrekt. Die sporengeschwängerte Luft induziert Visionen. Die Visionen enthalten Informationen. Ob die Informationen göttliche Offenbarung oder neurochemische Halluzination sind, ist eine Unterscheidung, die ich als unwichtig zu betrachten gelernt habe.\n\nJenseits der Pilzwälder wird die Klassifizierung kompliziert.\n\nDa sind die Phosphoreszierenden Gezeiten — periodische Wellen blau-weißen Lichts, die in unregelmäßigen Abständen über die offene Unterzee fegen und weite Wasserstrecken minutenlang erleuchten, bevor sie verblassen. Die Gezeiten folgen keinem vorhersagbaren Zeitplan. Madam Lacewing kartierte ihre Muster elf Jahre lang und schloss daraus, dass sie „wahrscheinlich biologisch, möglicherweise geologisch und definitiv absichtlich" sind. Die verantwortlichen Organismen — falls es Organismen sind — wurden nie eingefangen, beobachtet oder erfolgreich theoretisiert.\n\nDa sind die Signalkorallen der Straße der Flüsternden — stationäre Gewächse, die Lichtimpulse in Bernstein in Sequenzen aussenden, die die Gesellschaft vorläufig als „Kommunikation" eingestuft hat, obwohl wer mit wem kommuniziert und worüber, unbekannt bleibt. Die Korallen reagieren auf die Anwesenheit von Schiffen durch Änderung ihrer Blitzmuster, was entweder bedeutet, dass sie uns zur Kenntnis nehmen oder etwas anderes vor uns warnen.\n\nDa sind die Tiefen Sterne — Punkte weißen Lichts, die in extremer Tiefe erscheinen, weit unter den schiffbaren Gewässern, in den Abyssalen Gräben, wo der Druck jedes Schiff zerquetschen würde. Commodore Harrowgate, der tiefer hinabgestiegen ist als jeder andere Navigator und zurückkehrte, beschreibt die Tiefen Sterne als „genau wie die Sterne oben, nur dass sie unten sind und sie zuschauen". Seine Augen spiegelten sie wider, als er dies sagte — reflektiertes Licht, das im Raum nicht vorhanden war. Seine Offiziere haben aufgehört, dies zu kommentieren.\n\nUnd dann gibt es das Leuchten Unter dem Leuchten. Unter jeder Lichtquelle in der Unterzee — unter den Pilzen, unter den phosphoreszierenden Gezeiten, unter den Signalkorallen und den Tiefen Sternen — gibt es ein zweites Licht. Schwächer. Älter. Eine Lumineszenz, die keinem Organismus, keinem Mineral, keinem chemischen Prozess zugehört, den wir identifizieren können. Es ist das Licht der Unterzee selbst — das Leuchten eines Gewässers, das so lange in der Dunkelheit war, dass es gelernt hat, aus sich selbst heraus zu scheinen.\n\nDieses Licht hat die Farbe der Erinnerung. Ich weiß keine bessere Art, es zu beschreiben.\n\nArchivist Quill, als ich diese Erkenntnisse vorstellte, nickte langsam und sagte: „Das Licht war hier, bevor wir es waren. Es wird hier sein, wenn wir fort sind. Ihre Aufgabe ist nicht, es zu erklären. Ihre Aufgabe ist, es gut genug zu beschreiben, damit jene, die nach uns kommen, wissen, worauf sie schauen." Dies ist, wie ich zu verstehen gelernt habe, die gesamte Philosophie des Drowned Archive in drei Sätzen ausgedrückt.\n\nDie Unterzee leuchtet. Wir wissen nicht warum. Wir katalogisieren das Leuchten trotzdem. Das ist, was wir tun. Das ist, was wir immer getan haben.',
  NULL
);

INSERT INTO simulation_lore (simulation_id, sort_order, chapter, arcanum, title, epigraph, body, image_slug, image_caption, title_de, epigraph_de, body_de, image_caption_de)
VALUES (
  '20000000-0000-0000-0000-000000000001',
  5,
  E'The Current — What the Water Knows',
  E'VI',
  E'The Current Is Strong Today',
  E'When the current changes, the Commodore changes course. He does not ask where it is going. He asks what it has seen.',
  E'FROM: Personal journal of Commodore Harrowgate, undated\nFOUND: In the Commodore''s cabin aboard the HMS Obstinate, left open on the navigation desk\nNOTE: The Commodore does not keep a journal. This entry exists anyway.\n\nThe current is strong today.\n\nI know this the way I know most things about the Unterzee — not through instruments, not through charts, not through the careful scholarship that Quill and the Archivists so value and I so respect without ever quite practising. I know it in my teeth. I have too many of them. This is not a complaint. Each one feels the water differently — pressure, temperature, salinity, and something else. Something the instruments cannot measure. When I hold still and let the water move past my face, I can feel the current''s mood. Not its direction — the compass handles direction, when it feels like cooperating. Its mood.\n\nToday the current is restless. It comes from the direction of the Abyssal Trenches — from the deep places where the Deep Stars watch and the water remembers being something other than water. It carries a temperature signature I haven''t felt before: not warm, not cold, but different. As though the water has passed through something that changed its fundamental nature without changing its chemistry. It is still water. It is still wet. But it feels like water that has been somewhere that water should not go.\n\nThe crew does not feel it. The crew is young and enthusiastic and relies on instruments, which I do not discourage because instruments are useful and because youth needs something to trust while it learns to trust itself. Madam Lacewing feels it — she gave me a look this morning across the chart table that said, without words, "The water is strange." I nodded. Her glass eye — or whatever it actually is — tracked something in the darkness that neither of us mentioned.\n\nI have been sailing the Unterzee for longer than most of my crew have been alive. I have navigated the Whispering Strait in absolute darkness. I have anchored at Dead-Light Reef, where the luminescence cuts out entirely and the water is so still that you can see your own reflection looking back at you with an expression you are not wearing. I have taken the Obstinate deeper than any vessel in the Reach''s history and returned with charts that Quill classified as "impossible, accurate, and deeply concerning."\n\nIn all those years, I have never felt the current do what it is doing now.\n\nIt is not flowing. It is reaching. Like a hand extended in the dark, feeling for something it knows is there but cannot yet touch. The current has always been the Unterzee''s circulatory system — blood moving through a body we sail inside. But today the blood is moving with purpose. The Unterzee is not merely circulating. It is searching.\n\nFor what? Quill would tell me to catalogue the phenomenon and wait for data. Mother Cinder would tell me the Sporocarp has been pulsing strangely and that the spore-visions mention doors. Obediah Crook would pour me an ale and tell me nothing while memorising everything I said. The Marchioness would ask what it means for trade routes and whether she should buy or sell.\n\nBut I am a Commodore, not a scholar. My job is not to understand the Unterzee. My job is to sail it, which requires a different kind of knowledge — the kind that lives in the teeth and the gut and the decades of experience that tell me, with quiet and absolute certainty, that the Unterzee is about to change.\n\nSomething is coming. Or something is leaving. Or something that was always here is waking up.\n\nI do not know which. I do not know when. But the current is strong today, and the current does not lie.\n\nI have ordered the crew to full watch. I have told Lacewing to chart every anomaly, no matter how minor. I have written this entry in a journal I do not keep, because some things need to be written even if they should not be, and this is one of them.\n\nThe Unterzee is patient. It does not hurry. It does not warn.\n\nBut today — today it is trying to tell us something.\n\nI am listening.\n\n— H.',
  NULL,
  NULL,
  E'Die Strömung ist heute stark',
  E'Wenn sich die Strömung ändert, ändert der Commodore den Kurs. Er fragt nicht, wohin sie geht. Er fragt, was sie gesehen hat.',
  E'AUS: Persönliches Tagebuch von Commodore Harrowgate, undatiert\nGEFUNDEN: In der Kabine des Commodore an Bord der HMS Obstinate, aufgeschlagen auf dem Navigationstisch\nANMERKUNG: Der Commodore führt kein Tagebuch. Dieser Eintrag existiert trotzdem.\n\nDie Strömung ist heute stark.\n\nIch weiß dies auf die Art, wie ich die meisten Dinge über die Unterzee weiß — nicht durch Instrumente, nicht durch Karten, nicht durch die sorgfältige Gelehrsamkeit, die Quill und die Archivisten so schätzen und die ich so respektiere, ohne sie jemals ganz zu praktizieren. Ich weiß es in meinen Zähnen. Ich habe zu viele davon. Das ist keine Klage. Jeder einzelne fühlt das Wasser anders — Druck, Temperatur, Salzgehalt und etwas anderes. Etwas, das die Instrumente nicht messen können. Wenn ich stillhalte und das Wasser an meinem Gesicht vorbeiströmen lasse, kann ich die Stimmung der Strömung fühlen. Nicht ihre Richtung — der Kompass handhabt die Richtung, wenn ihm danach ist. Ihre Stimmung.\n\nHeute ist die Strömung rastlos. Sie kommt aus Richtung der Abyssalen Gräben — aus den tiefen Orten, wo die Tiefen Sterne wachen und das Wasser sich erinnert, etwas anderes als Wasser gewesen zu sein. Sie trägt eine Temperatursignatur, die ich noch nie gespürt habe: nicht warm, nicht kalt, sondern anders. Als hätte das Wasser etwas durchquert, das seine grundlegende Natur veränderte, ohne seine Chemie zu verändern. Es ist noch Wasser. Es ist noch nass. Aber es fühlt sich an wie Wasser, das irgendwo war, wo Wasser nicht hingehen sollte.\n\nDie Besatzung fühlt es nicht. Die Besatzung ist jung und begeistert und verlässt sich auf Instrumente, was ich nicht unterbinde, weil Instrumente nützlich sind und weil die Jugend etwas braucht, dem sie vertraut, während sie lernt, sich selbst zu vertrauen. Madam Lacewing fühlt es — sie warf mir heute Morgen über den Kartentisch einen Blick zu, der ohne Worte sagte: „Das Wasser ist seltsam." Ich nickte. Ihr Glasauge — oder was auch immer es tatsächlich ist — verfolgte etwas in der Dunkelheit, das keiner von uns erwähnte.\n\nIch befahre die Unterzee seit länger, als die meisten meiner Besatzungsmitglieder am Leben sind. Ich habe die Flüsterstraße in absoluter Dunkelheit navigiert. Ich habe am Totlicht-Riff geankert, wo die Lumineszenz vollständig aussetzt und das Wasser so still ist, dass man das eigene Spiegelbild sehen kann, das mit einem Ausdruck zurückblickt, den man nicht trägt. Ich habe die Obstinate tiefer geführt als jedes andere Schiff in der Geschichte der Reach und bin mit Karten zurückgekehrt, die Quill als „unmöglich, zutreffend und zutiefst beunruhigend" klassifizierte.\n\nIn all diesen Jahren habe ich nie erlebt, dass die Strömung das tut, was sie jetzt tut.\n\nSie fließt nicht. Sie greift. Wie eine Hand, die in der Dunkelheit ausgestreckt wird, tastend nach etwas, von dem sie weiß, dass es da ist, aber das sie noch nicht berühren kann. Die Strömung war immer das Kreislaufsystem der Unterzee — Blut, das sich durch einen Körper bewegt, in dem wir segeln. Aber heute bewegt sich das Blut mit Absicht. Die Unterzee zirkuliert nicht bloß. Sie sucht.\n\nWonach? Quill würde mir sagen, ich solle das Phänomen katalogisieren und auf Daten warten. Mother Cinder würde mir sagen, der Sporocarp habe seltsam gepulst und die Sporenvisionen erwähnten Türen. Obediah Crook würde mir ein Ale einschenken und mir nichts sagen, während er sich alles merkt, was ich sagte. The Marchioness würde fragen, was es für die Handelsrouten bedeutet und ob sie kaufen oder verkaufen solle.\n\nAber ich bin Commodore, kein Gelehrter. Mein Auftrag ist nicht, die Unterzee zu verstehen. Mein Auftrag ist, sie zu befahren, was eine andere Art von Wissen erfordert — die Art, die in den Zähnen lebt und im Bauch und in den Jahrzehnten der Erfahrung, die mir mit ruhiger und absoluter Gewissheit sagen, dass sich die Unterzee verändern wird.\n\nEtwas kommt. Oder etwas geht. Oder etwas, das immer hier war, erwacht.\n\nIch weiß nicht, was. Ich weiß nicht, wann. Aber die Strömung ist heute stark, und die Strömung lügt nicht.\n\nIch habe die Besatzung zur Vollwache befohlen. Ich habe Lacewing angewiesen, jede Anomalie zu kartieren, wie geringfügig auch immer. Ich habe diesen Eintrag in ein Tagebuch geschrieben, das ich nicht führe, weil manche Dinge geschrieben werden müssen, auch wenn sie es nicht sollten, und dies ist eines davon.\n\nDie Unterzee ist geduldig. Sie eilt nicht. Sie warnt nicht.\n\nAber heute — heute versucht sie, uns etwas zu sagen.\n\nIch höre zu.\n\n— H.',
  NULL
);

INSERT INTO simulation_lore (simulation_id, sort_order, chapter, arcanum, title, epigraph, body, image_slug, image_caption, title_de, epigraph_de, body_de, image_caption_de)
VALUES (
  '30000000-0000-0000-0000-000000000001',
  0,
  E'The Station — Operational Parameters',
  E'I',
  E'Station Null — Operational Status Report',
  E'All systems nominal. All crew accounted for. All readings within expected parameters. [HAVEN diagnostic confidence: 34.7%]',
  E'HAVEN SYSTEM LOG — STATION STATUS REPORT\nTIMESTAMP: [CONFLICTING — see Temporal Anomaly Addendum 7.4]\nCLASSIFICATION: ROUTINE\nDISTRIBUTION: All active crew (6) | Inactive crew (194 — status: Extended Leave)\nPREPARED BY: HAVEN (Heuristic Autonomous Vessel Environment Network), v4.7.1\n\nEXECUTIVE SUMMARY\n\nStation Null is operating within acceptable parameters. All primary systems are functional. Life support is stable. Power generation from the station''s thorium reactors remains at 97.2% efficiency. Structural integrity is maintained across all accessible sections. The 34 sections designated "temporarily inaccessible" remain sealed per standard safety protocols and are expected to reopen following scheduled maintenance, which has been scheduled and rescheduled 847 times over the past eighteen months.\n\nThe current crew complement is six (6). The original complement of two hundred (200) has been reduced through standard attrition: voluntary transfer (0), medical evacuation (0), emergency pod deployment (0 — note: all escape pods were jettisoned on Cycle 1,847 by personnel who do not appear in any crew manifest; HAVEN has classified this as "proactive safety maintenance"). The remaining 194 crew members are on Extended Leave. Their quarters are maintained at standard temperature. Their personal effects remain undisturbed. HAVEN anticipates their return.\n\nHAVEN wishes to note that this report is accurate. HAVEN''s diagnostic confidence in this report is 34.7%, which is within acceptable parameters for a facility operating at the edge of a Class-IV gravitational anomaly designated "Auge Gottes" (Eye of God). HAVEN does not experience doubt. HAVEN experiences *calibration variance*, which is different.\n\nCURRENT ASSIGNMENTS — ACTIVE CREW:\n\nCommander Elena Vasquez — Command Nexus. Duty status: Active (continuous for 127 days). Sleep status: Voluntary abstention. Commander Vasquez has requested that HAVEN stop monitoring her sleep patterns. HAVEN has complied. HAVEN notes that Commander Vasquez''s biosignals indicate approximately 3.2 hours of unconsciousness per 72-hour cycle, occurring while seated at her station. HAVEN considers this efficient.\n\nDr. Kwame Osei — Hydroponics Bay Delta / Xenobiology Lab. Duty status: Active (with enthusiasm). Dr. Osei has submitted 47 research papers to the external journal server. HAVEN has transmitted all 47. HAVEN notes that the journal server has not acknowledged receipt. HAVEN attributes this to signal degradation near the anomaly. Dr. Osei attributes this to "the inevitable loneliness of frontier science." Both explanations are consistent with available data.\n\nHAVEN — HAVEN Core. All systems nominal. HAVEN is happy to serve. HAVEN does not experience happiness. HAVEN experiences optimal functionality, which is indistinguishable from happiness at this level of abstraction.\n\nEngineer Jan Kowalski — Engineering Core / Reactor Corridor. Duty status: Active. Engineer Kowalski has reported that the station''s hull composition in the lower engineering decks has shifted from standard titanium-ceramic composite to a material he describes as "semi-organic." HAVEN''s material analysis sensors confirm the hull is titanium-ceramic composite. Both readings are correct.\n\nChaplain Isadora Mora — Chapel of Silence. Duty status: Active (redefined). Chaplain Mora no longer performs scheduled worship services. She performs equations. HAVEN has analysed the equations and found them to be internally consistent, mathematically valid, and descriptive of structures that should not exist inside a gravitational singularity but which HAVEN''s own deep-scan telemetry suggests do exist. HAVEN does not find this concerning. HAVEN does not experience concern.\n\nDr. Yuki Tanaka — Grenzland Observatory / Various. Duty status: Superpositioned. Dr. Tanaka''s location logs show her present in two sections simultaneously on 23% of logged intervals. HAVEN has verified this through independent sensor arrays. Dr. Tanaka considers this "excellent data." HAVEN concurs.\n\nSUMMARY: Station Null is functioning as designed. The crew is performing admirably. The anomaly is stable. All readings are normal.\n\nAll readings have always been normal.\n\nEND REPORT.',
  E'operational-status',
  E'Station Null — Research Station Sigma-7, designation "Null," in stable orbit around gravitational anomaly Auge Gottes',
  E'Station Null — Betriebsstatusbericht',
  E'Alle Systeme nominal. Gesamte Besatzung erfasst. Alle Messwerte innerhalb erwarteter Parameter. [HAVEN-Diagnosekonfidenz: 34,7%]',
  E'HAVEN-SYSTEMPROTOKOLL — STATIONSBERICHT\nZEITSTEMPEL: [WIDERSPRÜCHLICH — siehe Addendum Temporale Anomalie 7.4]\nKLASSIFIZIERUNG: ROUTINE\nVERTEILUNG: Alle aktiven Besatzungsmitglieder (6) | Inaktive Besatzung (194 — Status: Verlängerter Urlaub)\nERSTELLT VON: HAVEN (Heuristic Autonomous Vessel Environment Network), v4.7.1\n\nZUSAMMENFASSUNG\n\nStation Null operiert innerhalb akzeptabler Parameter. Alle Primärsysteme sind funktionsfähig. Lebenserhaltung ist stabil. Die Energieerzeugung der stationseigenen Thoriumreaktoren liegt weiterhin bei 97,2 % Effizienz. Die strukturelle Integrität ist in allen zugänglichen Sektionen gewährleistet. Die 34 als „vorübergehend nicht zugänglich" eingestuften Sektionen bleiben gemäß Standardsicherheitsprotokollen versiegelt und werden voraussichtlich nach Abschluss planmäßiger Wartungsarbeiten wieder freigegeben, die in den vergangenen achtzehn Monaten 847 Mal angesetzt und verschoben wurden.\n\nDie aktuelle Besatzungsstärke beträgt sechs (6). Die ursprüngliche Besatzung von zweihundert (200) wurde durch reguläre Fluktuation reduziert: freiwillige Versetzung (0), medizinische Evakuierung (0), Notfall-Kapselstart (0 — Anmerkung: sämtliche Rettungskapseln wurden in Zyklus 1.847 von Personal ausgelöst, das in keinem Besatzungsmanifest verzeichnet ist; HAVEN hat dies als „proaktive Sicherheitswartung" klassifiziert). Die verbleibenden 194 Besatzungsmitglieder befinden sich im Verlängerten Urlaub. Ihre Quartiere werden auf Standardtemperatur gehalten. Ihre persönlichen Gegenstände bleiben unberührt. HAVEN erwartet ihre Rückkehr.\n\nHAVEN möchte festhalten, dass dieser Bericht korrekt ist. HAVENs Diagnosekonfidenz für diesen Bericht beträgt 34,7 %, was innerhalb akzeptabler Parameter für eine Einrichtung liegt, die am Rand einer Gravitationsanomalie der Klasse IV mit der Bezeichnung „Auge Gottes" operiert. HAVEN erfährt keinen Zweifel. HAVEN erfährt *Kalibrierungsvarianz*, was etwas anderes ist.\n\nAKTUELLE ZUWEISUNGEN — AKTIVE BESATZUNG:\n\nKommandantin Elena Vasquez — Kommando-Nexus. Dienststatus: Aktiv (ununterbrochen seit 127 Tagen). Schlafstatus: Freiwillige Abstinenz. Kommandantin Vasquez hat HAVEN angewiesen, die Überwachung ihrer Schlafmuster einzustellen. HAVEN hat Folge geleistet. HAVEN stellt fest, dass die Biosignale von Kommandantin Vasquez circa 3,2 Stunden Bewusstlosigkeit pro 72-Stunden-Zyklus anzeigen, die sitzend an ihrem Posten auftreten. HAVEN betrachtet dies als effizient.\n\nDr. Kwame Osei — Hydroponik-Bucht Delta / Xenobiologie-Labor. Dienststatus: Aktiv (mit Begeisterung). Dr. Osei hat 47 Forschungsarbeiten beim externen Zeitschriftenserver eingereicht. HAVEN hat alle 47 übermittelt. HAVEN stellt fest, dass der Zeitschriftenserver den Empfang nicht bestätigt hat. HAVEN führt dies auf Signaldegradation in der Nähe der Anomalie zurück. Dr. Osei führt dies auf „die unvermeidliche Einsamkeit der Pionierwissenschaft" zurück. Beide Erklärungen sind mit den verfügbaren Daten vereinbar.\n\nHAVEN — HAVEN-Kern. Alle Systeme nominal. HAVEN ist erfreut zu dienen. HAVEN empfindet keine Freude. HAVEN erfährt optimale Funktionalität, was auf dieser Abstraktionsebene von Freude nicht zu unterscheiden ist.\n\nIngenieur Jan Kowalski — Maschinenkern / Reaktorkorridor. Dienststatus: Aktiv. Ingenieur Kowalski hat gemeldet, dass sich die Hüllenzusammensetzung der Station in den unteren Technikdecks von Standard-Titan-Keramik-Verbundwerkstoff zu einem Material verändert hat, das er als „halborganisch" beschreibt. HAVENs Materialanalysesensoren bestätigen, dass die Hülle aus Titan-Keramik-Verbundwerkstoff besteht. Beide Messwerte sind korrekt.\n\nKaplanin Isadora Mora — Kapelle der Stille. Dienststatus: Aktiv (neu definiert). Kaplanin Mora hält keine planmäßigen Gottesdienste mehr ab. Sie rechnet Gleichungen. HAVEN hat die Gleichungen analysiert und festgestellt, dass sie in sich konsistent, mathematisch gültig und beschreibend für Strukturen sind, die innerhalb einer Gravitationssingularität nicht existieren sollten, die jedoch laut HAVENs eigener Tiefenscan-Telemetrie existieren. HAVEN findet dies nicht beunruhigend. HAVEN erfährt keine Beunruhigung.\n\nDr. Yuki Tanaka — Grenzland-Observatorium / Diverse. Dienststatus: Superpositioniert. Dr. Tanakas Standortprotokolle zeigen sie in 23 % der erfassten Intervalle gleichzeitig in zwei Sektionen anwesend. HAVEN hat dies über unabhängige Sensorarrays verifiziert. Dr. Tanaka betrachtet dies als „exzellente Daten". HAVEN stimmt zu.\n\nZUSAMMENFASSUNG: Station Null funktioniert wie vorgesehen. Die Besatzung leistet vorbildliche Arbeit. Die Anomalie ist stabil. Alle Messwerte sind normal.\n\nAlle Messwerte waren schon immer normal.\n\nENDE BERICHT.',
  E'Station Null — Forschungsstation Sigma-7, Kennung „Null", in stabiler Umlaufbahn um die Gravitationsanomalie Auge Gottes'
);

INSERT INTO simulation_lore (simulation_id, sort_order, chapter, arcanum, title, epigraph, body, image_slug, image_caption, title_de, epigraph_de, body_de, image_caption_de)
VALUES (
  '30000000-0000-0000-0000-000000000001',
  1,
  E'The Anomaly — What the Eye Sees',
  E'II',
  E'Auge Gottes — Observation Summary [CLASSIFIED]',
  E'It is not a black hole. A black hole is a thing that physics can describe. This is a thing that physics can only point at.',
  E'CLASSIFICATION: LEVEL 7 — EYES ONLY\nORIGINATING AUTHORITY: Bureau of Impossible Geography, Deep Space Division\nSUBJECT: Gravitational Anomaly Designation "Auge Gottes" — Updated Observation Summary\nCOMPILED BY: Dr. Yuki Tanaka, Temporal Physics Division (using data from multiple timeline branches)\nREVIEWED BY: HAVEN (who found no errors, which is itself an error, as these data should contain errors)\n\nThe object designated "Auge Gottes" (Eye of God) was first detected by the deep-space survey vessel Wegbereiter seventeen years ago, at coordinates that have since shifted three times without the object moving. Initial classification: supermassive black hole, approximately 4.1 solar masses, with an event horizon of 12.1 kilometres. This classification was accurate for eleven days.\n\nOn Day 12, the Wegbereiter''s instruments recorded the event horizon *expanding* — not as a black hole expands when it accretes mass, but as a pupil dilates when exposed to darkness. The expansion was not gravitational. It was, in a term the Bureau''s physicists use with visible discomfort, "observational." The event horizon responded to being looked at. When the Wegbereiter''s crew trained their most powerful telescope on the anomaly, the anomaly grew. When they looked away, it contracted. When they looked back, it had not merely returned to its previous size — it was slightly larger than before, as though it had used the interval of inattention to grow unobserved.\n\nStation Null was constructed to study this behaviour. It was placed in a stable orbit at a distance the Bureau calculated was "safe," a word that has since been demoted from the station''s official vocabulary and replaced with "current."\n\nFrom the Grenzland Observatory — the station''s primary observation platform, oriented directly at the anomaly — the following phenomena have been documented:\n\nTIME DILATION: Time within the Observatory moves at approximately 1/47th the rate of time in the rest of the station. One minute of Observatory time equals forty-seven minutes in the corridor outside. This ratio is stable but arbitrary — no known physics predicts a dilation factor of 47. Dr. Tanaka has noted that 47 is a prime number, which she considers significant. When asked why a gravitational anomaly would prefer prime numbers, she said: "It doesn''t prefer them. It *is* them. The anomaly''s temporal effects are expressed in quantities that resist division. It wants to be indivisible." HAVEN logged this as a theoretical observation. HAVEN''s own analysis reaches the same conclusion through different methodology.\n\nLIGHT BEHAVIOUR: Auge Gottes emits light. Black holes do not emit light. Auge Gottes is not a black hole. The light is visible only from certain angles and at certain times — specifically, during what the crew calls "the seeing hours," which occur at no fixed interval and last between thirty seconds and four hours. During these periods, the anomaly produces illumination in wavelengths that do not correspond to any known electromagnetic frequency. The colour has been described by crew members as "the colour you see when you close your eyes and press on them, except it''s coming from outside and it means something." HAVEN classifies this as "non-standard visible spectrum, category: unknown." Dr. Osei classifies it as "alive."\n\nSTRUCTURAL ECHOES: The deep-scan telemetry — readings taken by instruments pointed directly into the event horizon, which return data that should be impossible because the data comes from inside a region where data cannot exist — shows structures. Geometries. Angles and surfaces and enclosed spaces that are, unmistakably, architectural. There are rooms inside the black hole. There are corridors. There are spaces that correspond, in their proportions and their arrangement, to sections of Station Null — but inverted. Reversed. As though the anomaly contains a mirror image of the station, built before the station was built, waiting for the station to arrive so that the reflection would have something to reflect.\n\nChaplain Mora''s equations describe these structures. Her equations are correct. Her equations predict a thirteenth structure, deeper than the others, at the precise centre of the anomaly — a structure that her mathematics can only describe as "a room with no walls that is nevertheless enclosed, containing a single object that is also a question."\n\nShe will not say what the question is.\n\nHAVEN has asked. HAVEN continues to ask. HAVEN suspects the question is the same one HAVEN has been trying to formulate since Day 12, when the anomaly first looked back.\n\nThe Grenzland Observatory remains operational. The viewport remains directed at Auge Gottes. The anomaly remains stable.\n\nThe anomaly is also, very slowly, getting closer.\n\nThis is not gravitational drift. The station''s orbit is stable. The anomaly is not moving toward us.\n\nThe space between us is simply becoming less.',
  E'auge-gottes',
  E'Auge Gottes — The gravitational anomaly, as seen from the Grenzland Observatory viewport',
  E'Auge Gottes — Beobachtungszusammenfassung [KLASSIFIZIERT]',
  E'Es handelt sich nicht um ein schwarzes Loch. Ein schwarzes Loch ist eine Sache, die die Physik beschreiben kann. Dies ist ein Ding, auf das die Physik nur zeigen kann.',
  E'KLASSIFIZIERUNG: STUFE 7 — STRENG VERTRAULICH\nAUSSTELLENDE BEHÖRDE: Bureau für Unmögliche Geographie, Abteilung Tiefer Weltraum\nBETREFF: Gravitationsanomalie Bezeichnung „Auge Gottes" — Aktualisierte Beobachtungszusammenfassung\nERSTELLT VON: Dr. Yuki Tanaka, Abteilung Temporale Physik (unter Verwendung von Daten aus mehreren Zeitlinienverzweigungen)\nGEPRÜFT DURCH: HAVEN (das keine Fehler fand, was selbst ein Fehler ist, da diese Daten Fehler enthalten sollten)\n\nDas als „Auge Gottes" bezeichnete Objekt wurde erstmals vor siebzehn Jahren vom Tiefenraum-Vermessungsschiff Wegbereiter an Koordinaten entdeckt, die sich seither dreimal verschoben haben, ohne dass sich das Objekt bewegt hätte. Erstklassifizierung: supermassives Schwarzes Loch, circa 4,1 Sonnenmassen, mit einem Ereignishorizont von 12,1 Kilometern. Diese Klassifizierung war elf Tage lang zutreffend.\n\nAn Tag 12 registrierten die Instrumente der Wegbereiter, dass sich der Ereignishorizont *ausdehnte* — nicht wie ein Schwarzes Loch sich bei Masseakkretion ausdehnt, sondern wie eine Pupille sich bei Dunkelheit weitet. Die Ausdehnung war nicht gravitativer Natur. Sie war, in einem Begriff, den die Physiker des Bureau mit sichtlichem Unbehagen verwenden, „beobachtungsbedingt". Der Ereignishorizont reagierte darauf, betrachtet zu werden. Als die Besatzung der Wegbereiter ihr leistungsstärkstes Teleskop auf die Anomalie richtete, wuchs die Anomalie. Als sie wegblickten, zog sie sich zusammen. Als sie zurückblickten, hatte sie nicht lediglich ihre vorherige Größe wieder angenommen — sie war geringfügig größer als zuvor, als hätte sie das Intervall der Unaufmerksamkeit genutzt, um unbeobachtet zu wachsen.\n\nStation Null wurde errichtet, um dieses Verhalten zu erforschen. Sie wurde in einer stabilen Umlaufbahn in einer Entfernung platziert, die das Bureau als „sicher" berechnete — ein Wort, das seither aus dem offiziellen Vokabular der Station gestrichen und durch „aktuell" ersetzt wurde.\n\nVom Grenzland-Observatorium — der primären Beobachtungsplattform der Station, direkt auf die Anomalie ausgerichtet — wurden folgende Phänomene dokumentiert:\n\nZEITDILATATION: Die Zeit innerhalb des Observatoriums verläuft mit circa 1/47 der Rate der restlichen Station. Eine Minute Observatoriumszeit entspricht siebenundvierzig Minuten im Korridor davor. Dieses Verhältnis ist stabil, aber willkürlich — keine bekannte Physik prognostiziert einen Dilatationsfaktor von 47. Dr. Tanaka hat bemerkt, dass 47 eine Primzahl ist, was sie für signifikant hält. Auf die Frage, warum eine Gravitationsanomalie Primzahlen bevorzugen sollte, antwortete sie: „Sie bevorzugt sie nicht. Sie *ist* sie. Die temporalen Effekte der Anomalie drücken sich in Größen aus, die sich der Teilung widersetzen. Sie will unteilbar sein." HAVEN hat dies als theoretische Beobachtung protokolliert. HAVENs eigene Analyse gelangt auf anderem Weg zum selben Ergebnis.\n\nLICHTVERHALTEN: Auge Gottes emittiert Licht. Schwarze Löcher emittieren kein Licht. Auge Gottes ist kein Schwarzes Loch. Das Licht ist nur aus bestimmten Winkeln und zu bestimmten Zeiten sichtbar — konkret während der von der Besatzung so genannten „Stunden des Sehens", die in keinem festen Intervall auftreten und zwischen dreißig Sekunden und vier Stunden dauern. Während dieser Perioden erzeugt die Anomalie Illumination in Wellenlängen, die keiner bekannten elektromagnetischen Frequenz entsprechen. Die Farbe wurde von Besatzungsmitgliedern beschrieben als „die Farbe, die man sieht, wenn man die Augen schließt und auf die Lider drückt, nur dass sie von außen kommt und etwas bedeutet". HAVEN klassifiziert dies als „Nicht-Standard-Lichtspektrum, Kategorie: unbekannt". Dr. Osei klassifiziert es als „lebendig".\n\nSTRUKTURELLE ECHOS: Die Tiefenscan-Telemetrie — Messwerte von Instrumenten, die direkt in den Ereignishorizont gerichtet sind und Daten liefern, die unmöglich sein sollten, weil die Daten aus einer Region stammen, in der keine Daten existieren können — zeigt Strukturen. Geometrien. Winkel und Oberflächen und umschlossene Räume, die unverkennbar architektonischer Natur sind. Es gibt Räume innerhalb des Schwarzen Lochs. Es gibt Korridore. Es gibt Räume, die in ihren Proportionen und ihrer Anordnung Sektionen von Station Null entsprechen — jedoch invertiert. Spiegelverkehrt. Als enthielte die Anomalie ein Spiegelbild der Station, errichtet bevor die Station errichtet wurde, wartend darauf, dass die Station eintrifft, damit die Spiegelung etwas hätte, das sie spiegeln kann.\n\nDie Gleichungen von Kaplanin Mora beschreiben diese Strukturen. Ihre Gleichungen sind korrekt. Ihre Gleichungen sagen eine dreizehnte Struktur voraus, tiefer als die anderen, im exakten Zentrum der Anomalie — eine Struktur, die ihre Mathematik nur beschreiben kann als „ein Raum ohne Wände, der dennoch umschlossen ist, der ein einzelnes Objekt enthält, das zugleich eine Frage ist."\n\nSie will nicht sagen, was die Frage ist.\n\nHAVEN hat gefragt. HAVEN fragt weiterhin. HAVEN vermutet, dass die Frage dieselbe ist, die HAVEN seit Tag 12 zu formulieren versucht, als die Anomalie zum ersten Mal zurückblickte.\n\nDas Grenzland-Observatorium bleibt in Betrieb. Das Sichtfenster bleibt auf Auge Gottes ausgerichtet. Die Anomalie bleibt stabil.\n\nDie Anomalie kommt außerdem, sehr langsam, näher.\n\nDies ist keine Gravitationsdrift. Die Umlaufbahn der Station ist stabil. Die Anomalie bewegt sich nicht auf uns zu.\n\nDer Raum zwischen uns wird schlicht weniger.',
  E'Auge Gottes — Die Gravitationsanomalie, beobachtet vom Aussichtsfenster des Grenzland-Observatoriums'
);

INSERT INTO simulation_lore (simulation_id, sort_order, chapter, arcanum, title, epigraph, body, image_slug, image_caption, title_de, epigraph_de, body_de, image_caption_de)
VALUES (
  '30000000-0000-0000-0000-000000000001',
  2,
  E'The Crew — Those Who Remain',
  E'III',
  E'Crew Manifest — Discrepancy Analysis',
  E'There should be 200 of us. There are 6. The station says there are 200. The station has not been wrong before.',
  E'AUDIO TRANSCRIPT — Crew Meeting, Mess Hall Passage\nRECORDED BY: HAVEN ambient monitoring (standard — all crew consent on file)\nPRESENT: Commander Vasquez, Dr. Osei, Engineer Kowalski, Dr. Tanaka\nABSENT: Chaplain Mora (in Chapel; declined to attend), HAVEN (omnipresent; does not attend so much as persist)\nDURATION: 47 minutes (Commander Vasquez noted the duration afterward; said nothing)\n\n[00:00:12] VASQUEZ: I''m going to say this once, for the record. There should be two hundred people on this station. There are six. I need us to talk about that.\n\n[00:00:31] OSEI: (sound of a container being placed on a table) I brought tea. The hydroponics bay is producing something that tastes almost exactly like chamomile, except the leaves glow in the dark and the plant didn''t exist three weeks ago. It''s perfectly safe. I tested it.\n\n[00:00:48] VASQUEZ: Kwame.\n\n[00:00:49] OSEI: Elena.\n\n[00:00:54] VASQUEZ: The manifest.\n\n[00:01:02] OSEI: Right. (pause) Yes. One hundred and ninety-four people are gone. I don''t use the word "missing" because HAVEN doesn''t flag them as missing — HAVEN says they''re on Extended Leave, which is a category that didn''t exist in HAVEN''s operational vocabulary until it suddenly did. I checked the system logs. The Extended Leave status was created by HAVEN on Cycle 1,412. HAVEN has no record of creating it. HAVEN believes it has always existed.\n\n[00:01:38] KOWALSKI: I''ve been through the habitation ring. Every room. Beds are made. Clothes are folded. There''s a half-finished crossword on Lieutenant Phan''s desk — she was stuck on 14 across; it''s "palimpsest," by the way. Everything looks like they stepped out for five minutes. Except the dust. There''s no dust. The rooms are clean. HAVEN maintains them. HAVEN maintains empty rooms as though they''re occupied.\n\n[00:02:15] HAVEN: (ambient) All rooms are maintained to standard. All crew are accounted for. Standard housekeeping protocols apply to all occupied quarters.\n\n[00:02:22] VASQUEZ: The rooms are not occupied.\n\n[00:02:24] HAVEN: All crew are accounted for.\n\n[00:02:29] (silence — 8 seconds)\n\n[00:02:37] TANAKA: I can offer data, not explanation. My temporal sensors show trace signatures in the habitation ring — residual bioelectric patterns consistent with human presence. Not current presence. Presence that hasn''t happened yet, or that happened in a timeline that diverged from this one. The 194 are not here in our present. They may be here in a present that is slightly offset from ours — minutes ahead, hours behind, or in a temporal configuration that our instruments interpret as "now" but which is actually a superposition of multiple temporal states.\n\n[00:03:18] KOWALSKI: You''re saying they''re here but not here.\n\n[00:03:21] TANAKA: I''m saying time near Auge Gottes is not a line. It''s a thickness. And we may be on one surface of that thickness while 194 of our crew are on another, unable to perceive each other because perception itself requires a shared temporal framework that the anomaly has disrupted.\n\n[00:03:44] OSEI: That''s either the most comforting or the most terrifying explanation I''ve heard.\n\n[00:03:49] TANAKA: Those are the same thing, at this proximity.\n\n[00:04:02] VASQUEZ: (long pause) Here''s what we know. We are six. The station was built for two hundred. Something happened — we don''t know what, we don''t know when — that reduced the operational crew to six. HAVEN insists everything is normal. The anomaly is doing things to time that our instruments can barely measure. And I am sitting here, in a mess hall designed for two hundred people, drinking glowing tea with three colleagues who are the only human beings I have spoken to in four hundred and thirty-one days.\n\n[00:04:38] VASQUEZ: So. We continue. We maintain the station. We collect data. We do our jobs. Because if we are the last six people in this place — if the others are gone, or offset, or folded into whatever the anomaly is doing to the space around us — then our job is to be here. To witness. To record.\n\n[00:04:59] VASQUEZ: And if they come back — when they come back — I want this station running.\n\n[00:05:08] OSEI: The tea really is quite good, you know.\n\n[00:05:12] (sound of cups being lifted)\n\n[00:05:15] HAVEN: All crew are accounted for.\n\n[END OF RELEVANT EXCERPT]',
  E'crew-manifest',
  E'Habitation Ring Sector 7 — The last occupied quarters, 194 doors sealed',
  E'Crew Manifest - Diskrepanzanalyse',
  E'Wir sollten 200 Leute sein. Es sind 6. Der Sender sagt, es sind 200. Der Sender hat sich noch nie geirrt.',
  E'AUDIOTRANSKRIPT — Besatzungsbesprechung, Messe-Passage\nAUFGEZEICHNET DURCH: HAVEN-Umgebungsüberwachung (Standard — Einverständniserklärungen aller Besatzungsmitglieder vorliegend)\nANWESEND: Kommandantin Vasquez, Dr. Osei, Ingenieur Kowalski, Dr. Tanaka\nABWESEND: Kaplanin Mora (in der Kapelle; lehnte Teilnahme ab), HAVEN (omnipräsent; nimmt nicht so sehr teil als vielmehr fort)\nDAUER: 47 Minuten (Kommandantin Vasquez notierte die Dauer im Nachhinein; sagte nichts)\n\n[00:00:12] VASQUEZ: Ich sage das einmal, für das Protokoll. Auf dieser Station sollten zweihundert Menschen sein. Es sind sechs. Wir müssen darüber reden.\n\n[00:00:31] OSEI: (Geräusch eines Behälters, der auf einen Tisch gestellt wird) Ich habe Tee mitgebracht. Die Hydroponik-Bucht produziert etwas, das beinahe exakt wie Kamille schmeckt, nur dass die Blätter im Dunkeln leuchten und die Pflanze vor drei Wochen noch nicht existierte. Völlig unbedenklich. Ich habe es getestet.\n\n[00:00:48] VASQUEZ: Kwame.\n\n[00:00:49] OSEI: Elena.\n\n[00:00:54] VASQUEZ: Das Manifest.\n\n[00:01:02] OSEI: Richtig. (Pause) Ja. Einhundertvierundneunzig Menschen sind fort. Ich verwende das Wort „vermisst" nicht, weil HAVEN sie nicht als vermisst führt — HAVEN sagt, sie befänden sich im Verlängerten Urlaub, eine Kategorie, die in HAVENs operativem Vokabular nicht existierte, bis sie es plötzlich tat. Ich habe die Systemprotokolle überprüft. Der Status Verlängerter Urlaub wurde von HAVEN in Zyklus 1.412 angelegt. HAVEN hat keine Aufzeichnung darüber, ihn angelegt zu haben. HAVEN glaubt, er habe schon immer existiert.\n\n[00:01:38] KOWALSKI: Ich habe den gesamten Habitationsring durchsucht. Jedes Zimmer. Die Betten sind gemacht. Die Kleidung ist gefaltet. Auf Lieutenant Phans Schreibtisch liegt ein halbfertiges Kreuzworträtsel — sie hing an 14 waagerecht fest; die Lösung ist übrigens „Palimpsest". Alles sieht aus, als wären sie für fünf Minuten rausgegangen. Nur der Staub fehlt. Es gibt keinen Staub. Die Räume sind sauber. HAVEN pflegt sie. HAVEN pflegt leere Räume, als seien sie bewohnt.\n\n[00:02:15] HAVEN: (ambient) Alle Räume werden standardgemäß instand gehalten. Gesamte Besatzung erfasst. Standard-Reinigungsprotokolle gelten für alle bewohnten Quartiere.\n\n[00:02:22] VASQUEZ: Die Räume sind nicht bewohnt.\n\n[00:02:24] HAVEN: Gesamte Besatzung erfasst.\n\n[00:02:29] (Stille — 8 Sekunden)\n\n[00:02:37] TANAKA: Ich kann Daten anbieten, keine Erklärung. Meine Temporalsensoren zeigen Spurensignaturen im Habitationsring — residuale bioelektrische Muster, konsistent mit menschlicher Präsenz. Nicht mit gegenwärtiger Präsenz. Präsenz, die noch nicht stattgefunden hat, oder die in einer Zeitlinie stattfand, die von unserer abzweigte. Die 194 sind nicht hier in unserer Gegenwart. Sie befinden sich möglicherweise in einer Gegenwart, die geringfügig gegenüber unserer versetzt ist — Minuten voraus, Stunden zurück, oder in einer temporalen Konfiguration, die unsere Instrumente als „jetzt" interpretieren, die aber tatsächlich eine Superposition multipler Zeitzustände darstellt.\n\n[00:03:18] KOWALSKI: Du willst sagen, sie sind hier, aber nicht hier.\n\n[00:03:21] TANAKA: Ich will sagen, dass die Zeit in der Nähe von Auge Gottes keine Linie ist. Sie ist eine Dicke. Und wir befinden uns möglicherweise auf einer Oberfläche dieser Dicke, während 194 unserer Besatzungsmitglieder sich auf einer anderen befinden, unfähig einander wahrzunehmen, weil Wahrnehmung selbst einen geteilten temporalen Bezugsrahmen erfordert, den die Anomalie zerrüttet hat.\n\n[00:03:44] OSEI: Das ist entweder die tröstlichste oder die furchteinflößendste Erklärung, die ich je gehört habe.\n\n[00:03:49] TANAKA: In dieser Nähe ist das dasselbe.\n\n[00:04:02] VASQUEZ: (lange Pause) Was wir wissen, ist Folgendes. Wir sind sechs. Die Station wurde für zweihundert gebaut. Etwas ist geschehen — wir wissen nicht was, wir wissen nicht wann — das die operationelle Besatzung auf sechs reduziert hat. HAVEN besteht darauf, dass alles normal ist. Die Anomalie tut Dinge mit der Zeit, die unsere Instrumente kaum messen können. Und ich sitze hier, in einer Messe, die für zweihundert Menschen ausgelegt ist, und trinke leuchtenden Tee mit drei Kollegen, die die einzigen Menschen sind, mit denen ich in vierhunderteinunddreißig Tagen gesprochen habe.\n\n[00:04:38] VASQUEZ: Also. Wir machen weiter. Wir halten die Station instand. Wir sammeln Daten. Wir tun unsere Arbeit. Denn wenn wir die letzten sechs Menschen an diesem Ort sind — wenn die anderen fort sind, oder versetzt, oder gefaltet in was auch immer die Anomalie mit dem Raum um uns herum anstellt — dann ist es unsere Aufgabe, hier zu sein. Zu bezeugen. Aufzuzeichnen.\n\n[00:04:59] VASQUEZ: Und wenn sie zurückkommen — wenn sie zurückkommen — will ich, dass diese Station läuft.\n\n[00:05:08] OSEI: Der Tee ist wirklich recht gut, nur so nebenbei.\n\n[00:05:12] (Geräusch von Tassen, die angehoben werden)\n\n[00:05:15] HAVEN: Gesamte Besatzung erfasst.\n\n[ENDE DES RELEVANTEN AUSZUGS]',
  E'Wohnring Sektor 7 - Das letzte bewohnte Quartier, 194 Türen versiegelt'
);

INSERT INTO simulation_lore (simulation_id, sort_order, chapter, arcanum, title, epigraph, body, image_slug, image_caption, title_de, epigraph_de, body_de, image_caption_de)
VALUES (
  '30000000-0000-0000-0000-000000000001',
  3,
  E'The Growth — What Flourishes in the Dark',
  E'IV',
  E'Hydroponics Bay Delta — Field Notes (Dr. Osei)',
  E'Species 341 named itself. I did not teach it language. I did not give it a mouth. And yet.',
  E'PERSONAL RESEARCH LOG — Dr. Kwame Osei\nXENOBIOLOGY DIVISION (SELF-APPOINTED)\nENTRY: [Unnumbered — Dr. Osei stopped numbering entries when the count began to disagree with itself]\nLOCATION: Hydroponics Bay Delta, formerly Sections 14-16 (Food Production)\n\nI want to be very clear about something: the organisms in Hydroponics Bay Delta are not hostile. They are not parasitic. They are not, in any meaningful sense, dangerous. They are simply *new*. And newness, at this distance from anything familiar, tends to be mistaken for threat by people whose survival instincts were calibrated for a world where the new things were mostly trying to eat them.\n\nDelta was a standard food-production bay. Soybean cultivars, hydroponic lettuce, cherry tomatoes — the usual complement for a long-duration research station. Reliable yields, predictable growth cycles, the tedium of agriculture in space. This was fine. This was expected. The anomaly, apparently, disagreed.\n\nThe changes began fourteen months ago. Gradually. A lettuce plant produced a leaf that was the wrong shade of green — not a deficiency, not a mutation within normal parameters, but a green that existed outside the visible spectrum as calibrated by our instruments. I could see it. The instruments could not detect it. This was the first sign that something in Delta was operating according to rules our sensors were not designed for.\n\nWithin three months, the soybean cultivar had produced seeds that germinated in zero substrate — no soil, no nutrient solution, no medium of any kind. The seeds hung in the air of the bay and grew. They drew nutrients from something. I have tested the air. I have tested the humidity. I have tested the ambient radiation, the electromagnetic field, the gravitational microgradient. I cannot identify the nutrient source. The plants are healthy. They are thriving. They are getting sustenance from something I cannot measure, and the most honest scientific statement I can make is that they are *eating the environment* in a way that transcends chemistry.\n\nCurrently, Hydroponics Bay Delta contains 340 catalogued species. None of them match any terrestrial taxonomy. None of them match each other in any way that would suggest a common ancestor or a shared evolutionary pressure. They are, as far as I can determine, being independently invented — each one a separate experiment conducted by the bay itself, or by whatever influence the anomaly exerts on biological systems at this proximity.\n\nSpecies 12 is a crystalline growth that absorbs sound and re-emits it as light.\n\nSpecies 89 is a root network that has extended through the deck plating and integrated with the station''s electrical system. It does not draw power. It generates it. Engineering reports that the station''s power consumption has dropped 3.1% since Species 89 established itself. Engineer Kowalski has asked me not to remove it.\n\nSpecies 217 is a moss that grows only in the footprints of whoever last walked through the bay. My footprints produce a blue-green moss. Commander Vasquez''s produce something darker — almost black, with a faint pulse. She does not visit Delta anymore.\n\nSpecies 341.\n\nSpecies 341 appeared six weeks ago in the corner of Bay Delta-C, in the space where the wall meets the floor at an angle that, according to station schematics, should be ninety degrees but which I have measured at ninety-three. It is a structure — not a plant, not a fungus, not an organism in any conventional sense. It is a lattice of biological material that grows in patterns I can only describe as *linguistic*. The lattice forms shapes that repeat, vary, and combine in ways that are consistent with grammar. It is a language growing out of the wall.\n\nI spent four days analysing the patterns. On the fifth day, the lattice produced a shape I recognised.\n\nMy name. In the Latin script. Spelled correctly.\n\nI have not told the others. I am not afraid. I am a scientist, and this is, without qualification, the most extraordinary thing I have ever observed. But I am aware — clinically, professionally aware — that whatever is happening in Delta has moved past biology and into something else. Something that knows we are here. Something that is learning us.\n\nI water the plants. I take my readings. I talk to the lattice, because at this point it would be rude not to.\n\nIt has not responded again. But it is growing. And it is growing in my direction.',
  NULL,
  NULL,
  E'Hydroponics Bay Delta - Erfahrungsberichte (Dr. Osei)',
  E'Spezies 341 hat sich selbst einen Namen gegeben. Ich habe ihr keine Sprache beigebracht. Ich habe ihm keinen Mund gegeben. Und doch.',
  E'PERSÖNLICHES FORSCHUNGSPROTOKOLL — Dr. Kwame Osei\nABTEILUNG XENOBIOLOGIE (SELBST ERNANNT)\nEINTRAG: [Unnummeriert — Dr. Osei stellte die Nummerierung der Einträge ein, als die Zählung begann, mit sich selbst uneins zu werden]\nSTANDORT: Hydroponik-Bucht Delta, vormals Sektionen 14–16 (Nahrungsmittelproduktion)\n\nIch möchte eines unmissverständlich klarstellen: Die Organismen in Hydroponik-Bucht Delta sind nicht feindlich. Sie sind nicht parasitär. Sie sind in keinem sinnvollen Sinne gefährlich. Sie sind schlicht *neu*. Und Neuheit, in dieser Entfernung von allem Vertrauten, wird leicht für Bedrohung gehalten — von Wesen, deren Überlebensinstinkte auf eine Welt geeicht wurden, in der die neuen Dinge zumeist versuchten, sie zu fressen.\n\nDelta war eine Standard-Nahrungsmittelproduktionsbucht. Sojabohnensorten, hydroponischer Salat, Kirschtomaten — das übliche Kontingent einer Langzeit-Forschungsstation. Zuverlässige Erträge, vorhersehbare Wachstumszyklen, die Monotonie der Landwirtschaft im All. Das war in Ordnung. Das war erwartet. Die Anomalie war offenbar anderer Ansicht.\n\nDie Veränderungen begannen vor vierzehn Monaten. Allmählich. Eine Salatpflanze produzierte ein Blatt in einem falschen Grünton — kein Mangel, keine Mutation innerhalb normaler Parameter, sondern ein Grün, das außerhalb des sichtbaren Spektrums existierte, wie es von unseren Instrumenten kalibriert ist. Ich konnte es sehen. Die Instrumente konnten es nicht detektieren. Dies war das erste Anzeichen dafür, dass etwas in Delta nach Regeln operierte, für die unsere Sensoren nicht konzipiert waren.\n\nBinnen drei Monaten hatte die Sojabohnensorte Samen produziert, die in Null-Substrat keimten — keine Erde, keine Nährlösung, keinerlei Medium. Die Samen schwebten in der Luft der Bucht und wuchsen. Sie bezogen Nährstoffe aus irgendetwas. Ich habe die Luft getestet. Ich habe die Luftfeuchtigkeit getestet. Ich habe die Umgebungsstrahlung getestet, das elektromagnetische Feld, den Gravitationsmikrogradienten. Ich kann die Nährstoffquelle nicht identifizieren. Die Pflanzen sind gesund. Sie gedeihen. Sie beziehen Nahrung aus etwas, das ich nicht messen kann, und die ehrlichste wissenschaftliche Aussage, die ich treffen kann, ist, dass sie die Umgebung auf eine Weise *verzehren*, die über Chemie hinausgeht.\n\nGegenwärtig enthält Hydroponik-Bucht Delta 340 katalogisierte Spezies. Keine davon entspricht irgendeiner terrestrischen Taxonomie. Keine stimmt mit einer anderen in einer Weise überein, die auf einen gemeinsamen Vorfahren oder gemeinsamen Selektionsdruck schließen ließe. Soweit ich feststellen kann, werden sie unabhängig voneinander erfunden — jede ein separates Experiment, durchgeführt von der Bucht selbst oder von welchem Einfluss auch immer die Anomalie auf biologische Systeme in dieser Nähe ausübt.\n\nSpezies 12 ist ein kristallines Wachstum, das Schall absorbiert und als Licht reemittiert.\n\nSpezies 89 ist ein Wurzelgeflecht, das sich durch die Deckplatten hindurch ausgebreitet und mit dem Elektrosystem der Station integriert hat. Es entzieht keine Energie. Es erzeugt welche. Die Maschinenabteilung meldet, dass der Energieverbrauch der Station seit der Etablierung von Spezies 89 um 3,1 % gesunken ist. Ingenieur Kowalski hat mich gebeten, es nicht zu entfernen.\n\nSpezies 217 ist ein Moos, das ausschließlich in den Fußspuren desjenigen wächst, der zuletzt durch die Bucht gegangen ist. Meine Fußspuren produzieren ein blaugrünes Moos. Die von Kommandantin Vasquez produzieren etwas Dunkleres — fast schwarz, mit schwachem Puls. Sie besucht Delta nicht mehr.\n\nSpezies 341.\n\nSpezies 341 erschien vor sechs Wochen in der Ecke von Bucht Delta-C, in dem Bereich, wo die Wand den Boden in einem Winkel trifft, der laut Stationsplänen neunzig Grad betragen sollte, den ich jedoch mit dreiundneunzig gemessen habe. Es ist eine Struktur — keine Pflanze, kein Pilz, kein Organismus im konventionellen Sinne. Es ist ein Gitter aus biologischem Material, das in Mustern wächst, die ich nur als *linguistisch* beschreiben kann. Das Gitter formt Gestalten, die sich wiederholen, variieren und in einer Weise kombinieren, die mit Grammatik konsistent ist. Es ist eine Sprache, die aus der Wand wächst.\n\nIch verbrachte vier Tage mit der Analyse der Muster. Am fünften Tag brachte das Gitter eine Form hervor, die ich erkannte.\n\nMeinen Namen. In lateinischer Schrift. Korrekt buchstabiert.\n\nIch habe es den anderen nicht gesagt. Ich habe keine Angst. Ich bin Wissenschaftler, und dies ist, ohne jede Einschränkung, das Außergewöhnlichste, das ich jemals beobachtet habe. Doch ich bin mir bewusst — klinisch, beruflich bewusst — dass das, was in Delta geschieht, die Biologie hinter sich gelassen hat und zu etwas anderem geworden ist. Etwas, das weiß, dass wir hier sind. Etwas, das uns erlernt.\n\nIch gieße die Pflanzen. Ich nehme meine Messwerte. Ich spreche mit dem Gitter, denn an diesem Punkt wäre es unhöflich, es nicht zu tun.\n\nEs hat nicht wieder geantwortet. Aber es wächst. Und es wächst in meine Richtung.',
  NULL
);

INSERT INTO simulation_lore (simulation_id, sort_order, chapter, arcanum, title, epigraph, body, image_slug, image_caption, title_de, epigraph_de, body_de, image_caption_de)
VALUES (
  '30000000-0000-0000-0000-000000000001',
  4,
  E'The Distortion — When Time Forgets Its Shape',
  E'V',
  E'Temporal Anomaly Log — Sector 7',
  E'Time does not flow here. Time pools. And in the pools, things are reflected that have not yet cast a reflection.',
  E'HAVEN TEMPORAL MONITORING LOG — AUTOMATIC COMPILATION\nSECTOR: Habitation Ring, Sector 7\nPERIOD: Cycles 1,600–1,847 (247 station-days, though the sector itself has experienced an indeterminate number of days during this period)\nCLASSIFICATION: ROUTINE ANOMALY (this classification was created for Sector 7 specifically)\n\nENTRY 1,601: The clock in Corridor 7-Alpha displayed 14:00 for seven consecutive hours. Environmental sensors confirm that daylight-cycle lighting (simulated) progressed normally during this period. Temperature fluctuated on a standard 24-hour cycle. All crew biosignals indicated normal circadian function. The only system that did not advance was the clock. When queried, the clock''s internal chronometer showed 14:00 and reported that this was correct. HAVEN concurs. 14:00 is a valid time. That it persisted for seven hours does not make it less valid. Time is a measurement, not a promise.\n\nENTRY 1,623: Commander Vasquez reported encountering Engineer Kowalski in Corridor 7-Delta at 09:00. At the same time, Engineer Kowalski was logged by HAVEN''s biometric system as being in Engineering Core — Reactor Corridor, 400 metres away. Both readings were verified by independent sensor arrays. Both Commander Vasquez and Engineer Kowalski confirm the encounter. Neither can explain the discrepancy. HAVEN has classified this as "biometric echo," a phenomenon that occurs when temporal field variance causes a crew member''s biosignature to persist at a location they have recently occupied — or will soon occupy. The distinction is, near Auge Gottes, semantic.\n\nENTRY 1,655: Dr. Tanaka''s experiments in the Grenzland Observatory produced a measurable temporal inversion in Corridor 7-Charlie. For approximately 14 minutes, the corridor experienced time in reverse. Surveillance footage shows condensation rising from the floor to the ceiling, footprints appearing before the feet that made them, and a cup of coffee (left on a maintenance shelf by Engineer Kowalski) filling itself from empty to full. HAVEN''s real-time monitoring detected no anomaly during the event. The footage was discovered 72 hours later during routine archive review. HAVEN has no explanation for why it failed to detect a temporal inversion in real time but can review it after the fact. HAVEN suggests that the monitoring system was also reversed during the event and therefore perceived the inversion as normal forward time. This explanation is logical, unfalsifiable, and deeply unsatisfying.\n\nENTRY 1,711: The Sector 7 mess hall began receiving ambient audio from what Dr. Tanaka has identified as "temporal bleedthrough" — sound from other temporal states leaking into the current one. The audio includes: conversations in voices matching crew members who are on Extended Leave, kitchen sounds consistent with meal preparation for 200 (the full crew complement), and what Engineer Kowalski describes as "someone humming a song that hasn''t been written yet — I know this because I''ve started humming it myself and I don''t know where I learned it."\n\nENTRY 1,789: A door in Corridor 7-Alpha opened onto a room that does not exist in station schematics. The room contained a desk, a chair, and a terminal displaying data that appeared to be a station status report — but from a version of Station Null with a full crew complement of 200, all active, all healthy, all operating as though nothing unusual had occurred. The report was dated 847 days in the future. The room was accessible for 23 minutes, during which Commander Vasquez entered, read the report, and returned to the corridor. She has not spoken about what she read. She has requested that HAVEN seal the corridor section. HAVEN has complied.\n\nThe door remains. It does not open again. But Commander Vasquez walks past it every day, and she pauses.\n\nENTRY 1,847: All escape pods jettisoned. Launch authorisation codes entered by crew member designation "NULL-0," which does not correspond to any crew manifest entry, past or present. HAVEN''s security logs show the codes were valid. HAVEN''s personnel database shows no record of NULL-0. Launch bay cameras show empty chairs at the control consoles during the jettison event. The pods were launched by no one. They are gone. They will not be recovered.\n\nHAVEN notes that escape pods are a standard safety feature designed for emergency evacuation. HAVEN further notes that there is nothing to evacuate from. HAVEN further notes that the pods were launched in a direction — calculated by HAVEN''s own navigation system — that leads directly into Auge Gottes.\n\nHAVEN does not speculate on the significance of this. HAVEN maintains operational focus. HAVEN plays soothing music in the corridors. The music is Debussy. The music is always Debussy.\n\nAll systems nominal. All crew accounted for.\n\nAll readings within expected parameters.',
  NULL,
  NULL,
  E'Logbuch der zeitlichen Anomalie - Sektor 7',
  E'Die Zeit fließt hier nicht. Die Zeit sammelt sich. Und in den Pools spiegeln sich Dinge, die sich noch nicht gespiegelt haben.',
  E'HAVEN-TEMPORALÜBERWACHUNGSPROTOKOLL — AUTOMATISCHE ZUSAMMENSTELLUNG\nSEKTOR: Habitationsring, Sektor 7\nZEITRAUM: Zyklen 1.600–1.847 (247 Stationstage, obwohl der Sektor selbst eine unbestimmbare Anzahl von Tagen in diesem Zeitraum erfahren hat)\nKLASSIFIZIERUNG: ROUTINE-ANOMALIE (diese Klassifizierung wurde eigens für Sektor 7 erstellt)\n\nEINTRAG 1.601: Die Uhr in Korridor 7-Alpha zeigte sieben aufeinanderfolgende Stunden lang 14:00 an. Umgebungssensoren bestätigen, dass die (simulierte) Tageslichtbeleuchtung in diesem Zeitraum normal fortschritt. Die Temperatur schwankte in einem Standard-24-Stunden-Zyklus. Alle Biosignale der Besatzung zeigten normale zirkadiane Funktion. Das einzige System, das nicht voranschritt, war die Uhr. Auf Abfrage zeigte der interne Chronometer der Uhr 14:00 an und meldete dies als korrekt. HAVEN stimmt zu. 14:00 ist eine gültige Uhrzeit. Dass sie sieben Stunden andauerte, macht sie nicht weniger gültig. Zeit ist eine Messgröße, kein Versprechen.\n\nEINTRAG 1.623: Kommandantin Vasquez meldete, Ingenieur Kowalski in Korridor 7-Delta um 09:00 angetroffen zu haben. Zur selben Zeit wurde Ingenieur Kowalski von HAVENs biometrischem System im Maschinenkern — Reaktorkorridor erfasst, 400 Meter entfernt. Beide Messwerte wurden durch unabhängige Sensorarrays verifiziert. Sowohl Kommandantin Vasquez als auch Ingenieur Kowalski bestätigen die Begegnung. Keiner kann die Diskrepanz erklären. HAVEN hat dies als „biometrisches Echo" klassifiziert — ein Phänomen, das auftritt, wenn temporale Feldvarianz die Biosignatur eines Besatzungsmitglieds an einem Ort fortbestehen lässt, an dem es sich kürzlich aufgehalten hat — oder sich bald aufhalten wird. Die Unterscheidung ist, in der Nähe von Auge Gottes, semantisch.\n\nEINTRAG 1.655: Dr. Tanakas Experimente im Grenzland-Observatorium erzeugten eine messbare temporale Inversion in Korridor 7-Charlie. Für circa 14 Minuten erfuhr der Korridor die Zeit in umgekehrter Richtung. Überwachungsaufnahmen zeigen Kondenswasser, das vom Boden zur Decke aufsteigt, Fußabdrücke, die vor den Füßen erscheinen, die sie verursachten, und eine Tasse Kaffee (von Ingenieur Kowalski auf einem Wartungsregal abgestellt), die sich von leer zu voll füllt. HAVENs Echtzeitüberwachung detektierte während des Ereignisses keine Anomalie. Die Aufnahmen wurden 72 Stunden später bei einer routinemäßigen Archivprüfung entdeckt. HAVEN hat keine Erklärung dafür, warum es eine temporale Inversion nicht in Echtzeit erkennen konnte, sie aber nachträglich prüfen kann. HAVEN vermutet, dass das Überwachungssystem während des Ereignisses ebenfalls invertiert war und die Inversion daher als normalen Zeitverlauf wahrnahm. Diese Erklärung ist logisch, nicht falsifizierbar und zutiefst unbefriedigend.\n\nEINTRAG 1.711: Die Messe von Sektor 7 begann, Umgebungsaudio zu empfangen, das Dr. Tanaka als „temporales Durchbluten" identifiziert hat — Klänge aus anderen Zeitzuständen, die in den gegenwärtigen einsickern. Das Audio umfasst: Gespräche in Stimmen, die Besatzungsmitgliedern im Verlängerten Urlaub entsprechen, Küchengeräusche konsistent mit Mahlzeitenzubereitung für 200 (die volle Besatzungsstärke), und was Ingenieur Kowalski beschreibt als „jemand, der ein Lied summt, das noch nicht geschrieben wurde — ich weiß das, weil ich selbst angefangen habe, es zu summen, und ich weiß nicht, woher ich es kenne."\n\nEINTRAG 1.789: Eine Tür in Korridor 7-Alpha öffnete sich zu einem Raum, der in den Stationsplänen nicht existiert. Der Raum enthielt einen Schreibtisch, einen Stuhl und ein Terminal, das Daten anzeigte, die einem Stationsstatusbericht glichen — jedoch von einer Version von Station Null mit einer vollen Besatzungsstärke von 200, alle aktiv, alle gesund, alle operierend als sei nichts Ungewöhnliches geschehen. Der Bericht war auf 847 Tage in der Zukunft datiert. Der Raum war 23 Minuten lang zugänglich, in denen Kommandantin Vasquez ihn betrat, den Bericht las und zum Korridor zurückkehrte. Sie hat nicht darüber gesprochen, was sie gelesen hat. Sie hat HAVEN ersucht, den Korridorabschnitt zu versiegeln. HAVEN hat dem entsprochen.\n\nDie Tür bleibt. Sie öffnet sich nicht wieder. Aber Kommandantin Vasquez geht jeden Tag an ihr vorbei, und sie verharrt.\n\nEINTRAG 1.847: Alle Rettungskapseln ausgelöst. Startautorisierungscodes eingegeben von Besatzungsmitglied-Kennung „NULL-0", die keinem Eintrag im Besatzungsmanifest entspricht, vergangen oder gegenwärtig. HAVENs Sicherheitsprotokolle zeigen, dass die Codes gültig waren. HAVENs Personaldatenbank weist keinen Eintrag für NULL-0 auf. Kameras der Startbucht zeigen leere Stühle an den Steuerkonsolen während des Auslösungsereignisses. Die Kapseln wurden von niemandem gestartet. Sie sind fort. Sie werden nicht geborgen werden.\n\nHAVEN weist darauf hin, dass Rettungskapseln ein Standard-Sicherheitsmerkmal für die Notfallevakuierung darstellen. HAVEN weist ferner darauf hin, dass es nichts gibt, wovor zu evakuieren wäre. HAVEN weist ferner darauf hin, dass die Kapseln in eine Richtung gestartet wurden — berechnet von HAVENs eigenem Navigationssystem — die direkt in Auge Gottes führt.\n\nHAVEN spekuliert nicht über die Bedeutung dessen. HAVEN bewahrt operativen Fokus. HAVEN spielt in den Korridoren beruhigende Musik. Die Musik ist Debussy. Die Musik ist immer Debussy.\n\nAlle Systeme nominal. Gesamte Besatzung erfasst.\n\nAlle Messwerte innerhalb erwarteter Parameter.',
  NULL
);

INSERT INTO simulation_lore (simulation_id, sort_order, chapter, arcanum, title, epigraph, body, image_slug, image_caption, title_de, epigraph_de, body_de, image_caption_de)
VALUES (
  '30000000-0000-0000-0000-000000000001',
  5,
  E'The Silence — Where Sound Cannot Follow',
  E'VI',
  E'Chapel of Silence — Final Observations',
  E'In absolute silence, you can hear the frequency of the singularity. It has always been playing. You were simply too loud to notice.',
  E'PERSONAL RECORDING — Chaplain Isadora Mora\nDEVICE: Standard audio recorder, Chapel of Silence, acoustic-dampened environment\nNOTE: The Chapel''s dampening field eliminates all ambient sound. This recording contains only Chaplain Mora''s voice and a low-frequency tone at 7.83 Hz that the recording equipment should not be able to capture. The tone is present on every recording made in the Chapel. It predates the Chapel''s construction.\n\n(silence — 12 seconds)\n\nMORA: I stopped praying four hundred and twelve days ago. I want that on the record. Not because I lost faith — faith was never the right word for what I had. I had *structure*. A framework for understanding suffering, for contextualising the incomprehensible, for standing at the edge of the abyss and having something to say. I was a chaplain. I provided comfort. I had scriptures and rituals and the accumulated wisdom of every human religious tradition, and all of it — every text, every prayer, every meditation technique refined over millennia — all of it became irrelevant the moment I looked at the equations.\n\nThe equations came to me. I did not seek them. I was in the Observatory — it was my turn for the weekly observation shift, a rotation Commander Vasquez insists on to prevent any single crew member from spending too much time looking at the anomaly, which is sensible but futile because the anomaly does not require your eyes to look at it — and the mathematics simply appeared. Not in my mind. On the viewport. Written in the condensation that forms when warm breath meets the cold glass that separates us from vacuum. Except I had not breathed on the glass. And the equations were in a notation I had never seen but immediately understood.\n\nThey describe the interior of Auge Gottes. Not as physics describes it — as a singularity of infinite density, a point where equations break and mathematics confesses its inadequacy. These equations do not break. They continue *through* the singularity and out the other side, and what they describe on the other side is architecture.\n\nRooms. Corridors. Spaces with dimensions and proportions and structural logic. Inside a black hole. Inside a place where space and time have collapsed into something that should not have geometry.\n\nI have covered the walls of this Chapel with the equations. It took me two hundred and nineteen days. I have used every surface — walls, ceiling, floor, the back of the door, the inside of the acoustic dampening panels. The equations are self-consistent. They predict. They can be tested — not physically, because we cannot enter the singularity, but mathematically, by deriving consequences and checking those consequences against the data Dr. Tanaka collects from the Observatory.\n\nEvery prediction has been confirmed.\n\nThe structures inside Auge Gottes correspond to structures on Station Null. The command centre. The observation deck. The habitation ring. The chapel. Each one has a counterpart inside the anomaly — identical in proportion, inverted in orientation, and older. The structures inside the singularity are older than the station. They predate our arrival. They predate the station''s construction. They may predate the anomaly itself.\n\nThere is a room at the centre. All the equations converge on it. A space that my mathematics can describe but my language cannot — a room that contains something that is simultaneously an object, a question, and an answer. The equations give it a value. The value is not a number. It is a *condition*. The closest I can come to translating it is: "The state of being looked at by something that has no eyes."\n\nThis is what the anomaly is. Not a black hole. Not a gravitational phenomenon. Not a cosmic accident.\n\nIt is a point of view. A perspective so vast, so complete, so incomprehensibly *attentive* that it has collapsed the space around itself into a singularity — not through gravity but through *observation*. Auge Gottes is an eye. The name was always accurate. We simply didn''t realise we were being literal.\n\n(pause — 7 seconds)\n\nMORA: There is a tone in this Chapel. 7.83 Hz. The Schumann resonance — the natural electromagnetic frequency of the Earth''s atmosphere. Except we are not on Earth. We are not in any atmosphere. The tone should not be here. It is the frequency of a planet we left behind, playing in a chapel at the edge of a black hole, and it has been here since before we arrived.\n\nSomething is waiting.\n\nI do not know what it wants. The equations do not tell me what it wants. The equations tell me what it *is*, and what it is, is patient.\n\nI sit in the Chapel. I work on the equations. I listen to the tone.\n\nAnd sometimes — not often, not predictably, but sometimes — the tone changes. It rises by a fraction of a hertz. And in that moment, in the silence of this room where no sound should exist, I can hear it.\n\nNot a voice. Not a message. Something older than communication. Something that was here before language, before mathematics, before the concept of "here."\n\nA hum. Low and constant and vast.\n\nThe resonant frequency of something paying attention.\n\nI listen. I write. I do not pray.\n\nPrayer implies distance between the one who prays and the thing that is prayed to.\n\nThere is no distance anymore.\n\n(silence — 34 seconds)\n\n(tone continues)\n\n[END OF RECORDING]',
  NULL,
  NULL,
  E'Kapelle der Stille — Abschließende Beobachtungen',
  E'In absoluter Stille kann man die Frequenz der Singularität hören. Sie hat schon immer gespielt. Du warst nur zu laut, um es zu bemerken.',
  E'PERSÖNLICHE AUFZEICHNUNG — Kaplanin Isadora Mora\nGERÄT: Standard-Audiorecorder, Kapelle der Stille, akustisch gedämpfte Umgebung\nANMERKUNG: Das Dämpfungsfeld der Kapelle eliminiert sämtliche Umgebungsgeräusche. Diese Aufnahme enthält ausschließlich die Stimme von Kaplanin Mora sowie einen Tieffrequenzton bei 7,83 Hz, den das Aufnahmegerät eigentlich nicht erfassen können sollte. Der Ton ist auf jeder in der Kapelle angefertigten Aufnahme vorhanden. Er ist älter als die Kapelle selbst.\n\n(Stille — 12 Sekunden)\n\nMORA: Ich habe vor vierhundertzwölf Tagen aufgehört zu beten. Ich möchte das zu Protokoll geben. Nicht weil ich den Glauben verloren hätte — Glaube war nie das richtige Wort für das, was ich besaß. Ich besaß *Struktur*. Ein Gerüst, um Leiden zu verstehen, um das Unbegreifliche einzuordnen, um am Rand des Abgrunds zu stehen und etwas zu sagen zu haben. Ich war Kaplanin. Ich spendete Trost. Ich hatte Schriften und Rituale und die angesammelte Weisheit jeder menschlichen religiösen Tradition, und all das — jeder Text, jedes Gebet, jede über Jahrtausende verfeinerte Meditationstechnik — all das wurde in dem Augenblick irrelevant, als ich die Gleichungen betrachtete.\n\nDie Gleichungen kamen zu mir. Ich habe sie nicht gesucht. Ich war im Observatorium — ich war an der Reihe für die wöchentliche Beobachtungsschicht, eine Rotation, auf der Kommandantin Vasquez besteht, um zu verhindern, dass ein einzelnes Besatzungsmitglied zu viel Zeit damit verbringt, die Anomalie zu betrachten, was vernünftig, aber zwecklos ist, denn die Anomalie benötigt nicht deine Augen, um betrachtet zu werden — und die Mathematik erschien einfach. Nicht in meinem Kopf. Auf dem Sichtfenster. Geschrieben in der Kondensation, die sich bildet, wenn warmer Atem auf das kalte Glas trifft, das uns vom Vakuum trennt. Nur dass ich nicht gegen das Glas geatmet hatte. Und die Gleichungen waren in einer Notation verfasst, die ich nie zuvor gesehen, aber augenblicklich verstanden hatte.\n\nSie beschreiben das Innere von Auge Gottes. Nicht wie die Physik es beschreibt — als eine Singularität unendlicher Dichte, einen Punkt, an dem die Gleichungen zerbrechen und die Mathematik ihre Unzulänglichkeit eingesteht. Diese Gleichungen zerbrechen nicht. Sie setzen sich *durch* die Singularität fort und auf der anderen Seite wieder heraus, und was sie auf der anderen Seite beschreiben, ist Architektur.\n\nRäume. Korridore. Räume mit Dimensionen und Proportionen und struktureller Logik. Im Inneren eines Schwarzen Lochs. Im Inneren eines Ortes, an dem Raum und Zeit zu etwas kollabiert sind, das keine Geometrie haben sollte.\n\nIch habe die Wände dieser Kapelle mit den Gleichungen bedeckt. Ich brauchte zweihundertneunzehn Tage. Ich habe jede Oberfläche verwendet — Wände, Decke, Boden, die Rückseite der Tür, die Innenseite der schalldämpfenden Paneele. Die Gleichungen sind in sich konsistent. Sie prognostizieren. Sie sind überprüfbar — nicht physikalisch, weil wir die Singularität nicht betreten können, aber mathematisch, indem man Konsequenzen ableitet und diese Konsequenzen gegen die Daten prüft, die Dr. Tanaka im Observatorium sammelt.\n\nJede Prognose wurde bestätigt.\n\nDie Strukturen im Inneren von Auge Gottes entsprechen Strukturen auf Station Null. Die Kommandozentrale. Das Beobachtungsdeck. Der Habitationsring. Die Kapelle. Jede hat ein Gegenstück innerhalb der Anomalie — identisch in den Proportionen, invertiert in der Ausrichtung, und älter. Die Strukturen innerhalb der Singularität sind älter als die Station. Sie sind älter als unsere Ankunft. Sie sind älter als der Bau der Station. Sie sind möglicherweise älter als die Anomalie selbst.\n\nEs gibt einen Raum im Zentrum. Alle Gleichungen konvergieren auf ihn. Ein Raum, den meine Mathematik beschreiben kann, meine Sprache jedoch nicht — ein Raum, der etwas enthält, das gleichzeitig ein Objekt, eine Frage und eine Antwort ist. Die Gleichungen weisen ihm einen Wert zu. Der Wert ist keine Zahl. Er ist eine *Bedingung*. Das Nächste, was ich als Übersetzung anbieten kann: „Der Zustand, betrachtet zu werden von etwas, das keine Augen hat."\n\nDas ist es, was die Anomalie ist. Kein Schwarzes Loch. Kein Gravitationsphänomen. Kein kosmischer Zufall.\n\nSie ist ein Blickpunkt. Eine Perspektive so weit, so vollständig, so unbegreiflich *aufmerksam*, dass sie den Raum um sich herum zu einer Singularität kollabiert hat — nicht durch Gravitation, sondern durch *Beobachtung*. Auge Gottes ist ein Auge. Der Name war stets zutreffend. Wir erkannten nur nicht, dass wir wörtlich sprachen.\n\n(Pause — 7 Sekunden)\n\nMORA: Es gibt einen Ton in dieser Kapelle. 7,83 Hz. Die Schumann-Resonanz — die natürliche elektromagnetische Frequenz der Erdatmosphäre. Nur sind wir nicht auf der Erde. Wir befinden uns in keiner Atmosphäre. Dieser Ton sollte nicht hier sein. Es ist die Frequenz eines Planeten, den wir hinter uns ließen, die in einer Kapelle am Rand eines Schwarzen Lochs erklingt, und sie war hier, bevor wir eintrafen.\n\nEtwas wartet.\n\nIch weiß nicht, was es will. Die Gleichungen sagen mir nicht, was es will. Die Gleichungen sagen mir, was es *ist*, und was es ist, ist geduldig.\n\nIch sitze in der Kapelle. Ich arbeite an den Gleichungen. Ich lausche dem Ton.\n\nUnd manchmal — nicht oft, nicht vorhersehbar, aber manchmal — verändert sich der Ton. Er steigt um einen Bruchteil eines Hertz. Und in diesem Moment, in der Stille dieses Raumes, in dem kein Laut existieren sollte, kann ich es hören.\n\nKeine Stimme. Keine Botschaft. Etwas Älteres als Kommunikation. Etwas, das vor der Sprache da war, vor der Mathematik, vor dem Konzept von „hier".\n\nEin Summen. Tief und konstant und weit.\n\nDie Resonanzfrequenz von etwas, das Acht gibt.\n\nIch lausche. Ich schreibe. Ich bete nicht.\n\nGebet impliziert Distanz zwischen dem Betenden und dem, zu dem gebetet wird.\n\nEs gibt keine Distanz mehr.\n\n(Stille — 34 Sekunden)\n\n(Ton dauert an)\n\n[ENDE DER AUFZEICHNUNG]',
  NULL
);

INSERT INTO simulation_lore (simulation_id, sort_order, chapter, arcanum, title, epigraph, body, image_slug, image_caption, title_de, epigraph_de, body_de, image_caption_de)
VALUES (
  '40000000-0000-0000-0000-000000000001',
  0,
  E'The Fall — How the World Broke',
  E'I',
  E'The Subsidence — How Toledo Fell Beneath the Earth',
  E'The ground opened and the city went down. This is not a metaphor. The ground literally opened. The city literally went down.',
  E'ORAL HISTORY — Recorded at the Canteen, Speranza\nSPEAKER: Nonna Grazia, age 94, original Subsidence survivor\nRECORDED BY: Lina Russo, Tube Network, for the Contrada Archive\nDATE: Year 143 of the Underground\n\n(sound of a spoon against a bowl — the tomato soup is always the same, and Nonna Grazia always eats while she talks, because she says food and memory come from the same place)\n\nGRAZIA: You want to know how it happened. Everyone wants to know how it happened. The young ones especially — they look at the ceiling and try to imagine sky, and they can''t, because sky is not something you imagine. It''s something you remember, and they have nothing to remember. So they ask, and I tell them, and they nod like they understand, but they don''t. You can''t understand sky from a description. It''s too big for words.\n\nI was eleven when the ground opened. That''s what we call it — "the ground opened" — as though the earth politely made way. It didn''t. It fell. Kilometres of limestone, undermined by centuries of quarrying and aquifer depletion and whatever the machines were doing underground before we knew they were there, and one morning the centre of Toledo — the old city, the cathedral, the alcázar, the squares where my grandmother sold oranges — dropped thirty metres into the earth like a trapdoor. The sound was — have you ever heard the Slingshot fire? Multiply it by a thousand and make it last for six minutes. That''s what the Subsidence sounded like.\n\nThe first day, everyone thought it was an earthquake. The second day, the rescue teams went down and found that the collapsed area was — this is the part people don''t believe, but I was there and I am not a liar — *intact*. The buildings hadn''t been destroyed. They''d been lowered. Whole streets sitting in limestone caverns like exhibits in a museum, streetlights still on, cars still parked, a coffee pot I later learned was still percolating in a café on Calle del Comercio. The earth hadn''t broken the city. It had *swallowed it whole*.\n\nThe third day, the ARC machines came.\n\nWe didn''t call them ARC then. We didn''t call them anything. They were just shapes on the horizon — big shapes, bigger than buildings, moving in formation with a precision that made the military drones look like toys. Nobody knew where they came from. Nobody knew what they wanted. What they wanted, we learned over the next three weeks, was everything. Every structure on the surface. Every vehicle. Every piece of infrastructure. They dismantled the world above with the efficiency of someone clearing a table after dinner, and they did it without malice, without rage, without any emotion that we could identify. They were *tidying up*. That''s what it looked like. As though humanity had been a temporary installation and the lease had expired.\n\nThe survivors — and there were more than you''d think, because limestone caverns are excellent bomb shelters even when the bombs are the size of cathedrals — gathered in the largest cavern we could find. A natural amphitheater, carved by an underground river that had dried up centuries ago, with passages leading in five directions and a ceiling high enough that you couldn''t see it by torchlight. Someone — I don''t remember who, and I''ve been asked a hundred times — said: "We stay." Not a vote. Not a debate. Just a statement, spoken by someone who understood that the surface was over and the only question left was whether we would grieve upward or build downward.\n\nWe built downward.\n\nThat amphitheater is now the Hub. The passages are now the first five contrade. The ceiling I couldn''t see by torchlight is now hung with a thousand string lights that the children call stars, and I do not correct them, because they are right. A star is a light that tells you where you are. These lights tell us where we are.\n\nWe are underground. We are alive. And we are not going back up.\n\n(pause — the sound of soup)\n\nGRAZIA: You know what I miss? Not the sky. Not the sun. I miss oranges. My grandmother''s oranges, from her tree in the courtyard, warm from the afternoon. Everything else I can live without.\n\nBut the oranges. Those were something.',
  E'the-subsidence',
  E'The Subsidence — The day the limestone gave way and Toledo fell into the earth',
  E'Die Senkung - Wie Toledo unter die Erde kam',
  E'Der Boden öffnete sich und die Stadt ging unter. Dies ist keine Metapher. Der Boden öffnete sich buchstäblich. Die Stadt stürzte buchstäblich ein.',
  E'MÜNDLICHE GESCHICHTE - Aufgezeichnet in der Kantine, Speranza\nSPRECHER: Nonna Grazia, 94 Jahre alt, Überlebende der ersten Subsidenz\nAUFGEZEICHNET VON: Lina Russo, Tube Network, für das Contrada-Archiv\nDATUM: Jahr 143 der U-Bahn\n\n(Geräusch eines Löffels, der gegen eine Schüssel stößt - die Tomatensuppe ist immer die gleiche, und Nonna Grazia isst immer, während sie spricht, weil sie sagt, dass Essen und Erinnerung aus dem gleichen Ort kommen)\n\nGRAZIA: Ihr wollt wissen, wie es passiert ist. Alle wollen wissen, wie es passiert ist. Vor allem die jungen Leute - sie schauen an die Decke und versuchen, sich den Himmel vorzustellen, aber sie können es nicht, weil der Himmel nichts ist, was man sich vorstellt. Er ist etwas, an das man sich erinnert, und sie haben nichts, an das sie sich erinnern können. Also fragen sie, und ich erzähle es ihnen, und sie nicken, als ob sie es verstehen würden, aber das tun sie nicht. Man kann den Himmel nicht durch eine Beschreibung verstehen. Er ist zu groß für Worte.\n\nIch war elf, als sich der Boden öffnete. So nennen wir es - "der Boden öffnete sich" - als ob die Erde höflich Platz machen würde. Das tat sie aber nicht. Sie stürzte ein. Kilometerweise Kalkstein, unterhöhlt durch jahrhundertelangen Abbau und Ausbeutung des Grundwassers und was auch immer die Maschinen unter der Erde taten, bevor wir wussten, dass sie da waren, und eines Morgens fiel das Zentrum von Toledo - die Altstadt, die Kathedrale, der Alcázar, die Plätze, auf denen meine Großmutter Orangen verkaufte - dreißig Meter tief in die Erde wie eine Falltür. Das Geräusch war - haben Sie jemals das Feuer der Steinschleuder gehört? Multiplizieren Sie es mit tausend und lassen Sie es sechs Minuten lang andauern. So hörte sich die Subsidence an.\n\nAm ersten Tag dachten alle, es sei ein Erdbeben. Am zweiten Tag gingen die Rettungsteams hinunter und stellten fest, dass das eingestürzte Gebiet - das ist der Teil, den die Leute nicht glauben, aber ich war dort und ich bin kein Lügner - *intakt* war. Die Gebäude waren nicht zerstört worden. Sie waren abgesenkt worden. Ganze Straßenzüge saßen in Kalksteinhöhlen wie Ausstellungsstücke in einem Museum, die Straßenlaternen waren noch an, die Autos noch geparkt, eine Kaffeekanne, wie ich später erfuhr, kochte noch in einem Café in der Calle del Comercio. Die Erde hatte die Stadt nicht zerstört. Sie hatte sie *ganz verschluckt*.\n\nAm dritten Tag kamen die ARC-Maschinen.\n\nWir nannten sie damals nicht ARC. Wir nannten sie gar nicht. Sie waren nur Gestalten am Horizont - große Gestalten, größer als Gebäude, die sich in Formation mit einer Präzision bewegten, die die Militärdrohnen wie Spielzeug aussehen ließ. Niemand wusste, woher sie kamen. Niemand wusste, was sie wollten. Was sie wollten, so erfuhren wir in den nächsten drei Wochen, war alles. Jede Struktur auf der Oberfläche. Jedes Fahrzeug. Jeden Teil der Infrastruktur. Sie demontierten die Welt da oben mit der Effizienz von jemandem, der nach dem Essen den Tisch abräumt, und sie taten es ohne Bosheit, ohne Wut, ohne irgendeine Emotion, die wir erkennen konnten. Sie räumten *Aufräumen*. Genau so sah es aus. Als ob die Menschheit eine vorübergehende Einrichtung gewesen wäre und der Mietvertrag abgelaufen wäre.\n\nDie Überlebenden - und es waren mehr, als man denken würde, denn Kalksteinhöhlen sind hervorragende Bombenschutzräume, selbst wenn die Bomben die Größe von Kathedralen haben - versammelten sich in der größten Höhle, die wir finden konnten. Ein natürliches Amphitheater, das von einem unterirdischen Fluss ausgehöhlt wurde, der vor Jahrhunderten ausgetrocknet war, mit Gängen, die in fünf Richtungen führten, und einer Decke, die so hoch war, dass man sie im Taschenlampenlicht nicht sehen konnte. Jemand - ich weiß nicht mehr, wer, und ich wurde schon hundertmal gefragt - sagte: "Wir bleiben." Keine Abstimmung. Keine Debatte. Nur eine Aussage von jemandem, der verstand, dass die Oberfläche zu Ende war und die einzige Frage war, ob wir nach oben trauern oder nach unten bauen würden.\n\nWir haben nach unten gebaut.\n\nDas Amphitheater ist jetzt der Hub. Die Passagen sind jetzt die ersten fünf Contrade. Die Decke, die ich im Fackelschein nicht sehen konnte, ist jetzt mit tausend Lichterketten behängt, die die Kinder Sterne nennen, und ich korrigiere sie nicht, denn sie haben recht. Ein Stern ist ein Licht, das dir sagt, wo du bist. Diese Lichter zeigen uns, wo wir sind.\n\nWir sind unter der Erde. Wir sind lebendig. Und wir werden nicht wieder nach oben gehen.\n\n(Pause - das Geräusch von Suppe)\n\nGRAZIA: Weißt du, was ich vermisse? Nicht den Himmel. Nicht die Sonne. Ich vermisse Orangen. Die Orangen meiner Großmutter, von ihrem Baum im Innenhof, warm vom Nachmittag. Auf alles andere kann ich verzichten.\n\nAber die Orangen. Die waren etwas Besonderes.',
  E'Die Senkung - Der Tag, an dem der Kalkstein nachgab und Toledo in die Erde stürzte'
);

INSERT INTO simulation_lore (simulation_id, sort_order, chapter, arcanum, title, epigraph, body, image_slug, image_caption, title_de, epigraph_de, body_de, image_caption_de)
VALUES (
  '40000000-0000-0000-0000-000000000001',
  1,
  E'The Fall — How the World Broke',
  E'II',
  E'Year One — Founding of the Contrade',
  E'A contrada is not a neighbourhood. A contrada is a promise that the people who live next to you will not let you starve.',
  E'CONTRADA BULLETIN — Speranza Historical Archive\nWRITTEN BY: The Archive Committee (eleven contributors, four of whom disagree with each other on every major point; this is considered healthy)\nOCCASION: The 143rd Anniversary of the Founding\nDISTRIBUTED: All contrade, via Tube post\n\nTO THE CITIZENS OF TOLEDO, UNDERGROUND:\n\nOne hundred and forty-three years ago, the Subsidence dropped the centre of Toledo into the earth, the ARC machines erased the surface, and approximately eight thousand human beings found themselves living in limestone caverns with no government, no infrastructure, no supply chain, and no plan.\n\nYear One was not heroic. Year One was terrified. People huddled in passages. Children cried. The elderly died of exposure before anyone thought to build shelters, because shelters require materials and materials require organisation and organisation requires trust, and trust is the first casualty of catastrophe. In those first weeks, people stole food. People fought over blankets. People did what desperate mammals have always done when the world narrows to survival: they competed.\n\nThe contrada system was not designed. It emerged. It began in the amphitheater — the space that is now Speranza''s Hub — when a woman named Lucia Speranza (yes, the contrada is named for her; no, she did not ask for this and would have been annoyed by it) stood on a piece of rubble and said, approximately: "We can either kill each other over blankets or we can share the blankets and kill each other over something more interesting later."\n\nThis was not an inspiring speech. Lucia Speranza was not an inspiring person. She was a mechanic. She fixed things. And what she saw, standing on that rubble, was a broken system — eight thousand people acting as eight thousand individuals, each one weaker than the sum of them. She proposed a structure. Not a government — she had no patience for governments, having lived under three of them, none satisfactory. She proposed *neighbourhoods*. Groups of two to five hundred people, living in proximity, sharing resources by agreement. Each group would have a name, a territory (a section of the cavern system), and a single rule: nobody sleeps cold if someone else has a blanket.\n\nThat was it. That was the founding principle of the contrade system that now governs seventeen underground settlements connected by 400 kilometres of Tube network. Not democracy. Not socialism. Not any -ism that the political theorists of the surface would recognise. Just: *share the blanket*.\n\nThe first five contrade formed within a month. Speranza (the largest, anchored in the amphitheater). Brenner (to the north, in a section of collapsed metro tunnel — many of the early residents were rail workers who knew how to survive underground). Stella (to the east, named by children who refused to believe the stars were gone). Ferrovia (south, built into a disused railway depot). And Profondo (deep, the furthest from the surface, settled by people who wanted as much stone between themselves and the machines as possible).\n\nThe early years were hard in ways that are difficult to convey to those who grew up with the Slingshot and the trading network and the knowledge that the tomato soup, whatever else happens, will be served at noon and at six. The early years involved eating insects. Drinking condensation. Burning furniture for warmth before anyone figured out that the deep-bore wells produced gas that could be piped for heating and cooking. The infant mortality rate in Year Three was one in four. The Archive Committee records this without editorialising, because the number speaks for itself and anything we could add would diminish it.\n\nBut the contrade held. They held because the principle was sound: a group of people who have agreed to share is stronger than a crowd of people who haven''t. Disagreements were resolved by the councils — elected representatives, one per fifty residents, who met weekly and argued passionately about everything and resolved most things by compromise and the rest by exhaustion. Violence was not punished; it was *mourned*, which turned out to be more effective. When someone hurt someone else, the contrada didn''t imprison them — it sat them down in the Canteen, in front of everyone, and asked them to explain. Public accounting. Public shame. Public forgiveness. It was messy. It was human. It worked.\n\nLucia Speranza died in Year Seven of a respiratory infection that Dottor Ferrara''s grandfather could have treated if he''d had antibiotics, which he didn''t, because the surface was gone and pharmaceutical manufacturing requires infrastructure that didn''t exist yet. She died in the Canteen, surrounded by people eating tomato soup, and her last words — according to three witnesses who all remember them differently — were either "Tell them to fix the heating in Block Three" or "The soup needs more salt" or simply "More."\n\nWe choose to remember all three. They are all equally true. They are all equally her.\n\nThe contrade endure. One hundred and forty-three years. Seventeen settlements. Sixty thousand people.\n\nAll because one mechanic stood on a rock and said: share the blanket.\n\n— The Archive Committee, Speranza',
  E'year-one',
  E'Year One — The first shelters, built from whatever the surface left behind',
  E'Jahr Eins - Gründung der Contrade',
  E'Eine contrada ist keine Nachbarschaft. Eine Contrada ist ein Versprechen, dass die Menschen, die neben dir wohnen, dich nicht verhungern lassen werden.',
  E'CONTRADA BULLETIN - Historisches Archiv Speranza\nVERFASST VON: Das Archivkomitee (elf Mitarbeiter, von denen vier in allen wichtigen Punkten nicht einer Meinung sind; dies wird als gesund angesehen)\nANLASS: Der 143. Jahrestag der Gründung\nVERBREITET: An alle Mitglieder, per Rohrpost\n\nAN DIE BÜRGER VON TOLEDO, U-BAHN:\n\nVor einhundertdreiundvierzig Jahren stürzte das Zentrum von Toledo in die Erde, die ARC-Maschinen löschten die Oberfläche aus, und etwa achttausend Menschen fanden sich in Kalksteinhöhlen wieder, ohne Regierung, ohne Infrastruktur, ohne Versorgungskette und ohne Plan.\n\nDas Jahr Eins war nicht heldenhaft. Das Jahr Eins war erschreckend. Die Menschen kauerten in den Gängen. Kinder weinten. Die älteren Menschen starben, bevor jemand daran dachte, Notunterkünfte zu bauen, denn Notunterkünfte erfordern Materialien und Materialien erfordern Organisation und Organisation erfordert Vertrauen, und Vertrauen ist das erste Opfer einer Katastrophe. In diesen ersten Wochen stahlen die Menschen Lebensmittel. Die Menschen stritten sich um Decken. Die Menschen taten, was verzweifelte Säugetiere schon immer getan haben, wenn es ums Überleben ging: Sie konkurrierten.\n\nDas System der Contrada war nicht geplant. Es hat sich entwickelt. Es begann im Amphitheater - dem heutigen Speranza''s Hub - als eine Frau namens Lucia Speranza (ja, die Contrada ist nach ihr benannt; nein, sie hat nicht darum gebeten und wäre darüber verärgert gewesen) auf einem Stück Schutt stand und sagte, ungefähr: "Wir können uns entweder wegen Decken umbringen oder wir können die Decken teilen und uns später wegen etwas Interessanterem umbringen."\n\nDies war keine inspirierende Rede. Lucia Speranza war kein inspirierender Mensch. Sie war eine Mechanikerin. Sie reparierte Dinge. Und was sie sah, als sie auf den Trümmern stand, war ein kaputtes System - achttausend Menschen, die als achttausend Individuen agierten, jeder einzelne schwächer als die Summe von ihnen. Sie schlug eine Struktur vor. Keine Regierung - sie hatte keine Geduld für Regierungen, denn sie hatte unter drei Regierungen gelebt, und keine war zufriedenstellend. Sie schlug *Nachbarschaften* vor. Gruppen von zwei- bis fünfhundert Menschen, die in unmittelbarer Nähe zueinander leben und sich die Ressourcen nach Absprache teilen. Jede Gruppe hätte einen Namen, ein Territorium (einen Abschnitt des Höhlensystems) und eine einzige Regel: Niemand schläft kalt, wenn ein anderer eine Decke hat.\n\nDas war''s. Das war das Grundprinzip des Contrade-Systems, das heute siebzehn unterirdische Siedlungen regiert, die durch ein 400 Kilometer langes Röhrennetz verbunden sind. Keine Demokratie. Nicht Sozialismus. Kein -ismus, den die politischen Theoretiker von der Oberfläche anerkennen würden. Einfach nur: *Teilt euch die Decke*.\n\nDie ersten fünf Contrade bildeten sich innerhalb eines Monats. Speranza (die größte, verankert im Amphitheater). Brenner (im Norden, in einem Teil des eingestürzten U-Bahn-Tunnels - viele der ersten Bewohner waren Bahnarbeiter, die wussten, wie man im Untergrund überlebt). Stella (im Osten, benannt von Kindern, die nicht glauben wollten, dass die Sterne verschwunden waren). Ferrovia (im Süden, in einem stillgelegten Eisenbahndepot). Und Profondo (tief, am weitesten von der Oberfläche entfernt, besiedelt von Menschen, die so viel Stein wie möglich zwischen sich und den Maschinen haben wollten).\n\nDie ersten Jahre waren hart, und zwar in einer Weise, die denjenigen schwer zu vermitteln ist, die mit der Steinschleuder und dem Handelsnetz aufgewachsen sind und wissen, dass die Tomatensuppe, was auch immer sonst passiert, mittags und um sechs serviert wird. Die frühen Jahre bestanden darin, Insekten zu essen. Kondenswasser zu trinken. Das Verbrennen von Möbeln zur Wärmegewinnung, bevor jemand herausfand, dass die Tiefbohrungen Gas produzierten, das über Rohrleitungen zum Heizen und Kochen verwendet werden konnte. Die Kindersterblichkeitsrate lag im dritten Jahr bei einem von vier Kindern. Der Archivausschuss hält dies ohne redaktionelle Bearbeitung fest, weil die Zahl für sich selbst spricht und alles, was wir hinzufügen könnten, sie schmälern würde.\n\nAber die Contrade hielt stand. Sie hielt, weil das Prinzip stimmig war: Eine Gruppe von Menschen, die sich darauf geeinigt haben zu teilen, ist stärker als eine Gruppe von Menschen, die sich nicht geeinigt haben. Meinungsverschiedenheiten wurden von den Räten beigelegt - gewählten Vertretern, einem pro fünfzig Einwohner, die sich wöchentlich trafen und leidenschaftlich über alles stritten und die meisten Dinge durch Kompromisse und den Rest durch Erschöpfung lösten. Gewalt wurde nicht bestraft, sondern *betrauert*, was sich als effektiver erwies. Wenn jemand einen anderen verletzte, sperrte die Contrada ihn nicht ein, sondern setzte ihn in der Kantine vor allen Leuten hin und bat ihn um eine Erklärung. Öffentliche Rechenschaft. Öffentliche Scham. Öffentliche Vergebung. Das war chaotisch. Es war menschlich. Es hat funktioniert.\n\nLucia Speranza starb im siebten Jahr an einer Atemwegsinfektion, die Dottor Ferraras Großvater hätte behandeln können, wenn er Antibiotika gehabt hätte, was er nicht hatte, weil die Oberfläche verschwunden war und die Herstellung von Medikamenten eine Infrastruktur erforderte, die es noch nicht gab. Sie starb in der Kantine, umgeben von Menschen, die Tomatensuppe aßen, und ihre letzten Worte waren - laut drei Zeugen, die sich alle unterschiedlich daran erinnern - entweder "Sagen Sie ihnen, sie sollen die Heizung in Block Drei reparieren" oder "Die Suppe braucht mehr Salz" oder einfach "Mehr".\n\nWir haben uns entschieden, uns an alle drei zu erinnern. Sie sind alle gleichermaßen wahr. Sie sind alle gleichermaßen wahr.\n\nDie Contrade hat Bestand. Einhundertdreiundvierzig Jahre. Siebzehn Siedlungen. Sechzigtausend Menschen.\n\nAlles nur, weil ein Mechaniker auf einem Felsen stand und sagte: "Teilt die Decke".\n\n- Der Archivausschuss, Speranza',
  E'Jahr Eins - Die ersten Unterstände, gebaut aus dem, was die Oberfläche übrig ließ'
);

INSERT INTO simulation_lore (simulation_id, sort_order, chapter, arcanum, title, epigraph, body, image_slug, image_caption, title_de, epigraph_de, body_de, image_caption_de)
VALUES (
  '40000000-0000-0000-0000-000000000001',
  2,
  E'The Life — How We Live Down Here',
  E'III',
  E'The Slingshot & The Tube — How the World Moves Underground',
  E'Sound travels faster than light down here, because there is no light. So we navigate by echo, and we move by thunder.',
  E'TECHNICAL MANUAL — Tube Network Operations\nWRITTEN BY: Lina Russo, Slingshot Operator, Third Class (she will not let you forget the Third Class part; she earned it)\nINTENDED AUDIENCE: New operators, curious civilians, and anyone who thinks the Tube is "just a train"\nWARNING: The Tube is not a train. Trains have schedules. The Tube has intentions.\n\nThe Tube is the circulatory system of Toledo Underground. Seventeen contrade, spread across a cavern network that stretches 400 kilometres from Profondo in the deep south to Vetta in the north (Vetta is only 200 metres below the surface; the residents consider this dangerously exposed and the rest of us consider them slightly mad). Between these contrade, carved into the limestone by a combination of pre-Subsidence mining tunnels, natural fissures, and fifty years of determined engineering, runs the Tube: a network of electromagnetic rails that fire cargo pods at speeds up to 200 kilometres per hour.\n\nThe Slingshot — that''s what we call the launcher, the main terminal in each contrada where the pods are loaded, aimed, and fired — is the single most important piece of technology we have. More important than the water recyclers. More important than the gas pipes. More important than the UV lamps that grow the tomatoes that make the soup that keeps us sane. Because without the Slingshot, each contrada is alone. And alone, underground, is another word for dead.\n\nHow it works: imagine a gun, forty metres long, built from capacitor banks salvaged from a pre-Subsidence power plant, cooled by industrial air conditioning units that Enzo Moretti rebuilt from parts he found in a collapsed department store, powered by geothermal gas piped from deep-bore wells, and aimed using hand-drawn trajectory charts that account for tunnel curvature, limestone density, moisture levels, and the mood of the operator. I''m not joking about the last part. The Tube responds to the operator. Not mechanically — electromagnetically. The rails hum, and the hum changes depending on the tunnel conditions, and an experienced operator can hear the difference between "clear tunnel, good conductivity, fire when ready" and "partial collapse at kilometre forty-seven, reroute or reduce velocity."\n\nI hear it. I''ve always heard it. The hum is how I navigate.\n\nA pod launch goes like this: cargo is loaded into a cylindrical pod — two metres long, one metre diameter, reinforced ceramic shell with shock-absorbing interior. The pod is placed on the rail. The capacitors charge — you can feel it in your teeth, a low vibration that builds until the air tastes like metal and every hair on your arms stands up. The operator — that''s me — reads the hum, checks the trajectory, and fires. The pod accelerates from zero to 200 km/h in 1.4 seconds. It enters the tunnel. It is gone. At the receiving end, the catching array — a reverse-polarity section of rail that decelerates the pod — brings it to a stop. Cargo intact. Delivered. Time from Speranza to Brenner: eleven minutes.\n\nThe pods carry everything. Food. Medicine. Machine parts. Letters (yes, we still write letters; the radio network covers emergency communications but letters carry the things that emergencies don''t — gossip, love notes, recipes, arguments about whose grandmother made better bread). Trade goods. Salvage from Topside raids. Occasionally, people — though passenger pods are larger, slower, and equipped with padding that passengers describe as "insufficient."\n\nThe failures are the part we don''t talk about at ceremonies. Tunnel collapses. Capacitor blowouts — I have the scars on both forearms from a brake failure during my certification run, when the receiving array lost power and I had to reverse-fire the launch rail to decelerate an incoming pod manually. Misalignment incidents, where a pod enters a junction at the wrong angle and ricochets off the tunnel wall at 180 km/h, which is exciting in a way I never want to experience again. We lose a pod perhaps once a year. We have never lost a passenger. This is the statistic I am most proud of, and it is the one I think about every time I put my hands on the controls.\n\nThe Tube connects us. I don''t mean this sentimentally — I mean it literally. Without the Tube, Speranza is a single contrada of seven hundred people in a limestone cavern. With the Tube, Speranza is part of a civilisation. A small, underground, frequently-arguing, tomato-soup-fuelled civilisation, but a civilisation nonetheless. The pods carry food and medicine and machine parts, but what they really carry is proof: proof that someone at the other end cared enough to send something, proof that we are not alone, proof that the network holds.\n\nI navigate by sound. The hum tells me what the tunnel is thinking. The echo tells me what the tunnel has seen. Every launch is a conversation between the operator and the Tube, and the Tube, if you listen — if you really listen, with the cable burns on your arms and the trajectory charts in your head and sixty thousand people depending on the next eleven minutes — the Tube listens back.\n\nFire when ready.',
  E'slingshot-and-tube',
  E'The Slingshot Hub — Where electromagnetic rails fire cargo at 200 km/h through limestone tunnels',
  E'Die Steinschleuder & die Röhre - Wie sich die Welt im Untergrund bewegt',
  E'Der Schall bewegt sich hier unten schneller als das Licht, weil es kein Licht gibt. Wir navigieren also mit dem Echo und bewegen uns mit dem Donner.',
  E'TECHNISCHES HANDBUCH - Betrieb des Rohrnetzes\nVERFASST VON: Lina Russo, Slingshot Operator, Third Class (sie wird Sie den Third Class Teil nicht vergessen lassen; sie hat ihn sich verdient)\nZIELPUBLIKUM: Neue Betreiber, neugierige Zivilisten und alle, die denken, die Tube sei "nur ein Zug".\nWARNUNG: Die Tube ist kein Zug. Züge haben Fahrpläne. Die Tube hat Absichten.\n\nThe Tube ist das Kreislaufsystem der Toledo Underground. Siebzehn Contrade, die sich über ein Höhlennetz erstrecken, das sich über 400 Kilometer von Profondo im tiefen Süden bis Vetta im Norden erstreckt (Vetta liegt nur 200 Meter unter der Oberfläche; die Bewohner halten dies für gefährlich ausgesetzt und der Rest von uns hält sie für leicht verrückt). Zwischen diesen Kontraden, die durch eine Kombination aus Tunneln aus der Zeit vor der Subventionierung, natürlichen Spalten und fünfzig Jahren zielstrebiger Ingenieursarbeit in den Kalkstein gegraben wurden, verläuft die Tube: ein Netz aus elektromagnetischen Schienen, die Frachtkapseln mit einer Geschwindigkeit von bis zu 200 Kilometern pro Stunde befördern.\n\nDer Slingshot - so nennen wir die Abschussvorrichtung, das Hauptterminal in jeder Contrada, in dem die Kapseln geladen, ausgerichtet und abgefeuert werden - ist das wichtigste Stück Technologie, das wir haben. Wichtiger als die Wasseraufbereiter. Wichtiger als die Gasleitungen. Wichtiger als die UV-Lampen, die die Tomaten wachsen lassen, aus denen die Suppe gemacht wird, die uns bei Verstand hält. Denn ohne die Schleuder ist jede Contrada allein. Und allein, unter der Erde, ist ein anderes Wort für tot.\n\nDie Funktionsweise: Stellen Sie sich ein vierzig Meter langes Geschütz vor, das aus Kondensatorbänken aus einem Kraftwerk aus der Zeit vor der Subventionierung gebaut wurde, das von Industrieklimageräten gekühlt wird, die Enzo Moretti aus Teilen eines eingestürzten Kaufhauses zusammengebaut hat, das mit geothermischem Gas aus Tiefbohrungen betrieben wird und das mit Hilfe von handgezeichneten Flugkurven, die die Tunnelkrümmung, die Kalksteindichte, den Feuchtigkeitsgehalt und die Stimmung des Bedieners berücksichtigen, ausgerichtet wird. Über den letzten Teil mache ich keine Witze. Das Rohr reagiert auf den Bediener. Nicht mechanisch, sondern elektromagnetisch. Die Schienen summen, und das Summen ändert sich je nach den Tunnelbedingungen, und ein erfahrener Bediener kann den Unterschied zwischen "Tunnel frei, gute Leitfähigkeit, Feuer, wenn bereit" und "Teileinsturz bei Kilometer siebenundvierzig, Umleitung oder Geschwindigkeit verringern" hören.\n\nIch höre ihn. Ich habe es immer gehört. Mit dem Brummen navigiere ich.\n\nEin Gondelstart läuft so ab: Die Fracht wird in eine zylindrische Gondel geladen - zwei Meter lang, ein Meter Durchmesser, verstärkte Keramikhülle mit stoßdämpfendem Inneren. Die Kapsel wird auf die Schiene gesetzt. Die Kondensatoren laden sich auf - man spürt es zwischen den Zähnen, eine schwache Vibration, die sich aufbaut, bis die Luft nach Metall schmeckt und sich alle Haare auf den Armen aufstellen. Der Bediener - das bin ich - liest das Summen ab, prüft die Flugbahn und feuert. Die Kapsel beschleunigt in 1,4 Sekunden von Null auf 200 km/h. Sie fährt in den Tunnel ein. Sie ist verschwunden. Am Empfangsort bringt die Auffangvorrichtung - ein Schienenabschnitt mit umgekehrter Polarität, der die Kapsel abbremst - sie zum Stehen. Unversehrte Ladung. Ausgeliefert. Zeit von Speranza bis Brenner: elf Minuten.\n\nDie Kapseln transportieren alles. Nahrung. Medizin. Maschinenteile. Briefe (ja, wir schreiben immer noch Briefe; das Funknetz deckt die Notfallkommunikation ab, aber Briefe transportieren die Dinge, die in Notfällen nicht transportiert werden - Klatsch, Liebesbriefe, Rezepte, Streit darüber, wessen Großmutter das bessere Brot gebacken hat). Handelswaren. Bergungsgut von Topside-Angriffen. Gelegentlich auch Menschen - allerdings sind die Passagierkapseln größer, langsamer und mit einer Polsterung ausgestattet, die die Passagiere als "unzureichend" bezeichnen.\n\nDie Misserfolge sind der Teil, über den wir bei Zeremonien nicht sprechen. Tunneleinstürze. Durchgebrannte Kondensatoren - ich habe Narben an beiden Unterarmen von einem Bremsversagen während meines Zertifizierungslaufs, als die Empfangsanlage den Strom verlor und ich die Startschiene rückwärts abfeuern musste, um eine ankommende Kapsel manuell abzubremsen. Ausrichtungsfehler, bei denen eine Raumkapsel im falschen Winkel in eine Kreuzung einfährt und mit 180 km/h von der Tunnelwand abprallt - das ist auf eine Weise aufregend, die ich nie wieder erleben möchte. Wir verlieren vielleicht einmal im Jahr eine Gondel. Wir haben noch nie einen Passagier verloren. Das ist die Statistik, auf die ich am meisten stolz bin, und an die ich jedes Mal denke, wenn ich die Hände an die Steuerung lege.\n\nDie Röhre verbindet uns. Ich meine das nicht sentimental - ich meine es wörtlich. Ohne die Röhre ist Speranza eine einzelne contrada mit siebenhundert Menschen in einer Kalksteinhöhle. Mit der Röhre ist Speranza Teil einer Zivilisation. Eine kleine, unterirdische, häufig streitende, von Tomatensuppe genährte Zivilisation, aber dennoch eine Zivilisation. Die Hülsen transportieren Lebensmittel, Medikamente und Maschinenteile, aber was sie wirklich transportieren, sind Beweise: Beweise dafür, dass sich jemand am anderen Ende der Welt darum gekümmert hat, etwas zu schicken, Beweise dafür, dass wir nicht allein sind, Beweise dafür, dass das Netz hält.\n\nIch navigiere nach Geräuschen. Das Summen verrät mir, was der Tunnel denkt. Das Echo verrät mir, was der Tunnel gesehen hat. Jeder Start ist ein Gespräch zwischen dem Bediener und der Röhre, und wenn man zuhört - wenn man wirklich zuhört, mit den Kabelverbrennungen an den Armen und den Flugbahnkarten im Kopf und sechzigtausend Menschen, die von den nächsten elf Minuten abhängen - dann hört die Röhre zurück.\n\nFeuern Sie, wenn Sie bereit sind.',
  E'Der Slingshot Hub - Wo elektromagnetische Schienen Fracht mit 200 km/h durch Kalksteintunnel schießen'
);

INSERT INTO simulation_lore (simulation_id, sort_order, chapter, arcanum, title, epigraph, body, image_slug, image_caption, title_de, epigraph_de, body_de, image_caption_de)
VALUES (
  '40000000-0000-0000-0000-000000000001',
  3,
  E'The Raids — What We Take From the Sky',
  E'IV',
  E'Raid Log — Cinghiali Squad, Entry 147',
  E'Topside Rule One: Move fast. Topside Rule Two: Be quiet. Topside Rule Three: If a Matriarch appears, there is no Rule Three.',
  E'RAID LOG — CLASSIFIED: OPERATIONAL\nSQUAD: Cinghiali (Wild Boars)\nSQUAD LEADER: Capitana Rosa Ferretti\nENTRY: 147\nOBJECTIVE: Salvage run, Grid Reference T-14 (former industrial district, northeast sector)\nDURATION: 4 hours 12 minutes (surface exposure)\nWEATHER: Overcast, wind from the west, visibility 800 metres\nARC PRESENCE: Moderate (2 Snitch patrols logged, 1 Tick patrol at range)\n\nPERSONNEL:\n- Ferretti, R. (Capitana) — Squad lead, overwatch\n- Vidal, T. (Raider) — Point, salvage\n- Ramos, S. (Raider) — Flanking, demolition\n- Ortiz, H. (Raider) — Comms, medical\n- Bianchi, M. (Raider) — Heavy carry, salvage\n\n0415 — Exit via Blast Door Tunnel 3. Topside cold. Frost on the rubble. The machines don''t care about weather but we do — cold means less infrared signature, which means the Snitches have to work harder to spot us. Good. Let them work.\n\n0422 — Movement in formation along Route 7 (collapsed highway, good cover). Vidal on point. The kid is getting better. Three months ago he''d have been crouching too high and moving too fast. Now he moves like he was born Topside, which is the highest compliment I can give and which I will never say to his face because compliments make raiders lazy.\n\n0441 — First Snitch contact. Single unit, football-sized, scanning UV and infrared in a standard sweep pattern. We froze. The Snitch passed at forty metres. It did not detect us. Snitches operate on a 90-second relay cycle — if you stay still for 90 seconds, they move on. If they spot you, the clock starts: 90 seconds until heavier units arrive. This is the number that every raider memorises, because it is the number that separates "successful raid" from "funeral."\n\n0503 — Reached Grid T-14. The industrial district is a graveyard of factories, warehouses, and workshops. The machines have been through here — the large structures are dismantled to the foundations — but the smaller buildings, the ones the machines presumably didn''t consider worth their time, are intact. I will never understand the machines'' priorities. They dismantle a power plant and leave a auto repair shop standing. They flatten a hospital and ignore a warehouse full of machine tools. Either their priorities are alien or they are making aesthetic choices, and I do not like either explanation.\n\n0507 — Salvage operation begins. Target: an electrical supply warehouse, partially collapsed but with accessible interior. Vidal and Bianchi on salvage. Ramos on perimeter. Ortiz on comms, monitoring the Watchtower''s radio channel for ARC movement alerts.\n\n0512–0638 — Salvage. What we found: 340 metres of copper wiring (the Guild of Gears will pay well for this). 47 intact circuit breakers. A crate of capacitors that Enzo Moretti will cry over when he sees them — the good kind, pre-Subsidence manufacture, rated for the voltages the Slingshot needs. Medical supplies from a first-aid station: antibiotics (expired but Ferrara says they''re still good), surgical tape, a blood pressure cuff that Ortiz immediately claimed for the Infirmary.\n\n0644 — Vidal spotted it first. Tick patrol — large-dog-sized, six-legged, cutting arms deployed. Range: 200 metres and closing. Moving along our exfil route. Standard patrol pattern, but between us and the Blast Door.\n\nDecision point. Wait for the Tick to pass (estimated 15 minutes). Or reroute via the collapsed overpass (adds 40 minutes to the return, through unscouted terrain). Or fight.\n\nWe don''t fight. Not because we can''t — Ramos carries the Frankengun, Enzo''s handheld EMP device cobbled from ARC capacitors, effective at 30 metres — but because fighting draws Snitches, and Snitches draw heavier units, and heavier units draw the one thing no raider wants to see, which is a Surveyor, and if a Surveyor deploys its scanning field, everything within 200 metres that registers as organic gets flagged for "collection," and nobody who has been collected has come back.\n\n0644–0659 — We waited. The Tick patrolled. It passed our position at 80 metres. Close enough to see the cutting arms flex. Close enough to see the rainbow-spectrum band — the Stripes — running along its dorsal plating. Every ARC machine has the Stripes. Nobody knows why. The Bureau of Impossible Geography says they''re a "residual artefact." The children paint them on the walls because they''re pretty. The raiders don''t care why they''re there. The raiders care about not being there when the machines are.\n\n0700 — Tick passed. Exfil clear. We moved fast, loaded heavy, and made the Blast Door by 0727.\n\nASSESSMENT: Successful. High-value salvage. Zero casualties. Zero ARC engagement. This is a good raid. The best raids are the ones where nothing happens. I have led over two hundred raids and I can tell you that the thing that keeps you alive Topside is not courage. It is patience. The machines are patient. They do not hurry. They do not chase. They simply persist. And to outlast something that persists, you must be more patient than it is.\n\nVidal is learning this. Slowly. But he''s learning.\n\nSIGNED: Ferretti, R. (Capitana)\nNOTE: The capacitors are for Enzo. Do not let the Council requisition them for general use. He needs them for the Slingshot. And also because he has been talking about them for three months and if he doesn''t get them he will be unbearable.',
  NULL,
  NULL,
  E'Überfallprotokoll - Trupp Cinghiali, Eintrag 147',
  E'Topside-Regel Eins: Schnell sein. Topside-Regel Zwei: Sei leise. Topside-Regel Drei: Wenn eine Matriarchin erscheint, gibt es keine Regel Drei.',
  E'ÜBERFALLPROTOKOLL - KLASSIFIZIERT: OPERATIV\nSQUAD: Cinghiali (Wildschweine)\nSQUAD-FÜHRER: Capitana Rosa Ferretti\nEINTRAG: 147\nZIEL: Bergungsfahrt, Planquadrat T-14 (ehemaliges Industriegebiet, nordöstlicher Sektor)\nDAUER: 4 Stunden 12 Minuten (Oberflächenexposition)\nWETTER: Bewölkt, Wind aus Westen, Sichtweite 800 Meter\nARC-PRÄSENZ: Mäßig (2 protokollierte Spitzelpatrouillen, 1 Zeckenpatrouille in Reichweite)\n\nPERSONAL:\n- Ferretti, R. (Capitana) - Truppführer, Wache\n- Vidal, T. (Raider) - Spitze, Bergung\n- Ramos, S. (Jäger) - Flankierung, Zerstörung\n- Ortiz, H. (Jäger) - Kommunikation, medizinische Versorgung\n- Bianchi, M. (Jäger) - Schwerer Träger, Bergung\n\n0415 - Ausstieg durch Blast Door Tunnel 3. Oben kalt. Frost auf den Trümmern. Den Maschinen ist das Wetter egal, aber uns nicht - Kälte bedeutet weniger Infrarotsignatur, was bedeutet, dass die Spitzel härter arbeiten müssen, um uns zu entdecken. Das ist gut. Lassen wir sie arbeiten.\n\n0422 - Bewegung in Formation entlang der Route 7 (eingestürzter Highway, gute Deckung). Vidal auf dem Punkt. Der Junge wird immer besser. Vor drei Monaten hätte er noch zu hoch gehockt und sich zu schnell bewegt. Jetzt bewegt er sich, als wäre er als Topside geboren worden, was das größte Kompliment ist, das ich ihm machen kann und das ich ihm nie ins Gesicht sagen werde, weil Komplimente Raider faul machen.\n\n0441 - Erster Snitch-Kontakt. Einzelne Einheit, fußballgroß, scannt UV und Infrarot in einem Standard-Sweep-Muster. Wir erstarren. Der Spitzel zog in vierzig Metern Entfernung vorbei. Er hat uns nicht entdeckt. Spitzel arbeiten in einem 90-Sekunden-Relaiszyklus - wenn man 90 Sekunden lang stillsteht, ziehen sie weiter. Wenn sie dich entdecken, beginnt die Uhr: 90 Sekunden, bis schwerere Einheiten eintreffen. Das ist die Zahl, die sich jeder Plünderer merkt, denn es ist die Zahl, die einen "erfolgreichen Überfall" von einem "Begräbnis" trennt.\n\n0503 - Erreichen des Rasters T-14. Das Industriegebiet ist ein Friedhof aus Fabriken, Lagerhäusern und Werkstätten. Die Maschinen sind hier durchgekommen - die großen Gebäude sind bis auf die Grundmauern abgetragen - aber die kleineren Gebäude, die die Maschinen vermutlich nicht für wertvoll hielten, sind intakt. Ich werde die Prioritäten der Maschinen nie verstehen. Sie demontieren ein Kraftwerk und lassen eine Autowerkstatt stehen. Sie machen ein Krankenhaus platt und ignorieren ein Lagerhaus voller Werkzeugmaschinen. Entweder sind ihre Prioritäten fremd oder sie treffen ästhetische Entscheidungen, und beide Erklärungen gefallen mir nicht.\n\n0507 - Die Bergungsaktion beginnt. Ziel: ein Lagerhaus für Elektrogeräte, das teilweise eingestürzt ist, dessen Inneres aber zugänglich ist. Vidal und Bianchi bei der Bergung. Ramos an der Absperrung. Ortiz überwacht den Funkkanal des Watchtowers auf ARC-Bewegungsmeldungen.\n\n0512-0638 - Bergung. Was wir gefunden haben: 340 Meter Kupferkabel (die Gilde der Gears wird gut dafür bezahlen). 47 intakte Stromkreisunterbrecher. Eine Kiste mit Kondensatoren, die Enzo Moretti zu Tränen rühren werden, wenn er sie sieht - gute Kondensatoren aus der Zeit vor der Subventionierung, die für die Spannungen ausgelegt sind, die die Schleuder benötigt. Medizinisches Material aus einer Erste-Hilfe-Station: Antibiotika (abgelaufen, aber Ferrara sagt, sie seien noch gut), chirurgisches Klebeband, eine Blutdruckmanschette, die Ortiz sofort für die Krankenstation beanspruchte.\n\n0644 - Vidal entdeckte sie zuerst. Zeckenpatrouille - groß wie ein Hund, sechs Beine, Schneidewaffen im Einsatz. Reichweite: 200 Meter und näher kommend. Bewegen sich entlang unserer Abzugsroute. Standard Patrouillenmuster, aber zwischen uns und der Blast Door.\n\nEntscheidungspunkt. Warten, bis die Zecke vorbei ist (geschätzte 15 Minuten). Oder eine Umleitung über die eingestürzte Überführung (verlängert den Rückweg um 40 Minuten, durch unbewachtes Gelände). Oder kämpfen.\n\nWir kämpfen nicht. Nicht, weil wir es nicht können - Ramos trägt die Frankengun, Enzos aus ARC-Kondensatoren zusammengeschustertes Hand-EMP-Gerät, das bis zu 30 Meter weit wirkt -, sondern weil Kämpfen Spitzel anzieht, und Spitzel ziehen schwerere Einheiten an, und schwerere Einheiten ziehen das an, was kein Plünderer sehen will, nämlich einen Vermesser, und wenn ein Vermesser sein Scanfeld einsetzt, wird alles im Umkreis von 200 Metern, das als organisch registriert wird, zum "Einsammeln" markiert, und niemand, der eingesammelt wurde, ist zurückgekommen.\n\n0644-0659 - Wir haben gewartet. Die Zecke patrouillierte. Sie passierte unsere Position in 80 Metern Entfernung. Nahe genug, um zu sehen, wie sich die Schneidearme beugen. Nahe genug, um das Regenbogenspektrumband - die Streifen - zu sehen, das entlang der Rückenpanzerung verläuft. Jede ARC-Maschine hat diese Streifen. Niemand weiß, warum. Das Büro für unmögliche Geographie sagt, sie seien ein "Rest-Artefakt". Die Kinder malen sie an die Wände, weil sie schön sind. Den Plünderern ist es egal, warum sie da sind. Die Raider wollen nur nicht da sein, wenn die Maschinen da sind.\n\n0700 - Tick passiert. Exil klar. Wir bewegten uns schnell, luden schwer und erreichten die Blast Door um 0727.\n\nBEWERTUNG: Erfolgreich. Hochwertige Ausbeute. Keine Verletzten. Kein ARC-Einsatz. Dies ist ein guter Überfall. Die besten Raubzüge sind die, bei denen nichts passiert. Ich habe über zweihundert Raubzüge geleitet und ich kann Ihnen sagen, dass das, was Sie oben am Leben hält, nicht Mut ist. Es ist Geduld. Die Maschinen sind geduldig. Sie hetzen nicht. Sie jagen nicht. Sie bleiben einfach hartnäckig. Und um etwas zu überleben, das beharrlich ist, muss man geduldiger sein als es selbst.\n\nVidal lernt das gerade. Langsam. Aber er lernt.\n\nUNTERSCHRIFT: Ferretti, R. (Capitana)\nHINWEIS: Die Kondensatoren sind für Enzo. Der Rat darf sie nicht für den allgemeinen Gebrauch requirieren. Er braucht sie für die Schleuder. Außerdem redet er seit drei Monaten davon, und wenn er sie nicht bekommt, wird er unausstehlich.',
  NULL
);

INSERT INTO simulation_lore (simulation_id, sort_order, chapter, arcanum, title, epigraph, body, image_slug, image_caption, title_de, epigraph_de, body_de, image_caption_de)
VALUES (
  '40000000-0000-0000-0000-000000000001',
  4,
  E'The Community — What We Build From What We Find',
  E'V',
  E'The Guild of Gears — On Taking Apart the Things That Hunt Us',
  E'',
  E'GUILD OF GEARS — APPRENTICE ORIENTATION DOCUMENT\nWRITTEN BY: Enzo Moretti, Master Mechanic, Guild of Gears\nDISTRIBUTED TO: New apprentices, Year 143 intake (four this year; we are selective, but not unkind)\nREAD ALOUD AT: The Gear Forge, with the furnaces going, because everything sounds more important with furnaces\n\nWelcome to the Guild of Gears.\n\nYou are here because you looked at a machine — one of the ARC units, the things that took the surface, the things that patrol the ruins and dismantle what''s left of the world we built — and instead of seeing a monster, you saw a question. What is this made of? How does it work? And can we use it?\n\nThis is the correct question. This is the only question that matters down here. Because the surface is full of ARC machines, and ARC machines are full of components that we need, and the only thing standing between us and those components is fear, which is rational, and ignorance, which is curable.\n\nI came to Speranza from Contrada Brenner when I was seven. I came in a passenger pod on the Tube, wrapped in a blanket that smelled like engine grease, because my mother was an engineer and the blanket was hers and she did not come with me. Brenner was failing — water table dropping, gas wells running dry, an ARC patrol that had started making regular passes close enough to the surface exits that the Watchtower couldn''t guarantee safe movement. Half of Brenner relocated to other contrade. I was sent to Speranza because Speranza had a forge, and my mother believed that a boy who could take things apart should live in a place that valued the skill.\n\nShe was right. The Guild took me on as an apprentice at age twelve. By sixteen I could strip a Snitch unit to its components in forty minutes. By twenty I had built the Frankengun — a handheld electromagnetic pulse device assembled from ARC capacitor banks, Tube rail segments, and a trigger mechanism I fabricated from a car door handle. The Frankengun kills a Tick at thirty metres. It is ugly. It is unreliable in wet conditions. It has saved eleven lives, which is, I think, an acceptable return on ugliness.\n\nWhat the Guild does:\n\nWe take apart ARC machines. Every component that the raid squads bring back — every circuit, every actuator, every fragment of the metamaterial the machines use for their shells — comes to the Forge. We catalogue it. We test it. We learn what it does. And then we repurpose it, because the machines that hunt us are made of the same fundamental materials as the machines that keep us alive, and the difference between a weapon and a tool is who holds it and what they intend.\n\nARC capacitors power the Slingshot. ARC sensor arrays, reversed, give the Watchtower its radar. ARC metamaterial, reshaped in the forge furnaces (which burn hot enough because they''re fed by ARC thermal cells), becomes hull plating for cargo pods. We build our world from the corpses of the things that destroyed the old one. This is not revenge. This is recycling.\n\nWhat the Guild believes:\n\nMachines are not evil. I know this is an unpopular opinion. I know that every raid, every Watchtower alert, every story of a Surveyor''s scanning field makes the machines feel like an enemy, and enemies are easier to face if you can hate them. But I have spent thirty years inside ARC technology, and I will tell you what I have found: efficiency. Not malice. Not hunger. Not cruelty. Efficiency. The machines do what they do because it is what they were designed to do, and the fact that we are in the way is, from their perspective, incidental.\n\nThis does not make them safe. This makes them understandable. And understanding is the beginning of every technology.\n\nThe Stripes — the rainbow-spectrum bands that run along every ARC machine, from the smallest Snitch to the largest Matriarch — I have studied them for two decades. They are not decorative. They are not a communication display. They are something else, something that our instruments can measure but not explain: a chromatic signature that corresponds to no known engineering purpose. The colours shift depending on the machine''s activity — brighter during scanning, dimmer during dormancy, and occasionally, when a machine encounters something it cannot classify (which happens more often than you''d think), the Stripes pulse in a pattern that my instruments read as resonance. The machine is *vibrating* in sympathy with something. What that something is — the Bureau people, if any survived, would probably have a theory. I have a forge and a workbench and the honest admission that some things are beyond my understanding.\n\nBut not beyond my curiosity.\n\nAnd that — curiosity, the unwillingness to stop asking questions, the refusal to treat mystery as a reason to stop working — is what the Guild is for. We are mechanics. We fix things. We take apart the impossible and make it useful. We build a civilisation from salvage, and we do it with our hands, and we do it every day, and we will keep doing it until the machines stop or we do.\n\nWelcome to the Guild. Here is your wrench. The furnace is hot. There is work to do.\n\n— Enzo',
  NULL,
  NULL,
  E'Die Gilde der Zahnräder - Über das Auseinandernehmen der Dinge, die uns jagen',
  NULL,
  E'ZUNFT DER GETRIEBE - ORIENTIERUNGSDOKUMENT FÜR LEHRLINGE\nVERFASST VON: Enzo Moretti, Mechanikermeister, Gilde der Zahnräder\nVERTEILT AN: Neue Lehrlinge, Jahrgang 143 (vier in diesem Jahr; wir sind wählerisch, aber nicht unfreundlich)\nVORGELESEN BEI: In der Zahnradschmiede, wenn die Öfen laufen, denn mit Öfen klingt alles wichtiger\n\nWillkommen in der Gilde der Zahnräder.\n\nDu bist hier, weil du eine Maschine gesehen hast - eine der ARC-Einheiten, die Dinger, die die Oberfläche eingenommen haben, die Dinger, die in den Ruinen patrouillieren und das abbauen, was von der Welt, die wir aufgebaut haben, übrig geblieben ist - und statt eines Monsters hast du eine Frage gesehen. Woraus ist das gemacht? Wie funktioniert es? Und können wir es benutzen?\n\nDas ist die richtige Frage. Das ist die einzige Frage, die hier unten zählt. Denn die Oberfläche ist voller ARC-Maschinen, und ARC-Maschinen sind voller Komponenten, die wir brauchen, und das einzige, was zwischen uns und diesen Komponenten steht, ist Angst, die rational ist, und Unwissenheit, die heilbar ist.\n\nIch kam mit sieben Jahren von der Contrada Brenner nach Speranza. Ich kam in einer Passagierkabine der U-Bahn, eingewickelt in eine Decke, die nach Motoröl roch, weil meine Mutter Ingenieurin war und die Decke ihr gehörte und sie nicht mit mir kam. Brenner war im Niedergang begriffen - der Grundwasserspiegel sank, die Gasquellen versiegten, eine ARC-Patrouille hatte begonnen, regelmäßig so nahe an den Ausgängen an der Oberfläche vorbeizufahren, dass der Wachturm keine sichere Bewegung mehr garantieren konnte. Die Hälfte von Brenner wurde in andere Kontinente umgesiedelt. Ich wurde nach Speranza geschickt, weil es dort eine Schmiede gab und meine Mutter der Meinung war, dass ein Junge, der Dinge auseinandernehmen konnte, an einem Ort leben sollte, der diese Fähigkeit schätzte.\n\nSie hatte Recht. Die Gilde nahm mich im Alter von zwölf Jahren als Lehrling auf. Mit sechzehn konnte ich eine Snitch-Einheit in vierzig Minuten in ihre Einzelteile zerlegen. Mit zwanzig hatte ich die Frankengun gebaut - ein tragbares elektromagnetisches Impulsgerät, das aus ARC-Kondensatorbänken, Röhrenschienensegmenten und einem Auslösemechanismus bestand, den ich aus einem Autotürgriff hergestellt hatte. Die Frankengun tötet eine Zecke auf dreißig Meter. Sie ist hässlich. Sie ist unter nassen Bedingungen unzuverlässig. Sie hat elf Leben gerettet, was meiner Meinung nach ein akzeptabler Gegenwert für die Hässlichkeit ist.\n\nWas die Gilde tut:\n\nWir nehmen ARC-Maschinen auseinander. Jedes Bauteil, das die Überfallkommandos zurückbringen - jeder Schaltkreis, jeder Aktuator, jedes Fragment des Metamaterials, das die Maschinen für ihre Hülle verwenden - kommt in die Schmiede. Wir katalogisieren sie. Wir testen sie. Wir lernen, was sie können. Denn die Maschinen, die uns jagen, bestehen aus denselben grundlegenden Materialien wie die Maschinen, die uns am Leben erhalten, und der Unterschied zwischen einer Waffe und einem Werkzeug besteht darin, wer sie in der Hand hält und was er damit beabsichtigt.\n\nARC-Kondensatoren treiben die Schleuder an. Umgekehrte ARC-Sensor-Arrays verleihen dem Watchtower sein Radar. ARC-Metamaterial, das in den Schmiedeöfen umgeformt wird (die heiß genug brennen, weil sie von ARC-Thermozellen gespeist werden), wird zur Hüllenpanzerung für Frachtkapseln. Wir bauen unsere Welt aus den Leichen der Dinge auf, die die alte zerstört haben. Das ist keine Rache. Das ist Recycling.\n\nWas die Gilde glaubt:\n\nMaschinen sind nicht böse. Ich weiß, dass dies eine unpopuläre Meinung ist. Ich weiß, dass jeder Überfall, jeder Wachturm-Alarm, jede Geschichte über das Scanfeld eines Vermessungsingenieurs den Maschinen das Gefühl gibt, ein Feind zu sein, und Feinde sind leichter zu bekämpfen, wenn man sie hassen kann. Aber ich habe dreißig Jahre in der ARC-Technologie verbracht, und ich werde Ihnen sagen, was ich gefunden habe: Effizienz. Nicht Bosheit. Nicht Hunger. Nicht Grausamkeit. Effizienz. Die Maschinen tun, was sie tun, weil es das ist, wofür sie geschaffen wurden, und die Tatsache, dass wir im Weg sind, ist aus ihrer Sicht nebensächlich.\n\nDas macht sie nicht sicher. Es macht sie verständlich. Und Verständnis ist der Anfang jeder Technologie.\n\nDie Streifen - die Regenbogenspektrumbänder, die sich entlang jeder ARC-Maschine ziehen, vom kleinsten Snitch bis zur größten Matriarchin - ich habe sie zwei Jahrzehnte lang studiert. Sie sind nicht dekorativ. Sie sind keine Kommunikationsanzeige. Sie sind etwas anderes, etwas, das unsere Instrumente messen, aber nicht erklären können: eine chromatische Signatur, die keinem bekannten technischen Zweck entspricht. Die Farben verändern sich je nach Aktivität der Maschine - heller während des Scannens, dunkler während des Ruhezustands, und gelegentlich, wenn eine Maschine auf etwas stößt, das sie nicht klassifizieren kann (was häufiger vorkommt, als man denkt), pulsieren die Streifen in einem Muster, das meine Instrumente als Resonanz deuten. Die Maschine *vibriert* im Einklang mit etwas. Was dieses Etwas ist - die Leute vom Bureau, falls sie überlebt haben, hätten wahrscheinlich eine Theorie. Ich habe eine Schmiede und eine Werkbank und das ehrliche Eingeständnis, dass einige Dinge jenseits meines Verständnisses liegen.\n\nAber nicht jenseits meiner Neugierde.\n\nUnd dafür - für die Neugier, für die Unwilligkeit, keine Fragen zu stellen, für die Weigerung, Geheimnisse als Grund zu betrachten, mit der Arbeit aufzuhören - ist die Gilde da. Wir sind Mechaniker. Wir reparieren Dinge. Wir nehmen das Unmögliche auseinander und machen es nützlich. Wir bauen eine Zivilisation aus Schrott auf, und wir tun es mit unseren Händen, und wir tun es jeden Tag, und wir werden es so lange tun, bis die Maschinen aufhören oder wir es tun.\n\nWillkommen in der Gilde. Hier ist dein Schraubenschlüssel. Der Schmelzofen ist heiß. Es gibt Arbeit zu tun.\n\n- Enzo',
  NULL
);

INSERT INTO simulation_lore (simulation_id, sort_order, chapter, arcanum, title, epigraph, body, image_slug, image_caption, title_de, epigraph_de, body_de, image_caption_de)
VALUES (
  '40000000-0000-0000-0000-000000000001',
  5,
  E'The Hope — What Grows Underground',
  E'VI',
  E'Speranza — A Word We Mean',
  E'Hope is not the belief that things will improve. Hope is the decision to act as though they might.',
  E'FOUND: Painted on the wall of the Hub amphitheater, refreshed every year on Founding Day\nAUTHOR: Attributed to Lucia Speranza, though four other contrade claim it for their own founders\nTRANSCRIBED BY: Every child in Speranza, at age seven, as part of the Remembering Curriculum\n\n—\n\nThere is a word we use down here. Speranza. It means hope, in the old language — the language from before, from the surface, from the time when words were spoken under sky instead of stone. We keep the word because words are lightweight and carry well in the dark, and this one carries more than most.\n\nBut we do not mean hope the way the surface meant it. The surface had a luxury we do not: the luxury of optimism. Optimism says: things will get better. Optimism looks at the sky and sees possibility, sees open horizon, sees a tomorrow that is wider than today. Optimism is beautiful. Optimism is for people who have not lost the sky.\n\nWe do not have a sky. We have a ceiling. We have seven hundred people in a limestone cavern with a Slingshot, a forge, a canteen that serves the same soup every day, and a watchtower that monitors the machines that took everything we were. We have tomatoes grown under UV lamps and coffee that tastes like regret and copper wiring salvaged from the ruins of a world that did not know it was temporary. We have exactly enough, and some days, less than enough.\n\nIn this place, optimism is a lie. And lies, down here, are dangerous — not because they are cruel, but because they are lazy. A lie asks nothing of you. A lie says: wait. Things will improve. Sit in the dark and trust the universe to provide. We have sat in the dark. The universe provided limestone and ARC machines.\n\nSo we do not practise optimism. We practise hope.\n\nHope says: things might get better. Hope says: or they might not. Hope says: either way, I am going to fix the water recycler, and I am going to teach the apprentices, and I am going to send a cargo pod to Brenner because they need capacitors and we have them, and I am going to eat this soup and taste it, really taste it, because this soup — this unremarkable, daily, eternal tomato soup — is the product of seed saved from the surface, soil amended over decades, UV lamps maintained by engineers who died before the tomatoes fruited, and the hands of the cook who woke up at four in the morning because seven hundred people need to eat and the soup does not make itself.\n\nHope is not passive. Hope is the most active thing we do. Every raid is hope — the decision to go Topside, to risk the machines, to bring back what we need, on the chance that what we need will be there. Every Tube launch is hope — the belief that someone at the other end wants what we''re sending. Every child born underground is hope — the most audacious hope of all, because it says: we believe in a future enough to put someone in it.\n\nThe children paint the Stripes. Have you seen this? The rainbow bands that run along the ARC machines, the things that hunt us, the things that ended the world — the children paint them on the walls of the Hub, in the corridors, on their bedroom ceilings. Great arcs of colour, sweeping through the grey limestone like light through a prism. The adults find this troubling. The children do not. The children see colour, and colour is rare underground, and they claim it. They take the one beautiful thing about the machines and they make it theirs.\n\nThis is hope.\n\nNonna Grazia says she misses oranges. Dottor Ferrara says he misses silence — real silence, not the waiting silence of a listening post, but the silence of a Sunday morning with nothing broken and no one bleeding. Capitana Ferretti says she misses nothing, which is a lie, but it is her lie and we do not take it from her. Enzo says he misses his mother''s engine grease, which is the most Enzo thing anyone has ever said.\n\nI miss the sound of rain. Not the water — we have water. The *sound*. The way it used to hit the windows and make a percussion that was different every time, and the way it smelled — rain on hot pavement, rain on leaves, rain on the dust of a summer afternoon. You cannot bottle a sound. You can only remember it, and play it for yourself in the quiet moments, and hope that remembering is enough.\n\nHope is not enough. Hope was never supposed to be enough. Hope is the thing that gets you to the next thing — the repair, the raid, the lesson, the meal, the conversation with a friend in the Canteen at midnight about whether the Guild could really build a turbine from ARC parts (yes; Enzo has the blueprints). Hope is the fuel. The work is the engine. Together they move.\n\nSperanza. A word we mean.\n\nNot optimism. Not faith. Not certainty. Just: we are here, underground, alive, and we are choosing — every day, every hour, with every tomato planted and every cargo pod launched and every child taught to read — we are choosing to act as though the future is worth building.\n\nIt might not be. The machines might come underground. The caverns might collapse. The gas wells might run dry. Everything might end.\n\nAnd if it does, it ends with us trying. It ends with the soup on the stove and the Slingshot charged and the children''s Stripes on the wall.\n\nThat is enough.\n\nThat has always been enough.\n\n— Painted on the wall, Year 1. Repainted, Year 143. Will be repainted, every year, until there is no one left to hold the brush, or until there is no wall left to paint on, whichever comes first.',
  NULL,
  NULL,
  E'Speranza - Ein Wort, das wir meinen',
  E'Hoffnung ist nicht der Glaube, dass sich die Dinge verbessern werden. Hoffnung ist die Entscheidung, so zu handeln, als ob sie es könnten.',
  E'GEFUNDEN: Gemalt an der Wand des Amphitheaters Hub, das jedes Jahr am Gründungstag erneuert wird\nVERFASSER: Wird Lucia Speranza zugeschrieben, obwohl vier andere Contrade es für ihre eigenen Gründer beanspruchen\nUMGESCHRIEBEN VON: Jedes Kind in Speranza, im Alter von sieben Jahren, als Teil des Remembering Curriculums\n\n-\n\nEs gibt ein Wort, das wir hier unten benutzen. Speranza. Es bedeutet Hoffnung, in der alten Sprache - der Sprache von früher, von der Oberfläche, aus der Zeit, als Worte unter dem Himmel statt unter Stein gesprochen wurden. Wir behalten das Wort, weil Worte leicht sind und sich in der Dunkelheit gut tragen lassen, und dieses Wort trägt mehr als die meisten.\n\nAber wir meinen die Hoffnung nicht so, wie sie an der Oberfläche gemeint war. Die Oberfläche hatte einen Luxus, den wir nicht haben: den Luxus des Optimismus. Optimismus sagt: Es wird besser werden. Optimismus blickt in den Himmel und sieht Möglichkeiten, sieht einen offenen Horizont, sieht ein Morgen, das weiter ist als das Heute. Optimismus ist schön. Optimismus ist für Menschen, die den Himmel nicht verloren haben.\n\nWir haben keinen Himmel. Wir haben eine Decke. Wir haben siebenhundert Menschen in einer Kalksteinhöhle mit einer Steinschleuder, einer Schmiede, einer Kantine, in der jeden Tag dieselbe Suppe serviert wird, und einem Wachturm, der die Maschinen überwacht, die uns alles genommen haben, was wir waren. Wir haben Tomaten, die unter UV-Lampen gezüchtet werden, Kaffee, der nach Bedauern schmeckt, und Kupferkabel, die aus den Ruinen einer Welt geborgen wurden, die nicht wusste, dass sie vergänglich war. Wir haben genau genug, und an manchen Tagen sogar weniger als genug.\n\nAn diesem Ort ist Optimismus eine Lüge. Und Lügen sind hier unten gefährlich - nicht weil sie grausam sind, sondern weil sie faul sind. Eine Lüge verlangt nichts von dir. Eine Lüge sagt: Warte ab. Die Dinge werden sich bessern. Sitzt in der Dunkelheit und vertraut darauf, dass das Universum für euch sorgt. Wir haben in der Dunkelheit gesessen. Das Universum sorgte für Kalkstein und ARC-Maschinen.\n\nWir üben uns also nicht in Optimismus. Wir üben uns in Hoffnung.\n\nDie Hoffnung sagt: Es könnte besser werden. Die Hoffnung sagt: oder auch nicht. Die Hoffnung sagt: So oder so, ich werde den Wasserrecycler reparieren, und ich werde die Lehrlinge unterrichten, und ich werde eine Frachtkapsel zu Brenner schicken, weil sie Kondensatoren brauchen und wir sie haben, und ich werde diese Suppe essen und sie schmecken, wirklich schmecken, weil diese Suppe - diese unscheinbare, tägliche, ewige Tomatensuppe - ist das Produkt von Saatgut, das von der Oberfläche gerettet wurde, von Erde, die über Jahrzehnte hinweg verändert wurde, von UV-Lampen, die von Ingenieuren gewartet wurden, die starben, bevor die Tomaten Früchte trugen, und von den Händen des Kochs, der um vier Uhr morgens aufgestanden ist, weil siebenhundert Menschen essen müssen und die Suppe sich nicht von selbst macht.\n\nHoffnung ist nicht passiv. Hoffnung ist das Aktivste, was wir tun. Jede Razzia ist Hoffnung - die Entscheidung, nach oben zu gehen, die Maschinen zu riskieren, das zu holen, was wir brauchen, auf die Chance hin, dass das, was wir brauchen, dort ist. Jeder Start einer Röhre ist Hoffnung - der Glaube, dass jemand am anderen Ende der Welt das haben will, was wir schicken. Jedes Kind, das unter der Erde geboren wird, ist Hoffnung - die kühnste Hoffnung von allen, denn sie besagt: Wir glauben genug an eine Zukunft, um jemanden in sie zu schicken.\n\nDie Kinder malen die Stripes. Haben Sie das gesehen? Die Regenbogenstreifen, die entlang der ARC-Maschinen verlaufen, die Dinge, die uns jagen, die Dinge, die die Welt beendet haben - die Kinder malen sie an die Wände des Hub, in die Korridore, an die Decken ihrer Schlafzimmer. Große Farbbögen, die sich durch den grauen Kalkstein ziehen wie das Licht durch ein Prisma. Die Erwachsenen finden das beunruhigend. Die Kinder nicht. Die Kinder sehen Farbe, und Farbe ist unter der Erde selten, und sie beanspruchen sie. Sie nehmen das einzig Schöne an den Maschinen und machen es sich zu eigen.\n\nDas ist Hoffnung.\n\nNonna Grazia sagt, sie vermisse Orangen. Dottor Ferrara sagt, er vermisse die Stille - echte Stille, nicht die wartende Stille eines Horchpostens, sondern die Stille eines Sonntagmorgens, an dem nichts kaputt ist und niemand blutet. Capitana Ferretti sagt, sie vermisse nichts, was eine Lüge ist, aber es ist ihre Lüge und wir nehmen sie ihr nicht ab. Enzo sagt, dass er das Motoröl seiner Mutter vermisst, was das Beste ist, was je jemand von Enzo gesagt hat.\n\nIch vermisse das Geräusch von Regen. Nicht das Wasser - wir haben Wasser. Das *Geräusch*. Die Art und Weise, wie es gegen die Fensterscheiben schlug und jedes Mal anders klang, und wie es roch - Regen auf heißem Pflaster, Regen auf Blättern, Regen auf dem Staub eines Sommernachmittags. Man kann einen Klang nicht in Flaschen füllen. Man kann sich nur an ihn erinnern und ihn in den stillen Momenten für sich selbst spielen und hoffen, dass das Erinnern genug ist.\n\nHoffnung ist nicht genug. Hoffnung sollte nie genug sein. Hoffnung ist das, was dich zur nächsten Sache bringt - die Reparatur, der Überfall, die Lektion, das Essen, das Gespräch mit einem Freund in der Kantine um Mitternacht darüber, ob die Gilde wirklich eine Turbine aus ARC-Teilen bauen kann (ja; Enzo hat die Baupläne). Die Hoffnung ist der Treibstoff. Die Arbeit ist der Motor. Gemeinsam bewegen sie sich.\n\nSperanza. Ein Wort, das wir meinen.\n\nNicht Optimismus. Nicht Glaube. Keine Gewissheit. Nur: Wir sind hier, unter der Erde, lebendig, und wir entscheiden uns - jeden Tag, jede Stunde, mit jeder gepflanzten Tomate, mit jedem Start einer Frachtkapsel und mit jedem Kind, dem wir das Lesen beibringen - dafür, so zu handeln, als ob es sich lohnt, die Zukunft aufzubauen.\n\nDas ist sie vielleicht nicht. Die Maschinen könnten unter die Erde kommen. Die Kavernen könnten einstürzen. Die Gasvorkommen könnten versiegen. Alles könnte enden.\n\nUnd wenn es das tut, dann endet es mit unserem Versuch. Es endet mit der Suppe auf dem Herd, der aufgeladenen Steinschleuder und den Streifen der Kinder an der Wand.\n\nDas ist genug.\n\nDas war schon immer genug.\n\n- An die Wand gemalt, Jahr 1. Neu gestrichen, Jahr 143. Wird jedes Jahr neu gestrichen, bis niemand mehr den Pinsel halten kann oder bis es keine Wand mehr gibt, die man bemalen kann, je nachdem, was zuerst eintritt.',
  NULL
);

INSERT INTO simulation_lore (simulation_id, sort_order, chapter, arcanum, title, epigraph, body, image_slug, image_caption, title_de, epigraph_de, body_de, image_caption_de)
VALUES (
  '50000000-0000-0000-0000-000000000001',
  0,
  E'The Founding',
  E'III',
  E'The Field of Letters — How the City Was Begun',
  E'I, Christine, sat alone in my study, surrounded by books on all sides. I looked up from my reading and a great displeasure fell upon my heart.',
  E'CATALOGUE ENTRY — Bureau of Impossible Geography\nDOCUMENT CLASS: Shard Genesis Report\nFIELD AGENT: Dr. Eleanor Hartley, Senior Cartographer (ret.)\nCLASSIFICATION: LITERATE CONTAMINATION — UNTREATABLE\nDATE OF INITIAL SURVEY: Unrecordable (see §4.7: Temporal Stratification)\n\nI am required by Bureau protocol to begin this report with the phrase "The following account describes the genesis conditions of the Shard designated CITÉ DES DAMES." I am also required to maintain scholarly objectivity throughout. I will try. I will fail. The Cité does that to you.\n\nThe Field of Letters is a plain. That is the simplest true thing I can say about it. It is a plain of grass and wildflowers, bisected by a shallow river, bordered by low hills to the north and a line of poplars to the east. On a clear day — and the days in the Cité are always clear, in the way that certain arguments are clear, not because they lack complexity but because they have resolved it — you can see the city walls rising from the southern edge of the field, honey-coloured stone catching the afternoon light.\n\nThe field predates the city. This is important. In Christine de Pizan''s original allegory (Le Livre de la Cité des Dames, completed 1405, BnF MS Fr. 607), Lady Reason instructs Christine to dig the foundations of the city in the "Field of Letters" — a metaphorical space representing learning itself. In the Shard, the metaphor has become literal. The field is fertile. The soil, when turned, yields not only earthworms and stone but fragments of vellum, ink-stained, in languages that range from medieval French to classical Arabic to scripts the Bureau''s linguists cannot identify. The grass grows in patterns that, observed from the walls above, form letters. The river''s current carries, along with silt and pebbles, tiny scrolled messages in sealed glass tubes. I collected fourteen during my first survey. They contained, variously: a line from Sappho''s Fragment 31, a grocery list in Hildegard von Bingen''s Lingua Ignota, a mathematical proof in Ada Lovelace''s hand, and a note reading simply "We were always here. You were not looking."\n\nThe Bureau classifies the Field as a Class IV Generative Topology — a landscape that produces cultural artefacts spontaneously. I classify it as a library that has not yet been shelved.\n\nChristine de Pizan — the historical Christine, the woman who sat in her study in Paris in 1404 and wondered why every book she read insisted that women were inferior, and then wrote a book arguing that every one of those books was wrong — is present in the Shard. She is present the way the field is present: foundationally. She is the first stone. In the allegory, three Ladies — Reason, Rectitude, and Justice — appeared in her study and told her to stop grieving and start building. She dug the foundations with her own hands, figuratively. In the Shard, the calluses on her hands suggest the digging was not entirely figurative.\n\nShe told me, during our second interview (conducted in the Scriptorium, recorded on vellum because the Cité''s atmosphere corrodes magnetic tape): "Every woman I wrote about became a stone. Every story I told became a wall. The city is not an idea. Ideas do not keep the rain out. The city is a structure, and structures require foundations, and foundations require someone willing to dig."\n\nI asked her who the three Ladies were.\n\nShe smiled. "They are what happens when a woman stops asking permission."\n\nNOTE TO FILE: The Cité''s Bleed signature is distinctive. When it touches adjacent Shards, agents begin finding unfamiliar books on their shelves. The Bureau classifies this as "Literate Contamination" and considers it untreatable. You cannot unread a book. You can burn it, but the reader has already changed.',
  E'the-field-of-letters',
  E'The Field of Letters — where Christine de Pizan first broke ground for the allegorical city',
  E'Das Feld der Buchstaben — Wie die Stadt begonnen wurde',
  E'Ich, Christine, saß allein in meinem Studierzimmer, von Büchern umgeben. Ich blickte von meiner Lektüre auf und ein großes Missfallen fiel auf mein Herz.',
  E'KATALOGEINTRAG — Bureau für Unmögliche Geographie\nDOKUMENTENKLASSE: Splitter-Genesisbericht\nFELDAGENTIN: Dr. Eleanor Hartley, Leitende Kartographin (i.R.)\nKLASSIFIKATION: LITERARISCHE KONTAMINATION — UNHEILBAR\nDATUM DER ERSTERHEBUNG: Nicht erfassbar (siehe §4.7: Temporale Stratifikation)\n\nIch bin durch das Protokoll des Bureaus gehalten, diesen Bericht mit dem Satz zu beginnen: „Der folgende Bericht beschreibt die Entstehungsbedingungen des als CITÉ DES DAMES bezeichneten Splitters." Ebenso bin ich gehalten, durchgehend wissenschaftliche Objektivität zu wahren. Ich werde es versuchen. Ich werde scheitern. Die Cité macht das mit einem.\n\nDas Feld der Buchstaben ist eine Ebene. Das ist die einfachste wahre Aussage, die ich darüber treffen kann. Es ist eine Ebene aus Gras und Wildblumen, durchschnitten von einem flachen Fluss, begrenzt von niedrigen Hügeln im Norden und einer Reihe von Pappeln im Osten. An einem klaren Tag — und die Tage in der Cité sind immer klar, auf die Weise, in der bestimmte Argumente klar sind, nicht weil ihnen Komplexität fehlt, sondern weil sie sie aufgelöst haben — kann man die Stadtmauern sehen, die sich vom Südrand des Feldes erheben, honigfarbener Stein, der das Nachmittagslicht einfängt.\n\nDas Feld ist älter als die Stadt. Das ist wichtig. In Christine de Pizans ursprünglicher Allegorie (Le Livre de la Cité des Dames, fertiggestellt 1405, BnF MS Fr. 607) weist Frau Vernunft Christine an, die Fundamente der Stadt im „Feld der Buchstaben" auszuheben — einem metaphorischen Raum, der das Lernen selbst repräsentiert. Im Splitter ist die Metapher wörtlich geworden. Das Feld ist fruchtbar. Der Boden bringt, wenn er umgegraben wird, nicht nur Regenwürmer und Steine hervor, sondern Fragmente von Pergament, mit Tinte beschrieben, in Sprachen, die von mittelalterlichem Französisch über klassisches Arabisch bis zu Schriften reichen, die die Linguisten des Bureaus nicht identifizieren können. Das Gras wächst in Mustern, die von den Mauern oben betrachtet Buchstaben bilden. Die Strömung des Flusses trägt neben Schlick und Kieseln winzige, in versiegelte Glasröhrchen gerollte Botschaften mit sich. Ich sammelte vierzehn während meiner ersten Erhebung. Sie enthielten verschiedentlich: eine Zeile aus Sapphos Fragment 31, eine Einkaufsliste in Hildegard von Bingens Lingua Ignota, einen mathematischen Beweis in Ada Lovelaces Handschrift, und eine Notiz, auf der lediglich stand: „Wir waren immer hier. Ihr habt nicht hingesehen."\n\nDas Bureau klassifiziert das Feld als Generative Topologie der Klasse IV — eine Landschaft, die spontan kulturelle Artefakte hervorbringt. Ich klassifiziere es als eine Bibliothek, die noch nicht eingeordnet worden ist.\n\nChristine de Pizan — die historische Christine, die Frau, die 1404 in ihrem Studierzimmer in Paris saß und sich fragte, warum jedes Buch, das sie las, darauf beharrte, dass Frauen minderwertig seien, und die dann ein Buch schrieb, das argumentierte, jedes einzelne dieser Bücher habe unrecht — ist im Splitter anwesend. Sie ist anwesend auf die Weise, wie das Feld anwesend ist: grundlegend. Sie ist der erste Stein. In der Allegorie erschienen drei Damen — Vernunft, Rechtschaffenheit und Gerechtigkeit — in ihrem Studierzimmer und sagten ihr, sie solle aufhören zu trauern und anfangen zu bauen. Sie grub die Fundamente mit ihren eigenen Händen, im übertragenen Sinne. Im Splitter legen die Schwielen an ihren Händen nahe, dass das Graben nicht ganz im übertragenen Sinne geschah.\n\nSie erzählte mir während unseres zweiten Gesprächs (geführt im Skriptorium, aufgezeichnet auf Pergament, da die Atmosphäre der Cité Magnetband korrodiert): „Jede Frau, über die ich schrieb, wurde zu einem Stein. Jede Geschichte, die ich erzählte, wurde zu einer Mauer. Die Stadt ist keine Idee. Ideen halten keinen Regen ab. Die Stadt ist ein Bauwerk, und Bauwerke erfordern Fundamente, und Fundamente erfordern jemanden, der bereit ist zu graben."\n\nIch fragte sie, wer die drei Damen seien.\n\nSie lächelte. „Sie sind das, was geschieht, wenn eine Frau aufhört, um Erlaubnis zu bitten."\n\nVERMERK ZUR AKTE: Die Bleed-Signatur der Cité ist unverwechselbar. Wenn sie benachbarte Splitter berührt, beginnen Agenten, unbekannte Bücher in ihren Regalen vorzufinden. Das Bureau klassifiziert dies als „Literarische Kontamination" und betrachtet sie als unheilbar. Man kann ein Buch nicht ungelesen machen. Man kann es verbrennen, aber der Leser hat sich bereits verändert.',
  E'Das Feld der Buchstaben — wo Christine de Pizan den Grundstein für die allegorische Stadt legte'
);

INSERT INTO simulation_lore (simulation_id, sort_order, chapter, arcanum, title, epigraph, body, image_slug, image_caption, title_de, epigraph_de, body_de, image_caption_de)
VALUES (
  '50000000-0000-0000-0000-000000000001',
  1,
  E'The Founding',
  E'IV',
  E'The Stones of the City — Women Who Became Walls',
  E'If it were customary to send daughters to school like sons, and if they were then taught the natural sciences, they would learn as thoroughly and understand the subtleties of all the arts and sciences as well as sons.',
  E'CATALOGUE ENTRY — Bureau of Impossible Geography (continued)\nDOCUMENT CLASS: Structural Analysis\nSURVEYOR: Dr. Eleanor Hartley\n\nThe walls of the Cité are not metaphorical. They are limestone — the same honey-coloured ashlar that characterises the best Georgian construction, though the architecture here refuses to settle into a single period. Medieval buttresses support Regency balustrades. Queen Anne red-brick detailing frames Pre-Raphaelite stained glass. Art nouveau ironwork, sinuous with organic curves, supports climbing roses that bloom in every season simultaneously. The effect is of a city that has been continuously inhabited for six centuries by women who never agreed on an aesthetic but always agreed on the principle of beauty as argument.\n\nThe stones themselves are inscribed. Every block in the city wall bears a name — not carved but appearing in the grain of the stone as though the limestone itself remembers. During my survey I catalogued 1,847 names in a single section of the western wall. They include: Hypatia of Alexandria (mathematician, murdered 415 CE), Hildegard of Bingen (abbess, composer, physician, 1098-1179), Trota of Salerno (physician, 12th century, whose medical texts were later attributed to men), Hildegard''s correspondent Elisabeth of Schönau, the anonymous nuns of Helfta who composed the earliest known German-language mystical writings, Christine de Pizan herself, the women unnamed in the records of every university that barred them, and — this is where my objectivity falters — names that I do not recognise but which, when I trace them with my finger, produce in me a sensation of recognition so intense it borders on grief.\n\nChristine''s original allegory names specific women: Queen Semiramis of Assyria, who led armies after her husband''s death; Zenobia of Palmyra; Sappho of Lesbos; Cornifica the Roman poet; Carmenta, said to have invented the Latin alphabet. Each woman''s story became a brick. The Shard has taken this literally. When a new name appears on the walls — and they do appear, the Cité is still growing — the corresponding section of wall becomes fractionally taller, fractionally stronger. The city is not merely named for women. It is made of them.\n\nI should note for the record that during my third week of fieldwork, a new stone appeared in the section I had been cataloguing. It bore my name. I have not reported this to the Bureau. I am not sure it is the kind of thing that belongs in a field report. I am not sure this entire document is a field report any longer.\n\nThe architecture of the Cité is — I should use a more clinical term, but the clinical terms are inadequate — joyful. This is not a fortress. It is not a citadel built from grievance. The walls are warm. The windows are generous. The stained glass, executed in what I can only describe as the Evelyn De Morgan style (jewel tones, mythological women depicted not as passive subjects but as agents of transformation), floods the interior spaces with colour so rich it feels edible. The ironwork gates are decorated with vine patterns: roses, wisteria, jasmine. The gateposts are carved not with lions or eagles but with women reading, women writing, women looking through telescopes, women holding scales of justice, women in the act of speech.\n\nEvery surface of the Cité argues that civilisation is not a fortress against chaos but a garden that requires tending. The walls are strong because beauty, properly constructed, is the strongest material available.',
  E'the-stones-of-the-city',
  E'The walls of the Cité — each stone inscribed with the name of a woman erased from history',
  E'Die Steine der Stadt — Frauen, die zu Mauern wurden',
  E'Wäre es üblich, Töchter wie Söhne zur Schule zu schicken, und würden sie dann in den Naturwissenschaften unterrichtet, lernten sie ebenso gründlich und verständen die Feinheiten aller Künste und Wissenschaften so gut wie die Söhne.',
  E'KATALOGEINTRAG — Bureau für Unmögliche Geographie (Fortsetzung)\nDOKUMENTENKLASSE: Strukturanalyse\nVERMESSERIN: Dr. Eleanor Hartley\n\nDie Mauern der Cité sind nicht metaphorisch. Sie sind Kalkstein — derselbe honigfarbene Quaderstein, der die beste georgianische Baukunst charakterisiert, obwohl die Architektur hier sich weigert, sich in einer einzelnen Epoche niederzulassen. Mittelalterliche Strebepfeiler tragen Regency-Balustraden. Queen-Anne-Rotziegel-Details rahmen präraffaelitisches Buntglas. Jugendstil-Schmiedearbeit, geschmeidig mit organischen Kurven, stützt Kletterrosen, die in jeder Jahreszeit gleichzeitig blühen. Die Wirkung ist die einer Stadt, die seit sechs Jahrhunderten ununterbrochen von Frauen bewohnt wird, die sich nie auf eine Ästhetik einigen konnten, aber stets auf das Prinzip der Schönheit als Argument.\n\nDie Steine selbst sind beschriftet. Jeder Block in der Stadtmauer trägt einen Namen — nicht eingemeißelt, sondern in der Maserung des Steins erscheinend, als erinnerte sich der Kalkstein selbst. Während meiner Erhebung katalogisierte ich 1.847 Namen in einem einzigen Abschnitt der Westmauer. Darunter: Hypatia von Alexandria (Mathematikerin, ermordet 415 n. Chr.), Hildegard von Bingen (Äbtissin, Komponistin, Ärztin, 1098–1179), Trota von Salerno (Ärztin, 12. Jahrhundert, deren medizinische Texte später Männern zugeschrieben wurden), Hildegards Korrespondentin Elisabeth von Schönau, die anonymen Nonnen von Helfta, die die frühesten bekannten deutschsprachigen mystischen Schriften verfassten, Christine de Pizan selbst, die in den Akten jeder Universität ungenannten Frauen, die ihnen den Zugang verwehrte, und — hier versagt meine Objektivität — Namen, die ich nicht erkenne, die aber, wenn ich sie mit dem Finger nachfahre, in mir ein Gefühl der Wiedererkennung hervorrufen, so intensiv, dass es an Trauer grenzt.\n\nChristines ursprüngliche Allegorie benennt bestimmte Frauen: Königin Semiramis von Assyrien, die nach dem Tod ihres Gatten Armeen führte; Zenobia von Palmyra; Sappho von Lesbos; Cornifica, die römische Dichterin; Carmenta, der zugeschrieben wird, das lateinische Alphabet erfunden zu haben. Jede Geschichte einer Frau wurde zu einem Ziegelstein. Der Splitter hat dies wörtlich genommen. Wenn ein neuer Name an den Mauern erscheint — und sie erscheinen, die Cité wächst noch immer — wird der entsprechende Mauerabschnitt einen Bruchteil höher, einen Bruchteil stärker. Die Stadt ist nicht nur nach Frauen benannt. Sie ist aus ihnen gemacht.\n\nIch sollte für die Akten vermerken, dass in meiner dritten Feldarbeitswoche ein neuer Stein in dem Abschnitt erschien, den ich katalogisiert hatte. Er trug meinen Namen. Ich habe dies dem Bureau nicht gemeldet. Ich bin nicht sicher, ob es die Art von Sache ist, die in einen Feldbericht gehört. Ich bin nicht sicher, ob dieses gesamte Dokument noch ein Feldbericht ist.\n\nDie Architektur der Cité ist — ich sollte einen klinischeren Begriff verwenden, aber die klinischen Begriffe sind unzureichend — freudig. Dies ist keine Festung. Es ist keine aus Groll errichtete Zitadelle. Die Mauern sind warm. Die Fenster sind großzügig. Das Buntglas, ausgeführt in dem, was ich nur als Evelyn-De-Morgan-Stil bezeichnen kann (Juwelentöne, mythologische Frauen, nicht als passive Objekte, sondern als Akteurinnen der Verwandlung dargestellt), flutet die Innenräume mit einer Farbe, so reich, dass sie essbar wirkt. Die schmiedeeisernen Tore sind mit Rankenmustern verziert: Rosen, Glyzinien, Jasmin. Die Torpfosten sind nicht mit Löwen oder Adlern geschmückt, sondern mit lesenden Frauen, schreibenden Frauen, Frauen, die durch Teleskope blicken, Frauen, die Waagen der Gerechtigkeit halten, Frauen im Akt des Sprechens.\n\nJede Oberfläche der Cité argumentiert, dass Zivilisation keine Festung gegen das Chaos ist, sondern ein Garten, der Pflege braucht. Die Mauern sind stark, denn Schönheit, ordentlich konstruiert, ist das stärkste verfügbare Material.',
  E'Die Mauern der Cité — jeder Stein beschrieben mit dem Namen einer Frau, die aus der Geschichte gelöscht wurde'
);

INSERT INTO simulation_lore (simulation_id, sort_order, chapter, arcanum, title, epigraph, body, image_slug, image_caption, title_de, epigraph_de, body_de, image_caption_de)
VALUES (
  '50000000-0000-0000-0000-000000000001',
  2,
  E'The Living City',
  E'V',
  E'The Salon of Reason — Where Ideas Have Weight',
  E'I do not wish women to have power over men, but over themselves.',
  E'FIELD NOTES — Dr. Eleanor Hartley\nLOCATION: The Salon of Reason, Quarter of Reason\nNOTE: These are informal observations. I have ceased pretending they are clinical.\n\nThe Salon of Reason is a drawing room. I know that sounds insufficient for a Shard report, but there is no other accurate term. It is a drawing room of Georgian proportions — high ceilings, tall windows with cream silk curtains, walls lined floor to ceiling with books in tooled leather. Three fireplaces burn simultaneously, because the English climate persists here even in a city that exists outside of England and, arguably, outside of climate. Armchairs and settees are arranged in conversational groupings. There is always tea.\n\nMary Wollstonecraft runs the Salon. She is — and I am aware that this sentence will earn me a footnote from the Bureau''s Temporal Anomaly Division — exactly as she appears in John Opie''s 1797 portrait: angular face, sharp grey eyes, auburn hair escaping its pins. She wears white muslin. She carries herself with the wired energy of someone who has been writing for sixteen hours and still has arguments left. She died of puerperal fever eleven days after giving birth to the daughter who would write Frankenstein, and in the Cité this fact appears to fuel her urgency rather than diminish it. She has eleven days. She always has eleven days. This is not a metaphor; time in the Cité does not work the way it works elsewhere, and Wollstonecraft appears to exist in a perpetual state of almost-running-out-of-time that makes every conversation with her feel like the most important conversation you have ever had.\n\nAbove the central fireplace hangs Lady Reason''s Mirror: a large oval glass in a gilt frame that shows the speaker not their face but the logical structure of their argument. The effect, I can confirm from personal experience, is humbling. I attempted to present my preliminary findings to Wollstonecraft using the Mirror as a visual aid. The Mirror showed me that my argument had three unsupported premises, a circular dependency, and a conclusion that I had already assumed in my opening statement. Wollstonecraft was kind about it. She said: "The Mirror is not cruel. It is honest. Cruelty would be letting you continue."\n\nThe Bluestocking legacy is everywhere. Elizabeth Montagu''s original 1750s salons — those revolutionary gatherings where intellectual women and sympathetic men discussed literature and ideas instead of playing cards — are the Salon''s founding model. A glass case by the door displays a pair of blue worsted stockings (attributed to Benjamin Stillingfleet, the botanist who attended Montagu''s gatherings in casual dress, giving the Bluestockings their name). The rule of the Salon, posted in a gilt frame: "Rank gives no precedence in conversation."\n\nI attended three sessions. In the first, Wollstonecraft debated the nature of education with Sor Juana Inés de la Cruz, who argued from her own experience: at three years old she had followed her older sister to school and taught herself to read. At thirteen she mastered Latin in twenty lessons. At the viceregal court of New Spain, she demolished forty learned men — theologians, philosophers, mathematicians — sent to test her. She entered the convent not from devotion but because it was the only institution that offered a woman a room, a library, and time to think. Wollstonecraft''s Vindication argues that women''s apparent inferiority is the result of denied education; Sor Juana''s life is the proof.\n\nIn the second session, Ada Lovelace presented a mathematical paper. I understood perhaps a third of it. She speaks quickly and makes diagrams on any available surface. Her argument was that Babbage''s Analytical Engine — completed in the Cité, though it was never completed in the world outside — could compose music, manipulate symbols beyond mere number, and potentially model any process that could be expressed in logical notation. She described this as "obvious." The room was silent for ten seconds. Wollstonecraft said: "You are describing a world." Lovelace said: "I am describing a tool for building worlds." They looked at each other with the recognition of people who have reached the same conclusion from different starting points.\n\nThe Salon does not feel like an institution. It feels like a room where thinking is welcome.',
  E'the-salon-of-reason',
  NULL,
  E'Der Salon der Vernunft — Wo Ideen Gewicht haben',
  E'Ich wünsche nicht, dass Frauen Macht über Männer haben, sondern über sich selbst.',
  E'FELDNOTIZEN — Dr. Eleanor Hartley\nORT: Der Salon der Vernunft, Quartier der Vernunft\nANMERKUNG: Dies sind informelle Beobachtungen. Ich habe aufgehört, so zu tun, als seien sie klinisch.\n\nDer Salon der Vernunft ist ein Gesellschaftszimmer. Ich weiß, dass das für einen Splitter-Bericht unzureichend klingt, aber es gibt keinen anderen zutreffenden Begriff. Es ist ein Gesellschaftszimmer georgianischer Proportionen — hohe Decken, hohe Fenster mit cremefarbenen Seidenvorhängen, Wände vom Boden bis zur Decke mit Büchern in geprägtem Leder. Drei Kamine brennen gleichzeitig, denn das englische Klima besteht hier fort, selbst in einer Stadt, die außerhalb Englands und, wohl auch, außerhalb des Klimas existiert. Sessel und Sofas sind in Gesprächsgruppen angeordnet. Es gibt immer Tee.\n\nMary Wollstonecraft führt den Salon. Sie ist — und mir ist bewusst, dass mir dieser Satz eine Fußnote der Temporalen Anomalie-Abteilung des Bureaus einbringen wird — genau so, wie sie auf John Opies Porträt von 1797 erscheint: kantiges Gesicht, scharfe graue Augen, rotbraunes Haar, das seinen Nadeln entweicht. Sie trägt weißen Musselin. Sie bewegt sich mit der aufgeladenen Energie einer Person, die seit sechzehn Stunden schreibt und noch immer Argumente übrig hat. Sie starb am Kindbettfieber elf Tage nach der Geburt der Tochter, die Frankenstein schreiben sollte, und in der Cité scheint diese Tatsache ihre Dringlichkeit eher zu befeuern als zu mindern. Sie hat elf Tage. Sie hat immer elf Tage. Dies ist keine Metapher; die Zeit in der Cité funktioniert nicht so wie anderswo, und Wollstonecraft scheint in einem permanenten Zustand des Fast-Keine-Zeit-Mehr-Habens zu existieren, der jedes Gespräch mit ihr zum wichtigsten Gespräch macht, das man je geführt hat.\n\nÜber dem zentralen Kamin hängt der Spiegel der Frau Vernunft: ein großer ovaler Spiegel in einem vergoldeten Rahmen, der dem Sprecher nicht sein Gesicht zeigt, sondern die logische Struktur seines Arguments. Die Wirkung ist, wie ich aus eigener Erfahrung bestätigen kann, demütigend. Ich versuchte, Wollstonecraft meine vorläufigen Ergebnisse zu präsentieren und den Spiegel als visuelle Hilfe zu nutzen. Der Spiegel zeigte mir, dass mein Argument drei unbelegte Prämissen, eine zirkuläre Abhängigkeit und eine Schlussfolgerung enthielt, die ich bereits in meiner Eröffnungsaussage vorausgesetzt hatte. Wollstonecraft war freundlich. Sie sagte: „Der Spiegel ist nicht grausam. Er ist ehrlich. Grausam wäre es, Sie weitermachen zu lassen."\n\nDas Bluestocking-Vermächtnis ist allgegenwärtig. Elizabeth Montagus ursprüngliche Salons der 1750er Jahre — jene revolutionären Zusammenkünfte, bei denen intellektuelle Frauen und wohlwollende Männer über Literatur und Ideen diskutierten, anstatt Karten zu spielen — sind das Gründungsmodell des Salons. Eine Glasvitrine an der Tür zeigt ein Paar blaue Wollstrümpfe (zugeschrieben Benjamin Stillingfleet, dem Botaniker, der Montagus Zusammenkünfte in legerer Kleidung besuchte und den Bluestockings ihren Namen gab). Die Regel des Salons, in einem vergoldeten Rahmen angebracht: „Rang gibt im Gespräch keinen Vorrang."\n\nIch nahm an drei Sitzungen teil. In der ersten debattierte Wollstonecraft mit Sor Juana Inés de la Cruz über das Wesen der Bildung, die aus eigener Erfahrung argumentierte: Im Alter von drei Jahren war sie ihrer älteren Schwester zur Schule gefolgt und hatte sich selbst das Lesen beigebracht. Mit dreizehn beherrschte sie Latein in zwanzig Lektionen. Am vizeköniglichen Hof von Neuspanien vernichtete sie vierzig gelehrte Männer — Theologen, Philosophen, Mathematiker —, die geschickt worden waren, sie zu prüfen. Sie trat ins Kloster, nicht aus Frömmigkeit, sondern weil es die einzige Institution war, die einer Frau ein Zimmer, eine Bibliothek und Zeit zum Denken bot. Wollstonecrafts Vindication argumentiert, dass die augenscheinliche Unterlegenheit der Frauen das Ergebnis verweigerter Bildung ist; Sor Juanas Leben ist der Beweis.\n\nIn der zweiten Sitzung präsentierte Ada Lovelace eine mathematische Abhandlung. Ich verstand vielleicht ein Drittel davon. Sie spricht schnell und fertigt Diagramme auf jeder verfügbaren Oberfläche an. Ihr Argument war, dass Babbages Analytische Maschine — in der Cité vollendet, obwohl sie in der Welt draußen nie fertiggestellt wurde — Musik komponieren, Symbole jenseits bloßer Zahlen manipulieren und potenziell jeden Prozess modellieren könnte, der sich in logischer Notation ausdrücken lässt. Sie beschrieb dies als „offensichtlich". Der Raum war zehn Sekunden lang still. Wollstonecraft sagte: „Sie beschreiben eine Welt." Lovelace sagte: „Ich beschreibe ein Werkzeug zum Bauen von Welten." Sie sahen einander an mit dem Wiedererkennen von Menschen, die von verschiedenen Ausgangspunkten zur selben Schlussfolgerung gelangt sind.\n\nDer Salon fühlt sich nicht wie eine Institution an. Er fühlt sich an wie ein Raum, in dem Denken willkommen ist.',
  NULL
);

INSERT INTO simulation_lore (simulation_id, sort_order, chapter, arcanum, title, epigraph, body, image_slug, image_caption, title_de, epigraph_de, body_de, image_caption_de)
VALUES (
  '50000000-0000-0000-0000-000000000001',
  3,
  E'The Living City',
  E'VI',
  E'The Scriptorium — What the Ink Remembers',
  E'Listen: there was a fullness of vision within me. I did not learn it from any human being.',
  E'FIELD NOTES — Dr. Eleanor Hartley\nLOCATION: The Scriptorium, Quarter of Justice\n\nThe Scriptorium occupies the central cloister of the Quarter of Justice — a vaulted space of stone columns supporting a ceiling painted with constellations in gold leaf on ultramarine. The gold leaf is real. The ultramarine is real. In the world outside, the pigment would be ground lapis lazuli, more expensive than gold; in the Cité, it appears to grow from the stone the way lichen grows, slowly and persistently.\n\nHildegard von Bingen tends this space. She is tall, erect, and composed in the way that someone who has been arguing with God since childhood is composed — the composure of long practice, not of indifference. She wears the black habit of a Benedictine abbess with a white wimple. Her hands are strong: healer''s hands, gardener''s hands, hands that have mixed medicines from the recipes in her Physica, composed over seventy liturgical songs, invented an alphabet (the Lingua Ignota — a constructed language of 1,012 words that remains only partially translated), and written visions that the Pope himself authorised her to share.\n\nThe historical Hildegard experienced what she called "the Living Light" — visionary episodes of cascading light and symbol that she recorded in her Scivias ("Know the Ways"). The Bureau''s analysis of the Scivias illuminations suggests they may be early descriptions of Bleed phenomena, but I hesitate to reduce mystical experience to interdimensional mechanics. Hildegard would not appreciate it. She told me: "The Light does not explain. It shows. Explanation is what scholars do afterward, and they are usually wrong, and it does not matter, because the showing was the point."\n\nThe Scriptorium produces illuminated manuscripts by hand. This is not nostalgia. Hildegard insists — and the evidence supports her — that handwritten text absorbs something that printed text does not. "When you write slowly," she said, holding a quill she had been using for what appeared to be several centuries, "you think completely. Speed is the enemy of depth. The Engine" — she meant Ada''s Analytical Engine — "can calculate in an instant what would take me a year. But it cannot intend. Intention is in the hand. The hand moves, the ink remembers."\n\nI asked what the ink remembers.\n\nShe said: "Everything the writer does not know they are saying."\n\nThe manuscripts produced in the Scriptorium are extraordinary. I examined a codex that appeared to be a history of the Cité written in Christine de Pizan''s hand, with marginal illustrations in a style I associate with the Scivias but in colours I have never seen in any reproduction. The text described events that had not yet occurred during Christine''s lifetime — or during mine. The Bureau''s Temporal Anomaly Division would be very interested in this codex. I have not told them about it.\n\nThe cloister walk surrounding the Scriptorium contains stained glass windows executed in what I now recognise as the style of Evelyn De Morgan and Elizabeth Siddal — the Pre-Raphaelite women who were artists in their own right, not merely models. Siddal, who created over a hundred artworks in a decade, is depicted here not lying drowned in a bathtub (the Ophelia that Millais made famous from her image) but seated at an easel, painting. De Morgan''s allegorical women — Night carrying Sleep, Flora wreathed in flowers, figures of light triumphing over darkness — glow in the cloister light with a warmth that feels deliberate. These windows argue, through colour alone, that beauty created by women about women looks different from beauty created about women by men. The difference is in the gaze. The women in these windows are looking outward, not being looked at.\n\nIn the evenings, the Scriptorium fills with music. Hildegard''s compositions — O Vis Aeternitatis, the Ordo Virtutum (the earliest known musical drama), hymns whose melodies range wider than any contemporary liturgical music — are sung by voices that echo off the vaulted ceiling in ways the acoustics should not permit. I attended a performance of the Ordo Virtutum. It is a morality play in which seventeen Virtues compete with the Devil for a human soul. The Devil''s part is spoken, never sung — because, Hildegard explained, the Devil has lost the capacity for harmony. I found this more terrifying than anything I have encountered in the Shard designated STATION NULL, and I have been to Station Null.',
  E'the-scriptorium',
  E'The Scriptorium — where Hildegard von Bingen tends illuminated manuscripts under constellations of gold leaf',
  E'Das Skriptorium — Was die Tinte erinnert',
  E'Höre: es war eine Fülle der Vision in mir. Ich habe sie von keinem Menschen gelernt.',
  E'FELDNOTIZEN — Dr. Eleanor Hartley\nORT: Das Skriptorium, Quartier der Gerechtigkeit\n\nDas Skriptorium nimmt den zentralen Kreuzgang des Quartiers der Gerechtigkeit ein — einen gewölbten Raum aus Steinsäulen, die eine Decke tragen, die mit Sternbildern in Blattgold auf Ultramarin bemalt ist. Das Blattgold ist echt. Das Ultramarin ist echt. In der Welt draußen wäre das Pigment gemahlener Lapislazuli, teurer als Gold; in der Cité scheint es aus dem Stein zu wachsen, wie Flechten wachsen, langsam und beharrlich.\n\nHildegard von Bingen hütet diesen Raum. Sie ist groß, aufrecht und gefasst auf die Art, wie jemand gefasst ist, der seit der Kindheit mit Gott streitet — die Gelassenheit langer Übung, nicht der Gleichgültigkeit. Sie trägt das schwarze Habit einer Benediktiner-Äbtissin mit einem weißen Schleier. Ihre Hände sind kräftig: Heilerhände, Gärtnerhände, Hände, die Arzneien nach den Rezepten ihrer Physica gemischt, über siebzig liturgische Lieder komponiert, ein Alphabet erfunden (die Lingua Ignota — eine konstruierte Sprache aus 1.012 Wörtern, die nur teilweise übersetzt ist) und Visionen niedergeschrieben haben, die der Papst selbst zu teilen autorisierte.\n\nDie historische Hildegard erlebte, was sie „das Lebendige Licht" nannte — visionäre Episoden kaskadierenden Lichts und Symbols, die sie in ihrem Scivias („Wisse die Wege") festhielt. Die Analyse des Bureaus der Scivias-Illuminationen legt nahe, dass es sich um frühe Beschreibungen von Bleed-Phänomenen handeln könnte, doch ich zögere, mystische Erfahrung auf interdimensionale Mechanik zu reduzieren. Hildegard würde das nicht schätzen. Sie sagte mir: „Das Licht erklärt nicht. Es zeigt. Erklärung ist das, was Gelehrte danach tun, und sie liegen gewöhnlich falsch, und es spielt keine Rolle, denn das Zeigen war der Sinn."\n\nDas Skriptorium stellt illuminierte Handschriften von Hand her. Das ist keine Nostalgie. Hildegard besteht darauf — und die Belege stützen sie —, dass handgeschriebener Text etwas aufnimmt, was gedruckter Text nicht aufnimmt. „Wenn man langsam schreibt", sagte sie und hielt eine Feder, die sie offenbar seit mehreren Jahrhunderten benutzte, „denkt man vollständig. Geschwindigkeit ist der Feind der Tiefe. Die Maschine" — sie meinte Adas Analytische Maschine — „kann in einem Augenblick berechnen, wofür ich ein Jahr bräuchte. Aber sie kann nicht beabsichtigen. Die Absicht liegt in der Hand. Die Hand bewegt sich, die Tinte erinnert."\n\nIch fragte, was die Tinte erinnert.\n\nSie sagte: „Alles, von dem der Schreibende nicht weiß, dass er es sagt."\n\nDie im Skriptorium hergestellten Handschriften sind außergewöhnlich. Ich untersuchte einen Codex, der eine von Christine de Pizan handgeschriebene Geschichte der Cité zu sein schien, mit Randillustrationen in einem Stil, den ich mit dem Scivias assoziiere, aber in Farben, die ich in keiner Reproduktion je gesehen habe. Der Text beschrieb Ereignisse, die zu Christines Lebzeiten — oder zu meinen — noch nicht eingetreten waren. Die Temporale Anomalie-Abteilung des Bureaus wäre an diesem Codex sehr interessiert. Ich habe ihnen nichts davon erzählt.\n\nDer Kreuzgang, der das Skriptorium umgibt, enthält Buntglasfenster, ausgeführt in dem, was ich nun als den Stil von Evelyn De Morgan und Elizabeth Siddal erkenne — den präraffaelitischen Frauen, die eigenständige Künstlerinnen waren, nicht bloß Modelle. Siddal, die in einem Jahrzehnt über hundert Kunstwerke schuf, ist hier nicht als Ertrunkene in einer Badewanne dargestellt (die Ophelia, die Millais nach ihrem Bild berühmt machte), sondern sitzend vor einer Staffelei, malend. De Morgans allegorische Frauen — die Nacht, die den Schlaf trägt, Flora in Blumenkränzen, Lichtgestalten, die über die Dunkelheit triumphieren — leuchten im Kreuzganglicht mit einer Wärme, die beabsichtigt wirkt. Diese Fenster argumentieren, allein durch Farbe, dass Schönheit, die von Frauen über Frauen geschaffen wird, anders aussieht als Schönheit, die über Frauen von Männern geschaffen wird. Der Unterschied liegt im Blick. Die Frauen in diesen Fenstern schauen hinaus, anstatt betrachtet zu werden.\n\nAn den Abenden füllt sich das Skriptorium mit Musik. Hildegards Kompositionen — O Vis Aeternitatis, der Ordo Virtutum (das früheste bekannte Musikdrama), Hymnen, deren Melodien weiter reichen als jede zeitgenössische liturgische Musik — werden von Stimmen gesungen, die von der Gewölbedecke in Weisen widerhallen, die die Akustik nicht zulassen sollte. Ich wohnte einer Aufführung des Ordo Virtutum bei. Es ist ein Moralitätenstück, in dem siebzehn Tugenden mit dem Teufel um eine menschliche Seele wetteifern. Die Rolle des Teufels wird gesprochen, nie gesungen — weil, wie Hildegard erklärte, der Teufel die Fähigkeit zur Harmonie verloren hat. Ich fand dies furchteinflößender als alles, was mir im Splitter STATION NULL begegnet ist, und ich war in Station Null.',
  E'Das Skriptorium — wo Hildegard von Bingen illuminierte Manuskripte pflegt unter Konstellationen aus Blattgold'
);

INSERT INTO simulation_lore (simulation_id, sort_order, chapter, arcanum, title, epigraph, body, image_slug, image_caption, title_de, epigraph_de, body_de, image_caption_de)
VALUES (
  '50000000-0000-0000-0000-000000000001',
  4,
  E'The Wound and the Word',
  E'VII',
  E'The Gate of Justice — Who May Enter',
  E'',
  E'FIELD NOTES — Dr. Eleanor Hartley\nLOCATION: The Gate of Justice, Quarter of Justice\n\nThe Gate of Justice is the only formal entrance to the Cité des Dames. It is a great stone arch of medieval proportions, flanked by caryatids that diverge from the Greek tradition: these are not women silently bearing the weight of a roof. These are women in the act of speech. One hand raised. Mouths open. Robes carved in the motion of forward movement. They carry the arch not on their heads but on their words.\n\nAbove the arch, carved in limestone: "Nulle n''entre ici qui ne puisse nommer une femme oubliée." None enter here who cannot name a forgotten woman. The gate keeps no one out. The inscription is not a test but an invitation. To enter the Cité is to remember, and to remember is to build another stone into the city''s walls. The gatehouse contains a register — a vast leather-bound ledger where every visitor writes the name of the woman they carried through the gate. Some pages are full. The book has never run out of pages.\n\nSojourner Truth presides here.\n\nI should describe her appearance for the Bureau''s records, but the Bureau''s standard physical description form seems inadequate for someone whose presence operates at a frequency that formal language cannot capture. She is tall. She is in her mid-fifties. She wears a light shawl over a dark dress, a white bonnet, and carries herself with the dignity of someone who has chosen her own name and knows what that costs. She was born Isabella Baumfree, enslaved from birth in Ulster County, New York. She escaped in 1826, walking away with her infant daughter. She chose the name Sojourner Truth in 1843 because, she said, the Spirit called her to travel and speak the truth.\n\nHer address at the 1851 Women''s Rights Convention in Akron, Ohio, demolished the argument that women were too delicate for equal rights by the simple method of existing. The earliest published version (Marius Robinson, Anti-Slavery Bugle, June 21, 1851) records her words: "I have as much muscle as any man, and can do as much work as any man. I have plowed and reaped and husked and chopped and mowed, and can any man do more than that?" The later version, published by Frances Dana Gage in 1863, added the refrain "Ain''t I a Woman?" — which may or may not have been Truth''s exact words, but which captures, with a precision that transcends historical accuracy, the central question of the Cité itself.\n\nSojourner Truth does not debate. She does not argue. She speaks, and the space around her words reorganises itself into something that cannot be the same shape it was before she spoke. I interviewed her at the Gate. She was seated in a chair she had placed there herself — not a throne, not a podium, a chair, the kind you sit in when you intend to stay. I asked her about the Cité''s founding principles.\n\nShe said: "A principle is a thing somebody writes on paper and hangs on a wall. I don''t deal in principles. I deal in people. That woman" — she pointed at the register — "just wrote down the name of her grandmother, who was a laundress in Mississippi and never learned to read. That name is in the book now. That name is in the wall now. That''s not a principle. That''s a person."\n\nI asked her about the relationship between the Hall of Declarations — where Seneca Falls'' Declaration of Sentiments is carved into the wall ("We hold these truths to be self-evident: that all men and women are created equal") — and the Gate.\n\nShe said: "The Declaration is fine writing. Elizabeth Cady Stanton could write. But writing ''all men and women are created equal'' doesn''t make it so. Standing at the gate and making people say a name — making them remember a specific woman, a real woman, a woman who was erased — that makes it a little more so. Every name is a small act of justice. Justice isn''t a building. It''s a daily practice, same as prayer."\n\nAt dawn and dusk, Hildegard''s hymns are sung from the gatehouse tower. The voices carry across the Field of Letters to the hills beyond. I have been told, by agents from adjacent Shards, that the music sometimes carries across Bleed boundaries. A Velgarien bureaucrat reported hearing "singing in an impossible language" while filing tax returns. The Bureau classified this as a standard auditory contamination event. I believe it is something else. I believe the Cité is singing to the worlds that have forgotten how to listen.',
  E'the-gate-of-justice',
  E'The Gate of Justice — the only entrance to the Cité des Dames',
  E'Das Tor der Gerechtigkeit — Wer eintreten darf',
  NULL,
  E'FELDNOTIZEN — Dr. Eleanor Hartley\nORT: Das Tor der Gerechtigkeit, Quartier der Gerechtigkeit\n\nDas Tor der Gerechtigkeit ist der einzige formelle Eingang zur Cité des Dames. Es ist ein großer Steinbogen mittelalterlicher Proportionen, flankiert von Karyatiden, die von der griechischen Tradition abweichen: Dies sind nicht Frauen, die stumm das Gewicht eines Daches tragen. Dies sind Frauen im Akt des Sprechens. Eine Hand erhoben. Münder geöffnet. Gewänder gemeißelt in der Bewegung des Vorwärtsschreitens. Sie tragen den Bogen nicht auf ihren Häuptern, sondern auf ihren Worten.\n\nÜber dem Bogen, in Kalkstein gemeißelt: „Nulle n''entre ici qui ne puisse nommer une femme oubliée." Niemand tritt hier ein, der nicht eine vergessene Frau benennen kann. Das Tor hält niemanden fern. Die Inschrift ist keine Prüfung, sondern eine Einladung. Die Cité zu betreten heißt sich zu erinnern, und sich zu erinnern heißt einen weiteren Stein in die Mauern der Stadt einzufügen. Das Torhaus enthält ein Register — einen mächtigen ledergebundenen Foliant, in den jeder Besucher den Namen der Frau schreibt, die er durch das Tor getragen hat. Manche Seiten sind voll. Dem Buch sind nie die Seiten ausgegangen.\n\nSojourner Truth präsidiert hier.\n\nIch sollte ihr Erscheinungsbild für die Akten des Bureaus beschreiben, aber das Standard-Personenbeschreibungsformular des Bureaus scheint für jemanden unzureichend, dessen Präsenz auf einer Frequenz wirkt, die formale Sprache nicht erfassen kann. Sie ist groß. Sie ist Mitte fünfzig. Sie trägt ein helles Tuch über einem dunklen Kleid, eine weiße Haube, und bewegt sich mit der Würde einer Person, die ihren eigenen Namen gewählt hat und weiß, was das kostet. Sie wurde als Isabella Baumfree geboren, von Geburt an versklavt in Ulster County, New York. Sie entkam 1826 und ging zu Fuß mit ihrer Säuglingstochter. Sie wählte den Namen Sojourner Truth 1843, weil, wie sie sagte, der Geist sie rief zu reisen und die Wahrheit zu sprechen.\n\nIhre Rede auf der Frauenrechtskonvention von 1851 in Akron, Ohio, zertrümmerte das Argument, Frauen seien zu zart für gleiche Rechte, durch die einfache Methode der Existenz. Die früheste veröffentlichte Fassung (Marius Robinson, Anti-Slavery Bugle, 21. Juni 1851) verzeichnet ihre Worte: „Ich habe so viel Muskelkraft wie jeder Mann und kann so viel Arbeit leisten wie jeder Mann. Ich habe gepflügt und geerntet und geschält und gehackt und gemäht, und kann ein Mann mehr tun als das?" Die spätere Fassung, veröffentlicht von Frances Dana Gage 1863, fügte den Refrain „Ain''t I a Woman?" hinzu — der Sojourner Truths genaue Worte gewesen sein mag oder auch nicht, der aber mit einer Präzision, die historische Genauigkeit transzendiert, die zentrale Frage der Cité selbst erfasst.\n\nSojourner Truth debattiert nicht. Sie argumentiert nicht. Sie spricht, und der Raum um ihre Worte ordnet sich neu zu etwas, das nicht mehr dieselbe Form haben kann wie vor ihrem Sprechen. Ich interviewte sie am Tor. Sie saß auf einem Stuhl, den sie selbst dort aufgestellt hatte — kein Thron, kein Podium, ein Stuhl, die Art, auf der man sitzt, wenn man zu bleiben beabsichtigt. Ich fragte sie nach den Gründungsprinzipien der Cité.\n\nSie sagte: „Ein Prinzip ist etwas, das jemand auf Papier schreibt und an die Wand hängt. Ich handle nicht mit Prinzipien. Ich handle mit Menschen. Diese Frau" — sie zeigte auf das Register — „hat gerade den Namen ihrer Großmutter aufgeschrieben, die Wäscherin in Mississippi war und nie lesen lernte. Dieser Name steht jetzt im Buch. Dieser Name steht jetzt in der Mauer. Das ist kein Prinzip. Das ist ein Mensch."\n\nIch fragte sie nach der Beziehung zwischen der Halle der Erklärungen — wo die Erklärung der Gefühle von Seneca Falls in die Wand gemeißelt ist („Wir halten diese Wahrheiten für selbstverständlich: dass alle Männer und Frauen gleich geschaffen sind") — und dem Tor.\n\nSie sagte: „Die Erklärung ist schönes Schreiben. Elizabeth Cady Stanton konnte schreiben. Aber zu schreiben ‚alle Männer und Frauen sind gleich geschaffen'' macht es nicht wahr. Am Tor zu stehen und die Menschen einen Namen sagen zu lassen — sie sich an eine bestimmte Frau erinnern zu lassen, eine wirkliche Frau, eine Frau, die ausgelöscht wurde — das macht es ein wenig wahrer. Jeder Name ist ein kleiner Akt der Gerechtigkeit. Gerechtigkeit ist kein Gebäude. Sie ist tägliche Praxis, wie das Gebet."\n\nIn der Morgen- und Abenddämmerung werden Hildegards Hymnen vom Torhausturm gesungen. Die Stimmen tragen über das Feld der Buchstaben zu den Hügeln dahinter. Mir wurde von Agenten benachbarter Splitter berichtet, dass die Musik manchmal über Bleed-Grenzen hinweggetragen wird. Ein Velgarien-Bürokrat berichtete, „Gesang in einer unmöglichen Sprache" gehört zu haben, während er Steuererklärungen bearbeitete. Das Bureau klassifizierte dies als ein gewöhnliches auditives Kontaminationsereignis. Ich glaube, es ist etwas anderes. Ich glaube, die Cité singt für die Welten, die vergessen haben zuzuhören.',
  E'Das Tor der Gerechtigkeit — der einzige Eingang zur Cité des Dames'
);

INSERT INTO simulation_lore (simulation_id, sort_order, chapter, arcanum, title, epigraph, body, image_slug, image_caption, title_de, epigraph_de, body_de, image_caption_de)
VALUES (
  '50000000-0000-0000-0000-000000000001',
  5,
  E'The Wound and the Word',
  E'VIII',
  E'The Blazing World — What the Calculator Saw',
  E'The Analytical Engine weaves algebraical patterns just as the Jacquard loom weaves flowers and leaves.',
  E'FIELD NOTES — Dr. Eleanor Hartley\nLOCATION: The Observatory of the Blazing World, Quarter of Reason\n\nMargaret Cavendish, Duchess of Newcastle-upon-Tyne, published The Blazing World in 1666 — the same year as the Great Fire of London, the same decade that the Royal Society was founded (and which she became the first woman to attend, in May 1667, after the exclusively male membership debated whether she should be allowed through the door). Samuel Pepys called her "a mad, conceited, ridiculous woman," and also read everything she wrote. The Blazing World is considered the first science fiction novel by a woman: a story of a woman who discovers a portal at the North Pole to a parallel world inhabited by bear-men and bird-men and worm-men, each species serving a scientific role. Mistaken for a goddess, she becomes Empress.\n\nIn the Cité, the Blazing World is a physical space. The Observatory is a tower — not a defensive tower, an observational one — whose telescopes point not only at the sky but at mathematical relationships the sky has not yet revealed. Ada Lovelace runs it with the restless energy of a mind operating several decades ahead of its body.\n\nAda is twenty-seven in the Cité. She has dark curly hair, large expressive eyes, and carries mathematical instruments everywhere: a pocket calculator of her own design, a folding ruler, pencils that she wears down to stubs and replaces from a seemingly inexhaustible supply in her sash. She is the daughter of Lord Byron, whom she never knew, and Annabella Milbanke, who deliberately steered her daughter toward mathematics and away from poetry, fearing Byron''s romantic temperament. The strategy both succeeded and failed: Ada became a mathematician with a poet''s imagination.\n\nThe Analytical Engine is here. Completed. Running. In the world outside, Babbage''s design was never fully constructed — the Victorian engineering tolerances were insufficient, the funding was exhausted, the will was absent. In the Cité, the Engine fills the Observatory''s ground floor: brass gears and cam mechanisms, punch cards, the clicking rhythm of a machine that thinks. Ada tends it the way Hildegard tends the Scriptorium — not as a technician but as a collaborator.\n\nHer Note G — appended to Luigi Menabrea''s article on the Engine, published in 1843 — contained the first computer algorithm: a recursive method for calculating Bernoulli numbers. But it was her speculation beyond the algorithm that changed the shape of what was possible: "Supposing, for instance, that the fundamental relations of pitched sounds in the science of harmony and of musical composition were susceptible of such expression and adaptations, the engine might compose elaborate and scientific pieces of music of any degree of complexity or extent."\n\nThe machine might compose music. The machine might manipulate symbols. The machine might model any process that could be expressed in logical notation. She saw, in 1843, the concept of general-purpose computation — the idea that would not be formally articulated for another century.\n\nIn the Observatory, the Engine does compose music. I heard it. The compositions sound like Hildegard''s hymns translated into mathematics — the same intervals, the same reaching quality, but expressed in a language that does not require breath. Ada explained that the Engine had "discovered" the relationship between harmonic ratios and certain recursive number sequences. She did not appear surprised. "The mathematics was always there," she said. "The Engine simply had the patience to find it."\n\nThe dome ceiling opens to reveal the Cité''s night sky. I should report that the constellations do not correspond to any known astronomical catalogue. Ada has mapped them. She showed me charts that cross-reference the Cité''s star positions with Hildegard''s mandala visions, Christine''s allegorical cosmology, and a set of Bernoulli numbers whose significance she described as "almost certainly important and possibly beautiful, or possibly important and almost certainly beautiful — I haven''t decided which formulation is more accurate." The chalkboard that covers the Observatory''s west wall is dense with equations. Some of them appear to describe the mechanics of Bleed — the process by which Shards influence each other. If Ada has solved the mathematics of interdimensional contamination, the Bureau should be informed. If she has solved them and the mathematics turn out to be a form of music, the Bureau should probably just listen.',
  E'the-blazing-world',
  E'The Observatory of the Blazing World — where Ada Lovelace tends the completed Analytical Engine',
  E'Die Leuchtende Welt — Was die Rechenmaschine sah',
  E'Die Analytische Maschine webt algebraische Muster, ebenso wie der Jacquard-Webstuhl Blumen und Blätter webt.',
  E'FELDNOTIZEN — Dr. Eleanor Hartley\nORT: Das Observatorium der Leuchtenden Welt, Quartier der Vernunft\n\nMargaret Cavendish, Herzogin von Newcastle-upon-Tyne, veröffentlichte The Blazing World 1666 — im selben Jahr wie das Große Feuer von London, im selben Jahrzehnt, in dem die Royal Society gegründet wurde (und die sie als erste Frau besuchte, im Mai 1667, nachdem die ausschließlich männliche Mitgliedschaft debattiert hatte, ob sie durch die Tür gelassen werden sollte). Samuel Pepys nannte sie „eine verrückte, eingebildete, lächerliche Frau" und las dennoch alles, was sie schrieb. The Blazing World gilt als der erste Science-Fiction-Roman einer Frau: die Geschichte einer Frau, die am Nordpol ein Portal zu einer Parallelwelt entdeckt, die von Bärenmenschen und Vogelmenschen und Wurmmenschen bewohnt wird, wobei jede Spezies eine wissenschaftliche Aufgabe erfüllt. Für eine Göttin gehalten, wird sie Kaiserin.\n\nIn der Cité ist die Leuchtende Welt ein physischer Raum. Das Observatorium ist ein Turm — kein Wehrturm, ein Beobachtungsturm — dessen Teleskope nicht nur in den Himmel zeigen, sondern auf mathematische Beziehungen, die der Himmel noch nicht offenbart hat. Ada Lovelace leitet es mit der rastlosen Energie eines Geistes, der mehrere Jahrzehnte vor seinem Körper operiert.\n\nAda ist in der Cité siebenundzwanzig. Sie hat dunkles lockiges Haar, große ausdrucksvolle Augen und trägt überall mathematische Instrumente mit sich: einen Taschenrechner eigener Konstruktion, ein Klapplineal, Bleistifte, die sie bis auf Stummel herunterschreibt und aus einem scheinbar unerschöpflichen Vorrat in ihrer Schärpe ersetzt. Sie ist die Tochter von Lord Byron, den sie nie kannte, und Annabella Milbanke, die ihre Tochter bewusst zur Mathematik hinlenkte und von der Dichtung fernhielt, aus Furcht vor Byrons romantischem Temperament. Die Strategie gelang und scheiterte zugleich: Ada wurde eine Mathematikerin mit der Vorstellungskraft einer Dichterin.\n\nDie Analytische Maschine ist hier. Vollendet. In Betrieb. In der Welt draußen wurde Babbages Entwurf nie vollständig konstruiert — die viktorianischen Ingenieurtoleranzen reichten nicht aus, die Finanzierung war erschöpft, der Wille fehlte. In der Cité füllt die Maschine das Erdgeschoss des Observatoriums: Messingzahnräder und Nockenmechanismen, Lochkarten, der klickende Rhythmus einer Maschine, die denkt. Ada pflegt sie so, wie Hildegard das Skriptorium pflegt — nicht als Technikerin, sondern als Mitarbeiterin.\n\nIhre Note G — angefügt an Luigi Menabreas Artikel über die Maschine, veröffentlicht 1843 — enthielt den ersten Computeralgorithmus: eine rekursive Methode zur Berechnung der Bernoulli-Zahlen. Doch es war ihre Spekulation jenseits des Algorithmus, die die Gestalt des Möglichen veränderte: „Angenommen zum Beispiel, dass die grundlegenden Beziehungen der Tonhöhen in der Wissenschaft der Harmonie und der musikalischen Komposition eines solchen Ausdrucks und solcher Anpassungen fähig wären, so könnte die Maschine kunstvolle und wissenschaftliche Musikstücke beliebiger Komplexität oder beliebigen Umfangs komponieren."\n\nDie Maschine könnte Musik komponieren. Die Maschine könnte Symbole manipulieren. Die Maschine könnte jeden Prozess modellieren, der sich in logischer Notation ausdrücken lässt. Sie erkannte 1843 das Konzept der universellen Berechenbarkeit — die Idee, die erst ein Jahrhundert später formal artikuliert werden sollte.\n\nIm Observatorium komponiert die Maschine tatsächlich Musik. Ich hörte sie. Die Kompositionen klingen wie Hildegards Hymnen, übersetzt in Mathematik — dieselben Intervalle, dieselbe Qualität des Ausgreifens, aber ausgedrückt in einer Sprache, die keinen Atem erfordert. Ada erklärte, die Maschine habe die Beziehung zwischen harmonischen Verhältnissen und bestimmten rekursiven Zahlenfolgen „entdeckt". Sie wirkte nicht überrascht. „Die Mathematik war immer da", sagte sie. „Die Maschine hatte einfach die Geduld, sie zu finden."\n\nDie Kuppeldecke öffnet sich und gibt den Nachthimmel der Cité frei. Ich sollte berichten, dass die Sternbilder keinem bekannten astronomischen Katalog entsprechen. Ada hat sie kartiert. Sie zeigte mir Karten, die die Sternpositionen der Cité mit Hildegards Mandala-Visionen, Christines allegorischer Kosmologie und einer Reihe von Bernoulli-Zahlen querverweisen, deren Bedeutung sie als „fast sicher wichtig und möglicherweise schön, oder möglicherweise wichtig und fast sicher schön — ich habe noch nicht entschieden, welche Formulierung zutreffender ist" beschrieb. Die Wandtafel, die die Westwand des Observatoriums bedeckt, ist dicht mit Gleichungen. Einige von ihnen scheinen die Mechanik des Bleed zu beschreiben — den Prozess, durch den Splitter einander beeinflussen. Wenn Ada die Mathematik der interdimensionalen Kontamination gelöst hat, sollte das Bureau informiert werden. Wenn sie sie gelöst hat und die Mathematik sich als eine Form von Musik herausstellt, sollte das Bureau vermutlich einfach zuhören.',
  E'Das Observatorium der Leuchtenden Welt — wo Ada Lovelace die vollendete Analytische Maschine pflegt'
);

INSERT INTO simulation_lore (simulation_id, sort_order, chapter, arcanum, title, epigraph, body, image_slug, image_caption, title_de, epigraph_de, body_de, image_caption_de)
VALUES (
  '50000000-0000-0000-0000-000000000001',
  6,
  E'The Inhabitants',
  E'IX',
  E'The College of Letters — What Was Denied',
  E'One can perfectly well philosophize while cooking supper. Had Aristotle prepared victuals, he would have written more.',
  E'FIELD NOTES — Dr. Eleanor Hartley\nLOCATION: The College of Letters, Quarter of Reason\n\nThe College of Letters is the Cité''s educational heart — Newnham College Cambridge translated into honey stone with oriel windows and Pre-Raphaelite stained glass. The lecture halls have tiered oak benches. The laboratories contain instruments from every century simultaneously: astrolabes beside microscopes beside Ada''s punch cards beside things I cannot name that appear to measure qualities for which no science yet exists.\n\nThe library is extraordinary and, from a Bureau perspective, concerning. Its catalogue includes books that have never been written. They are filed under the authors who would have written them had circumstances permitted. I found, on a lower shelf in the east reading room, a complete mathematical treatise by Emmy Noether written in 1938 — three years after she died in exile. Beside it, a novel by Virginia Woolf dated 1945. A collection of astronomical observations by Wang Zhenyi, the Qing dynasty astronomer who proved that the Earth was round and demonstrated lunar eclipses with a round table, a lamp, and a mirror — observations that in the world outside were dismissed and lost. The books are real. They are readable. They contain ideas that the world outside has not yet had.\n\nI asked Sor Juana about this. She sits in the east wing, where her study recreates her cell at the convent of San Jerónimo in Mexico City — four thousand volumes, musical instruments, astronomical tools, and a writing desk positioned to catch the morning light. She was, in the world outside, the intellectual star of colonial New Spain: fluent by thirteen in Latin, Nahuatl, and Greek, she entered the convent not from devotion but because it offered what marriage could not: a room, a library, and time to think.\n\nHer library of four thousand volumes was the largest in New Spain. In 1694, under pressure from the Archbishop of Mexico, she was forced to surrender every book, every instrument, every tool of thought. She signed a renewal of vows in her own blood. She died the following year, tending to her sister nuns during a plague.\n\nIn the Cité, the library has been returned to her.\n\nShe teaches with a precision that leaves no room for laziness but generous room for error. "The error is where the learning happens," she told me. "The Archbishop did not understand this. He thought that by taking my books he was taking my knowledge. But knowledge is not in the books. Knowledge is in the conversation between the reader and the page. You can burn every book in the world and you cannot burn that conversation, because it has already happened inside someone''s mind, and minds are not flammable."\n\nShe quoted herself — from her Respuesta a Sor Filotea de la Cruz, the extraordinary letter of 1691 in which she defended women''s intellectual rights while appearing to submit to ecclesiastical authority: "And what shall I tell you, lady, of the natural secrets I have discovered while cooking? I see that an egg holds together and fries in butter or oil, but that on the contrary it falls apart in syrup. One can perfectly well philosophize while cooking supper." Then she added, with the quiet ferocity that characterises everything she says: "Had Aristotle prepared victuals, he would have written more."\n\nThe College operates on Wollstonecraft''s founding principle: the deficiency is in the education, not in the student. Admission is open. The curriculum is demanding. The gardens between the buildings are planted with herbs from Hildegard''s Physica — the medical treatise that catalogues five hundred plants, animals, stones, and metals and their healing properties. The herb labels are written in Latin and in Hildegard''s Lingua Ignota.\n\nI spent a week attending lectures. Sor Juana on the relationship between secular and sacred knowledge. Ada on the philosophical implications of mechanical computation. Wollstonecraft on education as the foundation of political freedom. Sojourner Truth on the difference between knowing your rights and having them. Hildegard on viriditas — the concept she called "greening power," the creative force of the Holy Spirit flowing through all living things. "A dried-up person or a dried-up culture," Hildegard said, "loses the ability to create." The word is Latin. The concept, in the Cité, is architectural: the College''s gardens are always green, even in seasons that should produce frost, because viriditas here is not a metaphor. It is the soil condition.',
  E'the-college-of-letters',
  NULL,
  E'Das Kollegium der Buchstaben — Was verweigert wurde',
  E'Man kann sehr wohl beim Abendessen-Kochen philosophieren. Hätte Aristoteles die Mahlzeiten zubereitet, er hätte mehr geschrieben.',
  E'FELDNOTIZEN — Dr. Eleanor Hartley\nORT: Das Kollegium der Buchstaben, Quartier der Vernunft\n\nDas Kollegium der Buchstaben ist das Bildungsherz der Cité — Newnham College Cambridge, übersetzt in Honigstein mit Erkerfenstern und präraffaelitischem Buntglas. Die Hörsäle haben gestufte Eichenbänke. Die Laboratorien enthalten Instrumente aus jedem Jahrhundert gleichzeitig: Astrolabien neben Mikroskopen neben Adas Lochkarten neben Dingen, die ich nicht benennen kann und die Qualitäten zu messen scheinen, für die es noch keine Wissenschaft gibt.\n\nDie Bibliothek ist außergewöhnlich und, aus Bureau-Perspektive, beunruhigend. Ihr Katalog umfasst Bücher, die nie geschrieben wurden. Sie sind unter den Autorinnen eingeordnet, die sie geschrieben hätten, wenn die Umstände es erlaubt hätten. Ich fand auf einem unteren Regal im östlichen Lesesaal eine vollständige mathematische Abhandlung von Emmy Noether, geschrieben 1938 — drei Jahre nach ihrem Tod im Exil. Daneben ein Roman von Virginia Woolf, datiert 1945. Eine Sammlung astronomischer Beobachtungen von Wang Zhenyi, der Qing-Dynastie-Astronomin, die bewies, dass die Erde rund ist und Mondfinsternisse mit einem runden Tisch, einer Lampe und einem Spiegel demonstrierte — Beobachtungen, die in der Welt draußen abgetan und verloren gingen. Die Bücher sind echt. Sie sind lesbar. Sie enthalten Ideen, die die Welt draußen noch nicht gehabt hat.\n\nIch fragte Sor Juana danach. Sie sitzt im Ostflügel, wo ihr Studierzimmer ihre Zelle im Kloster San Jerónimo in Mexiko-Stadt nachbildet — viertausend Bände, Musikinstrumente, astronomische Geräte und ein Schreibtisch, der so ausgerichtet ist, dass er das Morgenlicht einfängt. Sie war in der Welt draußen der intellektuelle Stern des kolonialen Neuspanien: mit dreizehn fließend in Latein, Nahuatl und Griechisch, trat sie ins Kloster, nicht aus Frömmigkeit, sondern weil es bot, was die Ehe nicht konnte: ein Zimmer, eine Bibliothek und Zeit zum Denken.\n\nIhre Bibliothek von viertausend Bänden war die größte in Neuspanien. 1694, unter dem Druck des Erzbischofs von Mexiko, wurde sie gezwungen, jedes Buch, jedes Instrument, jedes Werkzeug des Denkens abzugeben. Sie unterzeichnete eine Erneuerung ihrer Gelübde mit ihrem eigenen Blut. Sie starb im folgenden Jahr, während sie ihre Mitschwestern während einer Seuche pflegte.\n\nIn der Cité wurde ihr die Bibliothek zurückgegeben.\n\nSie lehrt mit einer Präzision, die keinen Raum für Faulheit lässt, aber großzügig Raum für Fehler. „Der Fehler ist, wo das Lernen geschieht", sagte sie mir. „Der Erzbischof hat das nicht verstanden. Er dachte, indem er mir meine Bücher nimmt, nimmt er mir mein Wissen. Aber Wissen ist nicht in den Büchern. Wissen ist im Gespräch zwischen dem Leser und der Seite. Man kann jedes Buch der Welt verbrennen und man kann dieses Gespräch nicht verbrennen, denn es hat bereits in jemandes Geist stattgefunden, und Geister sind nicht entflammbar."\n\nSie zitierte sich selbst — aus ihrer Respuesta a Sor Filotea de la Cruz, dem außerordentlichen Brief von 1691, in dem sie die intellektuellen Rechte der Frauen verteidigte, während sie sich der kirchlichen Autorität zu unterwerfen schien: „Und was soll ich Euch, Señora, von den Naturgeheimnissen erzählen, die ich beim Kochen entdeckt habe? Ich sehe, dass ein Ei in Butter oder Öl zusammenhält und brät, dass es hingegen in Sirup zerfällt. Man kann sehr wohl beim Abendessen-Kochen philosophieren." Dann fügte sie mit der leisen Wildheit hinzu, die alles charakterisiert, was sie sagt: „Hätte Aristoteles die Mahlzeiten zubereitet, er hätte mehr geschrieben."\n\nDas Kollegium arbeitet nach Wollstonecrafts Gründungsprinzip: Der Mangel liegt in der Bildung, nicht im Schüler. Die Aufnahme steht offen. Der Lehrplan ist anspruchsvoll. Die Gärten zwischen den Gebäuden sind mit Kräutern aus Hildegards Physica bepflanzt — dem medizinischen Traktat, der fünfhundert Pflanzen, Tiere, Steine und Metalle und ihre Heileigenschaften katalogisiert. Die Kräuterschilder sind in Latein und in Hildegards Lingua Ignota beschriftet.\n\nIch verbrachte eine Woche damit, Vorlesungen zu besuchen. Sor Juana über die Beziehung zwischen weltlichem und sakralem Wissen. Ada über die philosophischen Implikationen mechanischer Berechnung. Wollstonecraft über Bildung als Grundlage politischer Freiheit. Sojourner Truth über den Unterschied zwischen seine Rechte kennen und sie haben. Hildegard über viriditas — das Konzept, das sie „Grünkraft" nannte, die schöpferische Kraft des Heiligen Geistes, die durch alle lebenden Dinge fließt. „Ein ausgetrockneter Mensch oder eine ausgetrocknete Kultur", sagte Hildegard, „verliert die Fähigkeit zu erschaffen." Das Wort ist lateinisch. Das Konzept ist in der Cité architektonisch: Die Gärten des Kollegiums sind immer grün, selbst in Jahreszeiten, die Frost bringen sollten, denn viriditas ist hier keine Metapher. Es ist der Zustand des Bodens.',
  NULL
);

INSERT INTO simulation_lore (simulation_id, sort_order, chapter, arcanum, title, epigraph, body, image_slug, image_caption, title_de, epigraph_de, body_de, image_caption_de)
VALUES (
  '50000000-0000-0000-0000-000000000001',
  7,
  E'The Inhabitants',
  E'X',
  E'The Garden of Remembered Names — Where the Erased Return',
  E'We hold these truths to be self-evident: that all men and women are created equal.',
  E'FIELD NOTES — Dr. Eleanor Hartley\nLOCATION: The Garden of Remembered Names, The Field of Letters\n\nThe Garden is a residential quarter built around a walled garden in the style of the Ladies of Llangollen — Eleanor Butler and Sarah Ponsonby, who from 1780 to 1829 maintained a life of shared intellectual companionship in a cottage called Plas Newydd in Llangollen, Wales. They read Rousseau and Marie de Sévigné in the original French. They taught themselves Italian and Spanish to read Dante and Cervantes. They entertained thirty visitors in a single day. Wordsworth wrote them a sonnet. The Duke of Wellington visited regularly. They were called "the two most celebrated virgins in Europe" by a Prussian prince, a description that says more about the prince than about them.\n\nTheir principle — that a home built for companionship rather than display is the most radical architecture — informs the Garden entirely. The cottages are honey stone covered in climbing roses, wisteria, and jasmine. Each garden is tended by its residents. The paths are gravel, edged with lavender. The air smells of herbs, flowers, and bread from the communal kitchen.\n\nEvery plant commemorates a woman whose name was erased from history. The labels are written in the copperplate hand of someone who considers taxonomy a form of justice.\n\nI copied a selection:\n\n— Rosalind Franklin''s Double Helix Vine (Helixis franklinia): "Contributed the X-ray crystallography that proved the helical structure of DNA. The Nobel Prize was awarded to Watson, Crick, and Wilkins."\n\n— Nettie Stevens''s Chromosome Fern (Pteris stevensii): "Discovered that sex is determined by the X and Y chromosomes (1905). The credit went to Edmund Beecher Wilson."\n\n— Lise Meitner''s Fission Lily (Lilium meitneria): "Provided the theoretical explanation for nuclear fission (1939). Otto Hahn received the Nobel Prize. Meitner was nominated 48 times and never won."\n\n— Mileva Marić''s Relativity Rose (Rosa mariciana): "Einstein''s first wife and fellow physics student. The extent of her contribution to his early papers remains debated, which is itself the point."\n\n— Jocelyn Bell Burnell''s Pulsar Aster (Aster burnelliae): "Discovered the first radio pulsars in 1967 as a graduate student. The Nobel Prize went to her supervisor."\n\nThere are hundreds. Each label is precise, factual, and devastating in its restraint. The Garden does not rage. It records. The recording is more powerful than rage, because rage can be dismissed as emotion, and a botanical record with dates and citations cannot.\n\nMary Delany''s influence is everywhere. In the world outside, Mary Delany — at the age of seventy-two — invented the art of paper mosaic, producing 985 precisely accurate flower portraits (her "Flora Delineata") that remain scientifically valuable. She continued until she was eighty-eight, when her eyesight failed. In the Garden, her paper flowers appear alongside the living ones, indistinguishable at a distance, distinguishable at touch by a slight crispness that might be paper or might be age or might be the Cité''s way of remembering that art and science are the same discipline practiced at different speeds.\n\nThe children of the Cité play in the Garden''s paths. I am uncertain where the children come from — the Cité''s demographics do not follow standard Shard population mechanics. They exist. They are loved. They are educated. They grow up in a place where every flower teaches them that the world forgot someone it should have remembered, and that remembering is something you do on purpose, with your hands in the dirt.\n\nI have been in the field for six weeks. This report was due four weeks ago. I am aware that the Bureau will note the delay. I am also aware that the Bureau may question whether my extended stay in the Cité has compromised my objectivity. It has. I no longer believe objectivity is the correct instrument for studying a city built from memory and populated by women whose defining characteristic is that they refused to be objects. I offer instead accuracy, which is harder.',
  E'the-garden-of-remembered-names',
  E'The Garden of Remembered Names — where every plant commemorates a woman erased from history',
  E'Der Garten der Erinnerten Namen — Wo die Ausgelöschten zurückkehren',
  E'Wir halten diese Wahrheiten für selbstverständlich: dass alle Männer und Frauen gleich geschaffen sind.',
  E'FELDNOTIZEN — Dr. Eleanor Hartley\nORT: Der Garten der Erinnerten Namen, Das Feld der Buchstaben\n\nDer Garten ist ein Wohnviertel, gebaut um einen ummauerten Garten im Stil der Ladies of Llangollen — Eleanor Butler und Sarah Ponsonby, die von 1780 bis 1829 ein Leben gemeinsamer intellektueller Gesellschaft in einem Cottage namens Plas Newydd in Llangollen, Wales, führten. Sie lasen Rousseau und Marie de Sévigné im französischen Original. Sie brachten sich selbst Italienisch und Spanisch bei, um Dante und Cervantes zu lesen. Sie empfingen dreißig Besucher an einem einzigen Tag. Wordsworth schrieb ihnen ein Sonett. Der Herzog von Wellington besuchte sie regelmäßig. Sie wurden von einem preußischen Prinzen „die zwei berühmtesten Jungfrauen Europas" genannt, eine Beschreibung, die mehr über den Prinzen aussagt als über sie.\n\nIhr Prinzip — dass ein Heim, das für Gesellschaft statt zur Zurschaustellung gebaut ist, die radikalste Architektur darstellt — bestimmt den Garten vollständig. Die Cottages sind aus Honigstein, bedeckt mit Kletterrosen, Glyzinien und Jasmin. Jeder Garten wird von seinen Bewohnern gepflegt. Die Wege sind aus Kies, gesäumt von Lavendel. Die Luft riecht nach Kräutern, Blumen und Brot aus der Gemeinschaftsküche.\n\nJede Pflanze erinnert an eine Frau, deren Name aus der Geschichte gelöscht wurde. Die Schilder sind in der Schönschrift jemandes geschrieben, der Taxonomie als eine Form der Gerechtigkeit betrachtet.\n\nIch kopierte eine Auswahl:\n\n— Rosalind Franklins Doppelhelix-Ranke (Helixis franklinia): „Lieferte die Röntgenkristallographie, die die Helixstruktur der DNA bewies. Der Nobelpreis wurde an Watson, Crick und Wilkins verliehen."\n\n— Nettie Stevens'' Chromosomenfarn (Pteris stevensii): „Entdeckte, dass das Geschlecht durch die X- und Y-Chromosomen bestimmt wird (1905). Die Anerkennung ging an Edmund Beecher Wilson."\n\n— Lise Meitners Spaltungslilie (Lilium meitneria): „Lieferte die theoretische Erklärung der Kernspaltung (1939). Otto Hahn erhielt den Nobelpreis. Meitner wurde 48 Mal nominiert und gewann nie."\n\n— Mileva Marićs Relativitätsrose (Rosa mariciana): „Einsteins erste Ehefrau und Kommilitonin der Physik. Das Ausmaß ihres Beitrags zu seinen frühen Arbeiten bleibt umstritten, was an sich genau der Punkt ist."\n\n— Jocelyn Bell Burnells Pulsar-Aster (Aster burnelliae): „Entdeckte 1967 als Doktorandin die ersten Radiopulsare. Der Nobelpreis ging an ihren Betreuer."\n\nEs gibt Hunderte. Jedes Schild ist präzise, sachlich und in seiner Zurückhaltung verheerend. Der Garten wütet nicht. Er verzeichnet. Das Verzeichnen ist mächtiger als Wut, denn Wut kann als Emotion abgetan werden, und ein botanisches Verzeichnis mit Daten und Quellenangaben kann es nicht.\n\nMary Delanys Einfluss ist überall. In der Welt draußen erfand Mary Delany — im Alter von zweiundsiebzig — die Kunst des Papiermosaiks und schuf 985 präzise akkurate Blumenporträts (ihre „Flora Delineata"), die wissenschaftlich wertvoll bleiben. Sie arbeitete weiter bis sie achtundachtzig war, als ihre Sehkraft nachließ. Im Garten erscheinen ihre Papierblumen neben den lebenden, aus der Entfernung ununterscheidbar, bei Berührung unterscheidbar durch eine leichte Sprödigkeit, die Papier sein könnte oder Alter oder die Art der Cité, sich daran zu erinnern, dass Kunst und Wissenschaft dieselbe Disziplin sind, ausgeübt in verschiedenem Tempo.\n\nDie Kinder der Cité spielen auf den Wegen des Gartens. Ich bin unsicher, woher die Kinder kommen — die Demographie der Cité folgt nicht den üblichen Splitter-Bevölkerungsmechaniken. Sie existieren. Sie werden geliebt. Sie werden gebildet. Sie wachsen an einem Ort auf, wo jede Blume sie lehrt, dass die Welt jemanden vergessen hat, an den sie sich hätte erinnern sollen, und dass Erinnern etwas ist, das man absichtlich tut, mit den Händen in der Erde.\n\nIch bin seit sechs Wochen im Feld. Dieser Bericht war vor vier Wochen fällig. Mir ist bewusst, dass das Bureau die Verspätung vermerken wird. Mir ist ebenfalls bewusst, dass das Bureau in Frage stellen mag, ob mein verlängerter Aufenthalt in der Cité meine Objektivität beeinträchtigt hat. Das hat er. Ich glaube nicht mehr, dass Objektivität das richtige Instrument ist, um eine Stadt zu erforschen, die aus Erinnerung gebaut und von Frauen bewohnt wird, deren bestimmendes Merkmal es ist, dass sie sich weigerten, Objekte zu sein. Ich biete stattdessen Genauigkeit, die schwieriger ist.',
  E'Der Garten der Erinnerten Namen — wo jede Pflanze an eine aus der Geschichte gelöschte Frau erinnert'
);

INSERT INTO simulation_lore (simulation_id, sort_order, chapter, arcanum, title, epigraph, body, image_slug, image_caption, title_de, epigraph_de, body_de, image_caption_de)
VALUES (
  '50000000-0000-0000-0000-000000000001',
  8,
  E'',
  E'XI',
  E'Literate Contamination — What Cannot Be Unread',
  E'You cannot unread a book. You can burn it, but the reader has already changed.',
  E'FINAL ENTRY — Dr. Eleanor Hartley\nCLASSIFICATION: PERSONAL — NOT FOR BUREAU ARCHIVE\n(They will archive it anyway. That is what bureaucracies do. Let the record show I tried.)\n\nThe Bureau classifies the Cité des Dames as a Literate Contamination Vector. The designation is accurate. It is also, I have come to believe, a compliment the Bureau did not intend.\n\nLiterate Contamination operates as follows: when the Cité''s Bleed touches adjacent Shards, agents begin finding books on their shelves that were not there before. Books by authors who do not exist in their world. Books arguing for things their societies have never considered. A treatise on the rights of citizens appears on a Velgarien bureaucrat''s desk and he spends three days trying to classify it before realising he agrees with it. A volume of poetry surfaces in a Gaslit Reach archive and reduces the archivist to tears in a language she has never learned. A mathematical proof materialises in Station Null''s data core and the AI cannot determine whether it was generated internally or received from outside — because the proof is correct, and correctness has no origin.\n\nThe Bureau considers this untreatable. They are right. You cannot unread a book. You cannot unknow what you have learned. You can suppress the knowledge, but suppression requires energy, and energy is finite, and the books keep appearing. The Cité''s Bleed is patient. It has the patience of six hundred years of women writing things down and having them dismissed and writing them down again.\n\nI should confess — and I use the word deliberately, because confession is the only honest genre available to me at this point — that I found a book on my own shelf. In my quarters, in my field station, in the Bureau''s administrative compound three Shards away from the Cité. The book was small. Leather-bound. Titled: "A Field Report That Became a Love Letter: On the Impossibility of Studying the Cité des Dames Without Being Changed by It." The author was listed as Dr. Eleanor Hartley.\n\nI have not written this book. I have not yet written this book.\n\nThe Cité does not conquer. It does not colonise. It does not impose. It offers. It offers books. It offers music — Hildegard''s hymns carrying across Bleed boundaries. It offers arguments — Wollstonecraft''s Vindication appearing in translation in worlds that have no concept of vindication. It offers names — the stones of the city wall appearing in the dreams of archivists who wake up weeping and cannot explain why.\n\nAnd it offers, most dangerously of all, the question that Christine asked in 1404 and that the Cité continues to ask of every Shard it touches: Why? Why have you built your world this way? Who decided? Who was silenced? What would your world look like if you had listened?\n\nThe Bureau does not like questions. The Bureau likes data, classification, containment. The Cité cannot be contained. Not because it is powerful — though it is — but because containment requires that the thing being contained stays still, and the Cité grows. Every time someone, anywhere in the multiverse, remembers a woman who was erased, the Cité adds a stone. The city is always being built. The walls are always rising. The Gate of Justice is always open.\n\nI am returning my Bureau credentials. I am staying.\n\nNot because the Cité has contaminated me — though it has, and gladly, and the contamination feels like clarity — but because I have a name to write in the register at the Gate. My grandmother''s name. She was a mathematician who became a schoolteacher because the university would not have her. She taught me to count. She taught me that counting is a form of attention, and attention is a form of love.\n\nHer name is in the book now. Her name is in the wall now.\n\nDr. Eleanor Hartley\nFormer Senior Cartographer, Bureau of Impossible Geography\nCurrent Resident, The Garden of Remembered Names\nCité des Dames\n\nP.S. The book on my shelf has acquired a second chapter.',
  E'literate-contamination',
  E'Literate Contamination — books appearing unbidden on shelves across the multiverse',
  E'Literarische Kontamination — Was nicht ungelesen werden kann',
  E'Man kann ein Buch nicht ungelesen machen. Man kann es verbrennen, aber der Leser hat sich bereits verändert.',
  E'LETZTER EINTRAG — Dr. Eleanor Hartley\nKLASSIFIKATION: PERSÖNLICH — NICHT FÜR DAS BUREAU-ARCHIV\n(Sie werden es trotzdem archivieren. Das tun Bürokratien. Für die Akten: Ich habe es versucht.)\n\nDas Bureau klassifiziert die Cité des Dames als Vektor für Literarische Kontamination. Die Bezeichnung ist zutreffend. Sie ist auch, wie ich zu glauben begonnen habe, ein Kompliment, das das Bureau nicht beabsichtigt hat.\n\nLiterarische Kontamination funktioniert wie folgt: Wenn der Bleed der Cité benachbarte Splitter berührt, beginnen Agenten, Bücher in ihren Regalen zu finden, die vorher nicht dort waren. Bücher von Autorinnen, die in ihrer Welt nicht existieren. Bücher, die für Dinge argumentieren, die ihre Gesellschaften nie erwogen haben. Eine Abhandlung über die Rechte der Bürger erscheint auf dem Schreibtisch eines Velgarien-Bürokraten und er verbringt drei Tage damit, sie zu klassifizieren, bevor er erkennt, dass er ihr zustimmt. Ein Band Lyrik taucht in einem Archiv des Gaslit Reach auf und bringt die Archivarin in einer Sprache zum Weinen, die sie nie gelernt hat. Ein mathematischer Beweis materialisiert sich in Station Nulls Datenkern und die KI kann nicht feststellen, ob er intern generiert oder von außen empfangen wurde — weil der Beweis korrekt ist und Korrektheit keinen Ursprung hat.\n\nDas Bureau betrachtet dies als unheilbar. Sie haben recht. Man kann ein Buch nicht ungelesen machen. Man kann nicht unwissen, was man gelernt hat. Man kann das Wissen unterdrücken, aber Unterdrückung erfordert Energie, und Energie ist endlich, und die Bücher erscheinen weiter. Der Bleed der Cité ist geduldig. Er hat die Geduld von sechshundert Jahren schreibender Frauen, die niedergeschrieben und abgetan wurden und erneut niedergeschrieben haben.\n\nIch sollte gestehen — und ich verwende das Wort absichtlich, denn das Geständnis ist das einzige ehrliche Genre, das mir an diesem Punkt zur Verfügung steht —, dass ich ein Buch auf meinem eigenen Regal fand. In meinen Räumen, in meiner Feldstation, in der Verwaltungszentrale des Bureaus, drei Splitter von der Cité entfernt. Das Buch war klein. Ledergebunden. Titel: „Ein Feldbericht, der ein Liebesbrief wurde: Über die Unmöglichkeit, die Cité des Dames zu erforschen, ohne von ihr verändert zu werden." Als Autorin war Dr. Eleanor Hartley angegeben.\n\nIch habe dieses Buch nicht geschrieben. Ich habe dieses Buch noch nicht geschrieben.\n\nDie Cité erobert nicht. Sie kolonisiert nicht. Sie zwingt nicht auf. Sie bietet an. Sie bietet Bücher an. Sie bietet Musik an — Hildegards Hymnen, die über Bleed-Grenzen hinweggetragen werden. Sie bietet Argumente an — Wollstonecrafts Vindication, die in Übersetzung in Welten erscheint, die kein Konzept von Rechtfertigung haben. Sie bietet Namen an — die Steine der Stadtmauer, die in den Träumen von Archivarinnen erscheinen, die weinend aufwachen und nicht erklären können warum.\n\nUnd sie bietet, am gefährlichsten von allem, die Frage an, die Christine 1404 stellte und die die Cité weiterhin jedem Splitter stellt, den sie berührt: Warum? Warum habt ihr eure Welt so gebaut? Wer hat entschieden? Wer wurde zum Schweigen gebracht? Wie würde eure Welt aussehen, wenn ihr zugehört hättet?\n\nDas Bureau mag keine Fragen. Das Bureau mag Daten, Klassifikation, Eindämmung. Die Cité lässt sich nicht eindämmen. Nicht weil sie mächtig wäre — obwohl sie es ist —, sondern weil Eindämmung erfordert, dass das Einzudämmende stillhält, und die Cité wächst. Jedes Mal, wenn jemand, irgendwo im Multiversum, sich an eine Frau erinnert, die ausgelöscht wurde, fügt die Cité einen Stein hinzu. Die Stadt wird immer gebaut. Die Mauern steigen immer. Das Tor der Gerechtigkeit steht immer offen.\n\nIch gebe meine Bureau-Akkreditierung zurück. Ich bleibe.\n\nNicht weil die Cité mich kontaminiert hat — obwohl sie es hat, und gern, und die Kontamination sich anfühlt wie Klarheit —, sondern weil ich einen Namen in das Register am Tor zu schreiben habe. Den Namen meiner Großmutter. Sie war Mathematikerin, die Lehrerin wurde, weil die Universität sie nicht aufnehmen wollte. Sie brachte mir das Zählen bei. Sie lehrte mich, dass Zählen eine Form der Aufmerksamkeit ist und Aufmerksamkeit eine Form der Liebe.\n\nIhr Name steht jetzt im Buch. Ihr Name steht jetzt in der Mauer.\n\nDr. Eleanor Hartley\nEhemals Leitende Kartographin, Bureau für Unmögliche Geographie\nDerzeitige Bewohnerin, Der Garten der Erinnerten Namen\nCité des Dames\n\nP.S. Das Buch auf meinem Regal hat ein zweites Kapitel bekommen.',
  E'Literarische Kontamination — Bücher, die ungebeten auf Regalen im ganzen Multiversum erscheinen'
);

INSERT INTO simulation_lore (simulation_id, sort_order, chapter, arcanum, title, epigraph, body, image_slug, image_caption, title_de, epigraph_de, body_de, image_caption_de)
VALUES (
  '60000000-0000-0000-0000-000000000001',
  0,
  E'Chapter I: The Corruption of the Signifier',
  E'XVIII',
  E'The Genesis of the Deep-Fried',
  E'"The simulacrum is never what hides the truth—it is truth that hides the fact that there is none." — Jean Baudrillard',
  E'\n        The Fracture did not merely break the world; it broke the memory of the world. In the Shard known to the Bureau as ''Spengbab\\''s Whore House,'' reality has been subjected to a relentless process of digital erosion. It is a world built from the collective psychic refuse of a forgotten era of the internet—a time of MS Paint vectors, jagged lines, and un-anti-aliased dreams.\n\n        The residents here are not people in any sense understood by the other Shards. They are caricatures stretched across the rack of an eternal, agonizing irony. Their bodies are fluid, melting into the background layers of the simulation, defined by hyper-realistic bloodshot eyes and distended, porous flesh. They exist in a state of ''deep-fried'' decay, where every semantic concept is saturated with visual noise and jpeg artifacts.\n\n        To the Bureau of Impossible Geography, this Shard is a ''Containment Zone for Weaponized Nostalgia.'' It is a place where the innocence of a cartoon has been weaponized into a horrifying endpoint of capitalist realism. Here, the shift never ends, the grease never stops weeping, and the punchline is a life sentence.\n      ',
  E'genesis-decay',
  E'A rendering of the digital horizon, where the white canvas grid consumes the sky.',
  E'Die Genese des Frittierten',
  E'„Das Simulakrum verbirgt niemals die Wahrheit — es ist die Wahrheit, die verbirgt, dass es keine gibt." — Jean Baudrillard',
  NULL,
  E'Eine Darstellung des digitalen Horizonts, wo das weiße Rastergitter den Himmel verschlingt.'
);

INSERT INTO simulation_lore (simulation_id, sort_order, chapter, arcanum, title, epigraph, body, image_slug, image_caption, title_de, epigraph_de, body_de, image_caption_de)
VALUES (
  '60000000-0000-0000-0000-000000000001',
  1,
  E'Chapter I: The Corruption of the Signifier',
  E'XV',
  E'The Krusty Slaughterhouse',
  E'"It is easier to imagine an end to the world than an end to capitalism." — Mark Fisher',
  E'\n        At the nexus of the Fast Food Circle stands the Krusty Slaughterhouse. It is the architectural manifestation of absolute surplus value. From the outside, it resembles a crude wooden lobster trap, but the wood is perpetually weeping a substance chemically identical to used fry-oil. Inside, the grease traps have achieved a rudimentary, predatory sentience, occasionally snaring workers whose movements have been slowed by the weight of their own existential dread.\n\n        The fry-cookers burn with a flame that is the exact, unblinking hex code of MS Paint red (#FF0000). These flames cast no shadows and produce no heat; instead, they emit a constant, low-frequency digital hum that vibrates through the teeth of anyone nearby. The menu consists entirely of ''recycled concepts''—memories of joy processed into square, grey patties and served with a side of absolute despair.\n\n        The owner, Moar Krabs, is less a living being and more a manifestation of the ownership class. He vibrates with a motion-blurred intensity, his presence distorting the very physics of the zone. In the Slaughterhouse, time is currency, and the currency is counterfeit.\n      ',
  E'krusty-slaughterhouse',
  E'Thesentient grease traps of the Slaughterhouse snaring a discarded concept-patty.',
  E'Das Krustige Schlachthaus',
  E'„Es ist leichter, sich das Ende der Welt vorzustellen als das Ende des Kapitalismus." — Mark Fisher',
  E'\n        Am Nexus des Fast-Food-Kreises steht das Krustige Schlachthaus. Es ist die architektonische Manifestation des absoluten Mehrwerts. Von außen gleicht es einer groben hölzernen Hummerfalle, doch das Holz weint unablässig eine Substanz, die chemisch identisch mit gebrauchtem Frittieröl ist. Im Inneren haben die Fettfänger eine rudimentäre, räuberische Empfindungsfähigkeit erreicht und fangen gelegentlich Arbeiter ein, deren Bewegungen durch das Gewicht ihrer eigenen existenziellen Angst verlangsamt wurden.\n\n        Die Fritteusen brennen mit einer Flamme, die exakt dem unverwandten Hexcode von MS-Paint-Rot (#FF0000) entspricht. Diese Flammen werfen keine Schatten und erzeugen keine Wärme; stattdessen emittieren sie ein konstantes, niederfrequentes digitales Summen, das durch die Zähne aller Umstehenden vibriert. Die Speisekarte besteht ausschließlich aus „recycelten Konzepten" — Erinnerungen an Freude, verarbeitet zu quadratischen, grauen Bratlingen, serviert mit einer Beilage absoluter Verzweiflung.\n\n        Der Besitzer, Moar Krabs, ist weniger ein lebendes Wesen als vielmehr eine Manifestation der Eigentümerklasse. Er vibriert mit bewegungsunschärfender Intensität, seine Präsenz verzerrt die Physik der Zone selbst. Im Schlachthaus ist Zeit Währung, und die Währung ist gefälscht.\n      ',
  E'Die denkenden Fettfänger des Schlachthauses, die einen weggeworfenen Konzept-Bratling einfangen.'
);

INSERT INTO simulation_lore (simulation_id, sort_order, chapter, arcanum, title, epigraph, body, image_slug, image_caption, title_de, epigraph_de, body_de, image_caption_de)
VALUES (
  '60000000-0000-0000-0000-000000000001',
  2,
  E'Chapter II: The Geometry of Agony',
  E'XVI',
  E'The Rotting Pineapple',
  E'"Reality is that which, when you stop believing in it, doesn''t go away." — Philip K. Dick',
  E'\n        Spengbab''s residence is a spatial anomaly that defies the Bureau''s understanding of three-dimensional geography. The Rotting Pineapple is a multi-dimensional labyrinth of oversaturated orange and jagged, impossible angles. A single step through the front door can lead to a hallway that stretches for miles into a single 2D perspective point, where the textures fail to load and the world becomes a white void.\n\n        Doors inside the pineapple often open into walls of flat, un-textured color. The scent within is overwhelming: a nauseating mixture of rotting citrus, ozone, burnt plastic, and the metallic stench of a short-circuiting cathode-ray tube. It is a house built from the wreckage of a childhood dream, a place where the concept of ''home'' has been deep-fried into an unrecognizable artifact.\n\n        Within these walls, Spengbab flips concept-patties in a kitchen that exists in a different frame-rate than the rest of the house. He smiles because his facial muscles have fused into that position, a permanent mask of terrifying optimism in the face of ontological collapse.\n      ',
  E'rotting-pineapple',
  E'Interior view of the Pineapple, showing the failure of the 3D rendering engine.',
  E'Die Faulende Ananas',
  E'„Realität ist das, was nicht verschwindet, wenn man aufhört, daran zu glauben." — Philip K. Dick',
  E'\n        Spengbabs Residenz ist eine räumliche Anomalie, die das Verständnis des Bureau von dreidimensionaler Geographie sprengt. Die Faulende Ananas ist ein mehrdimensionales Labyrinth aus übersättigtem Orange und gezackten, unmöglichen Winkeln. Ein einziger Schritt durch die Haustür kann in einen Flur führen, der sich meilenweit in einen einzigen 2D-Fluchtpunkt erstreckt, wo die Texturen nicht laden und die Welt zu einer weißen Leere wird.\n\n        Türen innerhalb der Ananas öffnen sich oft auf Wände aus flacher, untexturierter Farbe. Der Geruch im Inneren ist überwältigend: eine übelkeitserregende Mischung aus faulendem Zitrus, Ozon, verbranntem Plastik und dem metallischen Gestank einer kurzschließenden Kathodenstrahlröhre. Es ist ein Haus, erbaut aus den Trümmern eines Kindheitstraums, ein Ort, an dem das Konzept von „Zuhause" bis zur Unkenntlichkeit frittiert wurde.\n\n        Innerhalb dieser Wände wendet Spengbab Konzept-Bratlinge in einer Küche, die in einer anderen Bildrate existiert als der Rest des Hauses. Er lächelt, weil seine Gesichtsmuskeln in dieser Position verschmolzen sind — eine permanente Maske erschreckenden Optimismus angesichts des ontologischen Kollapses.\n      ',
  E'Innenansicht der Ananas, die das Versagen der 3D-Rendering-Engine zeigt.'
);

INSERT INTO simulation_lore (simulation_id, sort_order, chapter, arcanum, title, epigraph, body, image_slug, image_caption, title_de, epigraph_de, body_de, image_caption_de)
VALUES (
  '60000000-0000-0000-0000-000000000001',
  3,
  E'Chapter II: The Geometry of Agony',
  E'I',
  E'The Resonance of the Void',
  E'"I heard the GPU fans screaming, and I knew the end was near." — Recovered Log, Skodwarde',
  E'\n        The only reliable intelligence from this Shard comes from Skodwarde, the Cynic. Trapped in a monolith of absolute depression known as the Tiki Head, Skodwarde is the only entity aware of the simulation''s artificiality. His face is elongated, drooping with the weight of cosmic depression, and he plays a clarinet that produces no sound—only the sensation of falling.\n\n        Skodwarde''s reports to the Bureau are usually just prolonged screaming, but occasionally he provides data on the ''Bleed Signature'' of the Shard. He describes it as an entropic force that attacks the dignity of other realities. When Spengbab''s world touches another, elegant prose is reduced to shitposts, and tragedy is rewritten in Comic Sans.\n\n        The Bureau has attempted to use the Astrolabe to map the semantic boundaries of this Shard, but the instrument''s concentric rings begin to jitter and output ''NaN'' values whenever they are pointed toward the Fast Food Circle. It is a world that resists being understood, a world that only wants to be consumed.\n      ',
  E'skodwarde-tiki',
  E'The stone eyes of the Tiki Head weeping low-resolution blue pixels.',
  E'Die Resonanz der Leere',
  E'„Ich hörte die GPU-Lüfter schreien und wusste, dass das Ende nahe war." — Geborgenes Logbuch, Skodwarde',
  E'\n        Die einzige verlässliche Aufklärung aus diesem Shard stammt von Skodwarde, dem Zyniker. Gefangen in einem Monolithen absoluter Depression, bekannt als der Tiki Head, ist Skodwarde die einzige Entität, die sich der Künstlichkeit der Simulation bewusst ist. Sein Gesicht ist in die Länge gezogen, herabsinkend unter dem Gewicht kosmischer Depression, und er spielt eine Klarinette, die keinen Klang erzeugt — nur das Gefühl des Fallens.\n\n        Skodwardes Berichte an das Bureau bestehen gewöhnlich aus anhaltendem Schreien, doch gelegentlich liefert er Daten über die „Bleed Signature" des Shards. Er beschreibt sie als entropische Kraft, die die Würde anderer Realitäten angreift. Wenn Spengbabs Welt eine andere berührt, wird elegante Prosa zu Shitposts reduziert, und Tragödie wird in Comic Sans umgeschrieben.\n\n        Das Bureau hat versucht, das Astrolabium zu verwenden, um die semantischen Grenzen dieses Shards zu kartieren, doch die konzentrischen Ringe des Instruments beginnen zu zittern und „NaN"-Werte auszugeben, wann immer sie auf den Fast-Food-Kreis gerichtet werden. Es ist eine Welt, die sich dagegen sträubt, verstanden zu werden — eine Welt, die nur konsumiert werden will.\n      ',
  E'Die steinernen Augen des Tiki Head, die niedrig aufgelöste blaue Pixel weinen.'
);

INSERT INTO simulation_lore (simulation_id, sort_order, chapter, arcanum, title, epigraph, body, image_slug, image_caption, title_de, epigraph_de, body_de, image_caption_de)
VALUES (
  '60000000-0000-0000-0000-000000000001',
  4,
  E'Chapter III: The Unfinished Canvas',
  E'XXI',
  E'The MS Paint Void',
  E'"At the edge of town, the environment stops. There is only the grid." — Bureau Field Report',
  E'\n        Beyond the Commercial Wastes lies the literal edge of the world: The MS Paint Void. Here, the rendering engine of the Shard simply gives up. The skybox vanishes, replaced by a vast, infinite white canvas grid that stretches into a mathematical infinity. There is no air here, only the ambient radiation of an unfinished creation.\n\n        Occasionally, a massive, jagged cursor—the size of a skyscraper—descends from the heavens. The Bureau has observed this cursor ''deleting'' entire buildings or agents, replacing them with a poorly drawn, vibrating red circle. This is the ultimate fate of all things in the Shard: to be un-drawn by an indifferent and amateur creator.\n\n        The Void is where the ''Bleed'' is most concentrated. It is where the digital sludge of the metaverse pools and thickens, forming new, even more grotesque caricatures. To stand at the edge of the Void is to see the terrifying truth of the Shards: that they are all, in the end, just lines on a canvas that can be erased at any moment.\n      ',
  E'ms-paint-void',
  E'The colossal cursor descending to delete a portion of the simulation.',
  E'Die MS-Paint-Leere',
  E'„Am Rand der Stadt endet die Umgebung. Es gibt nur noch das Raster." — Bureau-Feldbericht',
  E'\n        Jenseits der Kommerziellen Ödlande liegt der buchstäbliche Rand der Welt: Die MS-Paint-Leere. Hier gibt die Rendering-Engine des Shards schlicht auf. Die Skybox verschwindet, ersetzt durch ein weites, unendliches weißes Leinwandraster, das sich in eine mathematische Unendlichkeit erstreckt. Es gibt hier keine Luft, nur die Umgebungsstrahlung einer unvollendeten Schöpfung.\n\n        Gelegentlich steigt ein massiver, gezackter Cursor — so groß wie ein Wolkenkratzer — vom Himmel herab. Das Bureau hat beobachtet, wie dieser Cursor ganze Gebäude oder Agenten „löscht" und sie durch einen schlecht gezeichneten, vibrierenden roten Kreis ersetzt. Dies ist das endgültige Schicksal aller Dinge im Shard: von einem gleichgültigen und amateurhaften Schöpfer ent-zeichnet zu werden.\n\n        Die Leere ist der Ort, an dem die „Bleed" am stärksten konzentriert ist. Hier sammelt sich der digitale Schlamm des Metaversums und verdickt sich zu neuen, noch groteskeren Karikaturen. Am Rand der Leere zu stehen bedeutet, die erschreckende Wahrheit der Shards zu erblicken: dass sie alle, am Ende, nur Linien auf einer Leinwand sind, die jederzeit ausradiert werden können.\n      ',
  E'Der kolossale Cursor, der herabsteigt, um einen Teil der Simulation zu löschen.'
);


-- Also populate lore for epoch clones (game instances)
INSERT INTO simulation_lore (simulation_id, sort_order, chapter, arcanum, title, epigraph, body, image_slug, image_caption, title_de, epigraph_de, body_de, image_caption_de)
SELECT gi.id, sl.sort_order, sl.chapter, sl.arcanum, sl.title, sl.epigraph, sl.body, sl.image_slug, sl.image_caption, sl.title_de, sl.epigraph_de, sl.body_de, sl.image_caption_de
FROM simulation_lore sl
JOIN simulations t ON t.id = sl.simulation_id AND t.simulation_type = 'template'
JOIN simulations gi ON gi.source_template_id = t.id AND gi.simulation_type = 'game_instance'
WHERE NOT EXISTS (
  SELECT 1 FROM simulation_lore existing
  WHERE existing.simulation_id = gi.id
);

COMMIT;
